-- Name: FUNCTION apply_draft_ranker_player_action(p_user_id uuid, p_ranking_id uuid, p_fhfh_player_id bigint, p_action text, p_operation_id uuid, p_priority smallint, p_note text, p_source text); Type: COMMENT; Schema: public; Owner: -
--

