--
-- Name: begin_draft_ranker_placement(uuid, uuid, bigint, bigint, uuid, text, jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.begin_draft_ranker_placement(p_user_id uuid, p_ranking_id uuid, p_fhfh_player_id bigint, p_expected_version bigint, p_operation_id uuid, p_operation_payload_hash text, p_state jsonb) RETURNS jsonb
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public'
    AS $_$
declare
    v_version bigint;
    v_existing_hash text;
    v_existing_result jsonb;
    v_active_session uuid;
    v_active_player bigint;
    v_session public.draft_ranker_placement_sessions%rowtype;
    v_result jsonb;
begin
    if p_user_id is null or p_ranking_id is null or p_fhfh_player_id is null
       or p_operation_id is null or p_expected_version is null
       or p_expected_version < 0 then
        raise exception using errcode = '22023', message = 'Valid owner, ranking, player, version, and operation are required';
    end if;
    if p_operation_payload_hash !~ '^[0-9a-f]{64}$' then
        raise exception using errcode = '22023', message = 'Operation payload hash must be lowercase SHA-256';
    end if;
    if jsonb_typeof(p_state) <> 'object'
       or jsonb_typeof(p_state->'issuedAnchors') <> 'array'
       or jsonb_typeof(p_state->'answers') <> 'array'
       or coalesce((p_state->>'intervalLow')::integer, 0) < 1
       or coalesce((p_state->>'intervalHigh')::integer, 0)
          < coalesce((p_state->>'intervalLow')::integer, 1)
       or coalesce((p_state->>'questionCount')::integer, -1) <> 0
       or jsonb_array_length(p_state->'issuedAnchors') <> 1
       or jsonb_array_length(p_state->'answers') <> 0 then
        raise exception using errcode = '22023', message = 'Invalid initial placement state';
    end if;

    select ranking.lock_version into v_version
    from public.draft_rankings ranking
    where ranking.id = p_ranking_id
      and ranking.user_id = p_user_id
      and ranking.status = 'active'
    for update;

    if v_version is null then
        return jsonb_build_object('status', 'not_found', 'code', 'ranking_not_found');
    end if;

    select event.metadata->>'operation_payload_hash', event.metadata->'result'
    into v_existing_hash, v_existing_result
    from public.draft_ranking_events event
    where event.ranking_id = p_ranking_id and event.operation_id = p_operation_id;
    if v_existing_hash is not null then
        if v_existing_hash <> p_operation_payload_hash then
            return jsonb_build_object('status', 'conflict', 'code', 'idempotency_conflict');
        end if;
        return coalesce(v_existing_result, '{}'::jsonb)
            || jsonb_build_object('idempotentReplay', true);
    end if;

    if v_version <> p_expected_version then
        return jsonb_build_object(
            'status', 'conflict', 'code', 'stale_ranking_version',
            'expectedVersion', p_expected_version, 'currentVersion', v_version
        );
    end if;

    update public.draft_ranker_placement_sessions
    set status = 'expired', completed_at = statement_timestamp()
    where ranking_id = p_ranking_id
      and status = 'active'
      and expires_at <= statement_timestamp();

    select session.id, session.fhfh_player_id
    into v_active_session, v_active_player
    from public.draft_ranker_placement_sessions session
    where session.ranking_id = p_ranking_id
      and session.status = 'active'
    order by session.updated_at desc
    limit 1;
    if v_active_session is not null then
        return jsonb_build_object(
            'status', 'conflict', 'code', 'active_placement_exists',
            'sessionId', v_active_session, 'playerId', v_active_player
        );
    end if;

    if not exists (
        select 1 from public.fhfh_player_identities identity
        where identity.id = p_fhfh_player_id
          and identity.verification_status = 'verified'
          and identity.lifecycle_status in (
              'active_nhl', 'active_prospect', 'unsigned_relevant'
          )
    ) then
        return jsonb_build_object('status', 'failed', 'code', 'player_not_rankable');
    end if;

    insert into public.draft_ranker_placement_sessions (
        user_id, ranking_id, fhfh_player_id, status, rough_range,
        interval_low, interval_high, plausible_low, plausible_high,
        question_count, contradiction_count, ranking_version,
        issued_anchors, answers, suggested_rank, expires_at,
        engine_version, confidence, completion_reason
    ) values (
        p_user_id, p_ranking_id, p_fhfh_player_id, 'active',
        p_state->>'roughRange',
        (p_state->>'intervalLow')::integer,
        (p_state->>'intervalHigh')::integer,
        nullif(p_state->>'plausibleLow', '')::integer,
        nullif(p_state->>'plausibleHigh', '')::integer,
        0, 0, v_version,
        p_state->'issuedAnchors', p_state->'answers',
        nullif(p_state->>'suggestedRank', '')::integer,
        statement_timestamp() + interval '7 days',
        'deterministic_v1', coalesce(p_state->>'confidence', 'developing'),
        nullif(p_state->>'completionReason', '')
    ) returning * into v_session;

    v_result := jsonb_build_object(
        'status', 'completed', 'sessionId', v_session.id,
        'rankingId', p_ranking_id, 'playerId', p_fhfh_player_id,
        'rankingVersion', v_version, 'idempotentReplay', false
    );
    insert into public.draft_ranking_events (
        ranking_id, user_id, fhfh_player_id, event_type, event_source,
        operation_id, expected_version, resulting_version,
        before_state, after_state, metadata
    ) values (
        p_ranking_id, p_user_id, p_fhfh_player_id,
        'assisted_placement_started', 'assisted_placement', p_operation_id,
        null, v_version, '{}'::jsonb,
        jsonb_build_object('sessionId', v_session.id),
        jsonb_build_object(
            'operation_payload_hash', p_operation_payload_hash,
            'engineVersion', 'deterministic_v1', 'result', v_result
        )
    );
    return v_result;
end;
$_$;


--
-- Name: FUNCTION begin_draft_ranker_placement(p_user_id uuid, p_ranking_id uuid, p_fhfh_player_id bigint, p_expected_version bigint, p_operation_id uuid, p_operation_payload_hash text, p_state jsonb); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.begin_draft_ranker_placement(p_user_id uuid, p_ranking_id uuid, p_fhfh_player_id bigint, p_expected_version bigint, p_operation_id uuid, p_operation_payload_hash text, p_state jsonb) IS 'Service-only deterministic placement start with one resumable active session per ranking.';


--
-- Name: calculate_goalie_start_projections(date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calculate_goalie_start_projections(target_date date) RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE
    game_record RECORD;
BEGIN
    -- Loop through all games on the target date
    FOR game_record IN
        SELECT id, "homeTeamId", "awayTeamId"
        FROM games
        WHERE date = target_date
    LOOP
        -- Process Home Team
        PERFORM process_team_goalie_projections(game_record.id, game_record."homeTeamId", target_date);

        -- Process Away Team
        PERFORM process_team_goalie_projections(game_record.id, game_record."awayTeamId", target_date);
    END LOOP;
END;
$$;


--
-- Name: cancel_draft_ranker_placement(uuid, uuid, uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.cancel_draft_ranker_placement(p_user_id uuid, p_session_id uuid, p_operation_id uuid, p_operation_payload_hash text) RETURNS jsonb
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public'
    AS $$
declare
    v_session public.draft_ranker_placement_sessions%rowtype;
    v_version bigint;
    v_existing_hash text;
    v_existing_result jsonb;
    v_result jsonb;
begin
    select session.* into v_session
    from public.draft_ranker_placement_sessions session
    where session.id = p_session_id and session.user_id = p_user_id
    for update;
    if not found then
        return jsonb_build_object('status', 'not_found', 'code', 'placement_not_found');
    end if;
    select event.metadata->>'operation_payload_hash', event.metadata->'result'
    into v_existing_hash, v_existing_result
    from public.draft_ranking_events event
    where event.ranking_id = v_session.ranking_id
      and event.operation_id = p_operation_id;
    if v_existing_hash is not null then
        if v_existing_hash <> p_operation_payload_hash then
            return jsonb_build_object('status', 'conflict', 'code', 'idempotency_conflict');
        end if;
        return coalesce(v_existing_result, '{}'::jsonb)
            || jsonb_build_object('idempotentReplay', true);
    end if;
    if v_session.status <> 'active' then
        return jsonb_build_object('status', 'conflict', 'code', 'placement_not_active');
    end if;
    select lock_version into v_version from public.draft_rankings
    where id = v_session.ranking_id and user_id = p_user_id for update;
    update public.draft_ranker_placement_sessions
    set status = 'cancelled', completed_at = statement_timestamp()
    where id = p_session_id;
    v_result := jsonb_build_object(
        'status', 'completed', 'sessionId', p_session_id,
        'rankingId', v_session.ranking_id, 'cancelled', true,
        'idempotentReplay', false
    );
    insert into public.draft_ranking_events (
        ranking_id, user_id, fhfh_player_id, event_type, event_source,
        operation_id, expected_version, resulting_version,
        before_state, after_state, metadata
    ) values (
        v_session.ranking_id, p_user_id, v_session.fhfh_player_id,
        'assisted_placement_cancelled', 'assisted_placement', p_operation_id,
        null, v_version, jsonb_build_object('status', 'active'),
        jsonb_build_object('status', 'cancelled'),
        jsonb_build_object(
            'operation_payload_hash', p_operation_payload_hash,
            'sessionId', p_session_id, 'result', v_result
        )
    );
    return v_result;
end;
$$;


--
-- Name: FUNCTION cancel_draft_ranker_placement(p_user_id uuid, p_session_id uuid, p_operation_id uuid, p_operation_payload_hash text); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.cancel_draft_ranker_placement(p_user_id uuid, p_session_id uuid, p_operation_id uuid, p_operation_payload_hash text) IS 'Service-only assisted-placement cancellation.';


--
-- Name: confirm_draft_ranker_placement(uuid, uuid, uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.confirm_draft_ranker_placement(p_user_id uuid, p_session_id uuid, p_operation_id uuid, p_operation_payload_hash text) RETURNS jsonb
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public'
    AS $$
declare
    v_session public.draft_ranker_placement_sessions%rowtype;
    v_version bigint;
    v_existing_hash text;
    v_existing_result jsonb;
    v_was_unplaced boolean;
    v_tail_key bigint;
    v_result jsonb;
begin
    select session.* into v_session
    from public.draft_ranker_placement_sessions session
    where session.id = p_session_id and session.user_id = p_user_id
    for update;
    if not found then
        return jsonb_build_object('status', 'not_found', 'code', 'placement_not_found');
    end if;
    select event.metadata->>'operation_payload_hash', event.metadata->'result'
    into v_existing_hash, v_existing_result
    from public.draft_ranking_events event
    where event.ranking_id = v_session.ranking_id
      and event.operation_id = p_operation_id;
    if v_existing_hash is not null then
        if v_existing_hash <> p_operation_payload_hash then
            return jsonb_build_object('status', 'conflict', 'code', 'idempotency_conflict');
        end if;
        return coalesce(v_existing_result, '{}'::jsonb)
            || jsonb_build_object('idempotentReplay', true);
    end if;
    if v_session.status <> 'active' or v_session.suggested_rank is null
       or v_session.completion_reason is null then
        return jsonb_build_object('status', 'conflict', 'code', 'placement_not_ready');
    end if;
    select ranking.lock_version into v_version
    from public.draft_rankings ranking
    where ranking.id = v_session.ranking_id and ranking.user_id = p_user_id
    for update;
    if v_version is distinct from v_session.ranking_version then
        return jsonb_build_object(
            'status', 'conflict', 'code', 'stale_ranking_version',
            'expectedVersion', v_session.ranking_version,
            'currentVersion', v_version
        );
    end if;

    v_was_unplaced := not exists (
        select 1 from public.draft_ranking_entries entry
        where entry.ranking_id = v_session.ranking_id
          and entry.user_id = p_user_id
          and entry.fhfh_player_id = v_session.fhfh_player_id
    );
    if v_was_unplaced then
        select coalesce(max(order_key), 0) + 1048576 into v_tail_key
        from public.draft_ranking_entries
        where ranking_id = v_session.ranking_id and user_id = p_user_id;
        insert into public.draft_ranking_entries (
            ranking_id, user_id, fhfh_player_id, order_key, seed_source,
            first_interacted_at, last_interacted_at
        ) values (
            v_session.ranking_id, p_user_id, v_session.fhfh_player_id,
            v_tail_key, 'assisted_placement', statement_timestamp(), statement_timestamp()
        );
    end if;

    v_result := public.reorder_draft_ranking(
        p_user_id, v_session.ranking_id, v_session.fhfh_player_id,
        'move_to_rank', v_session.suggested_rank, null, v_version,
        p_operation_id, p_operation_payload_hash
    );
    if v_result->>'status' <> 'completed' then
        if v_was_unplaced then
            delete from public.draft_ranking_entries
            where ranking_id = v_session.ranking_id
              and fhfh_player_id = v_session.fhfh_player_id;
        end if;
        return v_result;
    end if;

    update public.draft_ranker_placement_sessions
    set status = 'confirmed', completed_at = statement_timestamp()
    where id = p_session_id;
    delete from public.draft_ranker_player_preferences
    where ranking_id = v_session.ranking_id
      and fhfh_player_id = v_session.fhfh_player_id
      and disposition is null;

    v_result := v_result || jsonb_build_object(
        'sessionId', p_session_id,
        'wasUnplaced', v_was_unplaced,
        'plausibleLow', v_session.plausible_low,
        'plausibleHigh', v_session.plausible_high,
        'confidence', v_session.confidence
    );
    update public.draft_ranking_events
    set event_type = 'assisted_placement_confirmed',
        event_source = 'assisted_placement',
        metadata = jsonb_set(
            metadata || jsonb_build_object(
                'sessionId', p_session_id,
                'wasUnplaced', v_was_unplaced,
                'engineVersion', v_session.engine_version
            ),
            '{result}', v_result, true
        )
    where ranking_id = v_session.ranking_id and operation_id = p_operation_id;
    return v_result;
end;
$$;


--
-- Name: FUNCTION confirm_draft_ranker_placement(p_user_id uuid, p_session_id uuid, p_operation_id uuid, p_operation_payload_hash text); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.confirm_draft_ranker_placement(p_user_id uuid, p_session_id uuid, p_operation_id uuid, p_operation_payload_hash text) IS 'Service-only atomic assisted placement into the continuous ranking.';


--
-- Name: delete_duplicate_players_in_rosters(bigint); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.delete_duplicate_players_in_rosters(_seasonid bigint) RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
   DELETE FROM "rosters"
   WHERE ("rosters"."playerId", "rosters"."seasonId") in (
       SELECT "playerId","seasonId" from "rosters"
       WHERE "playerId" in (
           SELECT "rosters"."playerId"
           FROM "rosters"
           WHERE "rosters"."seasonId" = _seasonId
           GROUP BY "rosters"."playerId"
           HAVING COUNT("rosters"."playerId") > 1)
       );
END;
$$;


--
-- Name: enforce_draft_ranker_pairwise_rate_limit(uuid, text, uuid, text, bigint, bigint, boolean, jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.enforce_draft_ranker_pairwise_rate_limit(p_user_id uuid, p_action text, p_operation_id uuid, p_operation_payload_hash text, p_low_player_id bigint, p_high_player_id bigint, p_community_collection_enabled boolean, p_config jsonb) RETURNS jsonb
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public'
    AS $_$
declare
    v_existing_hash text;
    v_existing_result jsonb;
    v_now timestamptz := statement_timestamp();
    v_queue_hour_limit integer;
    v_queue_day_limit integer;
    v_response_minute_limit integer;
    v_response_hour_limit integer;
    v_soft_response_ten_minute_limit integer;
    v_same_pair_week_limit integer;
    v_hour_count integer := 0;
    v_day_count integer := 0;
    v_minute_count integer := 0;
    v_ten_minute_count integer := 0;
    v_same_pair_week_count integer := 0;
    v_allowed boolean := true;
    v_decision text := 'allowed';
    v_reason_code text;
    v_retry_after_seconds integer;
    v_counts jsonb;
    v_result jsonb;
begin
    if p_user_id is null or p_operation_id is null then
        raise exception using errcode = '22023', message = 'owner and operation IDs are required';
    end if;
    if p_action not in ('queue', 'respond') then
        raise exception using errcode = '22023', message = 'unsupported rate-limit action';
    end if;
    if p_operation_payload_hash is null
       or p_operation_payload_hash !~ '^[0-9a-f]{64}$' then
        raise exception using errcode = '22023', message = 'operation payload hash must be lowercase SHA-256';
    end if;
    if (p_low_player_id is null) <> (p_high_player_id is null)
       or (
           p_low_player_id is not null
           and p_low_player_id >= p_high_player_id
       ) then
        raise exception using errcode = '22023', message = 'rate-limit pair must be canonical or omitted';
    end if;
    if p_action = 'queue' and p_low_player_id is not null then
        raise exception using errcode = '22023', message = 'queue limits do not accept a player pair';
    end if;
    if p_config is null or jsonb_typeof(p_config) <> 'object' then
        raise exception using errcode = '22023', message = 'rate-limit config must be a JSON object';
    end if;

    v_queue_hour_limit := coalesce((p_config->>'queueHourlyLimit')::integer, 120);
    v_queue_day_limit := coalesce((p_config->>'queueDailyLimit')::integer, 500);
    v_response_minute_limit := coalesce((p_config->>'responseMinuteLimit')::integer, 60);
    v_response_hour_limit := coalesce((p_config->>'responseHourlyLimit')::integer, 300);
    v_soft_response_ten_minute_limit := coalesce(
        (p_config->>'communityResponseTenMinuteLimit')::integer,
        30
    );
    v_same_pair_week_limit := coalesce((p_config->>'samePairWeeklyLimit')::integer, 3);

    if v_queue_hour_limit not between 1 and 10000
       or v_queue_day_limit not between 1 and 50000
       or v_response_minute_limit not between 1 and 10000
       or v_response_hour_limit not between 1 and 50000
       or v_soft_response_ten_minute_limit not between 1 and 10000
       or v_same_pair_week_limit not between 1 and 1000 then
        raise exception using errcode = '22023', message = 'rate-limit config is outside supported bounds';
    end if;

    -- Serialize each account/action quota across every application instance.
    perform pg_advisory_xact_lock(
        hashtextextended(
            'draft-ranker-pairwise-rate:' || p_user_id::text || ':' || p_action,
            0
        )
    );

    select event.operation_payload_hash, event.result
    into v_existing_hash, v_existing_result
    from public.draft_ranker_pairwise_rate_events event
    where event.user_id = p_user_id
      and event.action = p_action
      and event.operation_id = p_operation_id;

    if found then
        if v_existing_hash <> p_operation_payload_hash then
            return jsonb_build_object(
                'status', 'conflict',
                'code', 'idempotency_conflict',
                'message', 'The operation ID was already used with a different rate-limit payload.'
            );
        end if;
        return coalesce(v_existing_result, '{}'::jsonb)
            || jsonb_build_object('idempotentReplay', true);
    end if;

    if p_action = 'queue' then
        select
            count(*) filter (where event.created_at >= v_now - interval '1 hour'),
            count(*)
        into v_hour_count, v_day_count
        from public.draft_ranker_pairwise_rate_events event
        where event.user_id = p_user_id
          and event.action = 'queue'
          and event.decision <> 'hard_limited'
          and event.created_at >= v_now - interval '1 day';

        if v_hour_count >= v_queue_hour_limit then
            v_allowed := false;
            v_decision := 'hard_limited';
            v_reason_code := 'queue_hour_limit';
            v_retry_after_seconds := 3600;
        elsif v_day_count >= v_queue_day_limit then
            v_allowed := false;
            v_decision := 'hard_limited';
            v_reason_code := 'queue_day_limit';
            v_retry_after_seconds := 86400;
        end if;
    else
        select
            count(*) filter (where event.created_at >= v_now - interval '1 minute'),
            count(*) filter (where event.created_at >= v_now - interval '10 minutes'),
            count(*)
        into v_minute_count, v_ten_minute_count, v_hour_count
        from public.draft_ranker_pairwise_rate_events event
        where event.user_id = p_user_id
          and event.action = 'respond'
          and event.decision <> 'hard_limited'
          and event.created_at >= v_now - interval '1 hour';

        if p_low_player_id is not null then
            select count(*) into v_same_pair_week_count
            from public.draft_ranker_pairwise_rate_events event
            where event.user_id = p_user_id
              and event.action = 'respond'
              and event.low_player_id = p_low_player_id
              and event.high_player_id = p_high_player_id
              and event.decision <> 'hard_limited'
              and event.created_at >= v_now - interval '7 days';
        end if;

        if v_minute_count >= v_response_minute_limit then
            v_allowed := false;
            v_decision := 'hard_limited';
            v_reason_code := 'response_minute_limit';
            v_retry_after_seconds := 60;
        elsif v_hour_count >= v_response_hour_limit then
            v_allowed := false;
            v_decision := 'hard_limited';
            v_reason_code := 'response_hour_limit';
            v_retry_after_seconds := 3600;
        elsif not coalesce(p_community_collection_enabled, false) then
            v_decision := 'community_suppressed';
            v_reason_code := 'community_collection_disabled';
        elsif v_ten_minute_count >= v_soft_response_ten_minute_limit then
            v_decision := 'community_suppressed';
            v_reason_code := 'automated_burst';
        elsif p_low_player_id is not null
          and v_same_pair_week_count >= v_same_pair_week_limit then
            v_decision := 'community_suppressed';
            v_reason_code := 'repeated_pair_targeting';
        end if;
    end if;

    v_counts := jsonb_build_object(
        'hour', v_hour_count,
        'day', v_day_count,
        'minute', v_minute_count,
        'tenMinutes', v_ten_minute_count,
        'samePairWeek', v_same_pair_week_count
    );
    v_result := jsonb_build_object(
        'status', case when v_allowed then 'completed' else 'rate_limited' end,
        'code', v_reason_code,
        'allowed', v_allowed,
        'decision', v_decision,
        'moderationReasonCode', v_reason_code,
        'communitySuppressionReason', case
            when v_decision = 'community_suppressed' then v_reason_code
            else null
        end,
        'retryAfterSeconds', v_retry_after_seconds,
        'windowCounts', v_counts,
        'idempotentReplay', false
    );

    insert into public.draft_ranker_pairwise_rate_events (
        user_id, action, operation_id, operation_payload_hash,
        low_player_id, high_player_id, decision, reason_code,
        window_counts, result
    ) values (
        p_user_id, p_action, p_operation_id, p_operation_payload_hash,
        p_low_player_id, p_high_player_id, v_decision, v_reason_code,
        v_counts, v_result
    );

    return v_result;
end;
$_$;


--
-- Name: FUNCTION enforce_draft_ranker_pairwise_rate_limit(p_user_id uuid, p_action text, p_operation_id uuid, p_operation_payload_hash text, p_low_player_id bigint, p_high_player_id bigint, p_community_collection_enabled boolean, p_config jsonb); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.enforce_draft_ranker_pairwise_rate_limit(p_user_id uuid, p_action text, p_operation_id uuid, p_operation_payload_hash text, p_low_player_id bigint, p_high_player_id bigint, p_community_collection_enabled boolean, p_config jsonb) IS 'Serializes per-account pairwise quotas and provides payload-safe operation replay across application instances.';


--
-- Name: execute_sql(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.execute_sql(sql_statement text) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$BEGIN
  EXECUTE sql_statement;
END;$$;


--
-- Name: finalize_non_realized_game_stats_v1(bigint); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.finalize_non_realized_game_stats_v1(p_game_id bigint) RETURNS TABLE(game_id bigint, outcome text, reason text, contract_version smallint, expected_team_rows integer, observed_team_rows integer, expected_skater_rows integer, observed_skater_rows integer, expected_goalie_rows integer, observed_goalie_rows integer, completed_at timestamp with time zone)
    LANGUAGE plpgsql
    SET search_path TO ''
    AS $$
declare
  v_status_count integer;
  v_completed_at timestamp with time zone := pg_catalog.transaction_timestamp();
begin
  if p_game_id is null or p_game_id <= 0 then
    raise exception using message = 'INVALID_NON_REALIZED_GAME_STATS_ID';
  end if;

  perform pg_catalog.pg_advisory_xact_lock(
    pg_catalog.hashtextextended('fhfh:game-stats:' || p_game_id::text, 0)
  );

  if not exists (
    select 1
    from public.games
    where id = p_game_id
      and "startTime" <= v_completed_at - pg_catalog.make_interval(days => 7)
  ) then
    raise exception using message = 'NON_REALIZED_GAME_STATS_NOT_OLD_ENOUGH';
  end if;

  if exists (
    select 1 from public."teamGameStats" where "gameId" = p_game_id
    union all
    select 1 from public."skatersGameStats" where "gameId" = p_game_id
    union all
    select 1 from public."goaliesGameStats" where "gameId" = p_game_id
  ) then
    raise exception using message = 'NON_REALIZED_GAME_STATS_PARTIAL_DATA_PRESENT';
  end if;

  update public."statsUpdateStatus" as status
  set
    updated = true,
    outcome = 'quarantined',
    reason = 'schedule_not_realized',
    contract_version = 1,
    expected_team_rows = 0,
    observed_team_rows = 0,
    expected_skater_rows = 0,
    observed_skater_rows = 0,
    expected_goalie_rows = 0,
    observed_goalie_rows = 0,
    completed_at = v_completed_at
  where status."gameId" = p_game_id
    and status.updated = false
    and status.outcome = 'pending'
    and status.reason is null
    and status.contract_version = 1
    and status.expected_team_rows is null
    and status.observed_team_rows is null
    and status.expected_skater_rows is null
    and status.observed_skater_rows is null
    and status.expected_goalie_rows is null
    and status.observed_goalie_rows is null
    and status.completed_at is null;
  get diagnostics v_status_count = row_count;

  if v_status_count <> 1 then
    raise exception using message = 'NON_REALIZED_GAME_STATS_STATUS_NOT_PENDING';
  end if;

  return query
  select
    p_game_id,
    'quarantined'::text,
    'schedule_not_realized'::text,
    1::smallint,
    0, 0, 0, 0, 0, 0,
    v_completed_at;
end;
$$;


--
-- Name: finish_xg_execution_lease(text, uuid, boolean, text, jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.finish_xg_execution_lease(p_lease_key text, p_owner_token uuid, p_succeeded boolean, p_error text DEFAULT NULL::text, p_metadata jsonb DEFAULT '{}'::jsonb) RETURNS boolean
    LANGUAGE sql
    SET search_path TO 'public', 'pg_temp'
    AS $$
  update public.xg_execution_leases
  set owner_token = null,
      state = case when p_succeeded then 'succeeded' else 'failed' end,
      lease_expires_at = null,
      completed_at = now(),
      last_success_at = case when p_succeeded then now() else last_success_at end,
      last_failure_at = case when p_succeeded then last_failure_at else now() end,
      last_error = case when p_succeeded then null else left(coalesce(p_error, 'unknown failure'), 2000) end,
      metadata = metadata || coalesce(p_metadata, '{}'::jsonb),
      updated_at = now()
  where lease_key = p_lease_key
    and owner_token = p_owner_token
    and state = 'running'
  returning true;
$$;


--
-- Name: get_aggregated_player_stats(integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_aggregated_player_stats(player_id_param integer, season_year integer) RETURNS TABLE(shooting_percentage double precision, assist_ratio double precision, total_peripherals double precision, pdo double precision, o_zone_start_pct double precision)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT
        CAST(SUM(s.goals) / NULLIF(SUM(s.shots), 0) * 100 AS FLOAT) AS shooting_percentage,
        CAST(SUM(s.total_primary_assists) / NULLIF(SUM(s.total_secondary_assists), 0) AS FLOAT) AS assist_ratio,
        CAST(SUM(s.blocked_shots + s.hits + s.shots) AS FLOAT) AS total_peripherals,
        CAST((SUM(s.skater_save_pct_5v5) / NULLIF(SUM(s.shooting_percentage_5v5), 0)) * 100 AS FLOAT) AS pdo,
        CAST(AVG(s.zone_start_pct) AS FLOAT) AS o_zone_start_pct
    FROM
        wgo_skater_stats s
    WHERE
        s.player_id = player_id_param
        AND EXTRACT(YEAR FROM s.date) = season_year;
END; $$;


--
-- Name: get_aggregated_player_stats(integer, date, date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_aggregated_player_stats(player_id_param integer, season_start_date date, end_date date) RETURNS TABLE(shooting_percentage double precision, assist_ratio double precision, total_peripherals double precision, pdo double precision, o_zone_start_pct double precision)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT
        SUM(s.goals) / NULLIF(SUM(s.shots), 0) * 100 AS shooting_percentage,
        SUM(s.total_primary_assists) / NULLIF(SUM(s.total_secondary_assists), 0) AS assist_ratio,
        SUM(s.blocked_shots + s.hits + s.shots)::FLOAT AS total_peripherals,
        (SUM(s.skater_save_pct_5v5) / NULLIF(SUM(s.shooting_percentage_5v5), 0)) * 100 AS pdo,
        AVG(s.zone_start_pct) AS o_zone_start_pct
    FROM
        wgo_skater_stats s
    WHERE
        s.player_id = player_id_param
        AND s.date >= season_start_date
        AND s.date <= end_date;
END; $$;


