--
-- Name: get_skater_game_score_by_limit(bigint, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_skater_game_score_by_limit(player_id bigint, num_games integer) RETURNS TABLE(game_date date, game_score numeric)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $_$
BEGIN
  RETURN QUERY
  SELECT sub.game_date, sub.game_score
  FROM (
    SELECT
        wgs.date AS game_date,
        (
          0.75 * wgs.goals +
          0.7 * wgs.total_primary_assists +
          0.55 * wgs.total_secondary_assists +
          0.075 * wgs.shots +
          0.05 * wgs.blocked_shots +
          0.15 * wgs.penalties_drawn -
          0.15 * wgs.penalties +
          0.01 * wgs.total_fow -
          0.01 * wgs.total_fol +
          0.05 * wgs.sat_for -
          0.05 * wgs.sat_against +
          0.15 * (wgs.es_goals_for + wgs.pp_goals_for + wgs.sh_goals_for) -
          0.15 * (wgs.es_goals_against + wgs.pp_goals_against + wgs.sh_goals_against)
        ) AS game_score
    FROM
        "wgo_skater_stats" wgs
    WHERE
        wgs."player_id" = $1
    ORDER BY wgs.date DESC
  ) sub
  WHERE sub.game_score IS NOT NULL
  ORDER BY sub.game_date DESC
  LIMIT $2;
END;
$_$;


--
-- Name: get_skater_game_scores_for_season(integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_skater_game_scores_for_season(p_player_id integer, p_season_id integer) RETURNS TABLE(game_date date, game_score numeric)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT sub.game_date, sub.game_score
  FROM (
    SELECT
        wgs.date AS game_date,
        (
          -- *** Your existing game_score calculation remains unchanged ***
          0.75 * wgs.goals +
          0.7 * wgs.total_primary_assists +
          0.55 * wgs.total_secondary_assists +
          0.075 * wgs.shots +
          0.05 * wgs.blocked_shots +
          0.15 * wgs.penalties_drawn -
          0.15 * wgs.penalties +
          0.01 * wgs.total_fow -
          0.01 * wgs.total_fol +
          0.05 * wgs.sat_for -
          0.05 * wgs.sat_against +
          0.15 * (wgs.es_goals_for + wgs.pp_goals_for + wgs.sh_goals_for) -
          0.15 * (wgs.es_goals_against + wgs.pp_goals_against + wgs.sh_goals_against)
        )::numeric AS game_score
    FROM
        "wgo_skater_stats" wgs
    WHERE
        wgs."player_id" = p_player_id
        -- ****** ADD THIS LINE - VERIFY YOUR COLUMN NAME ******
        AND wgs."season_id" = p_season_id
        -- *****************************************************
  ) sub
  WHERE sub.game_score IS NOT NULL
  ORDER BY sub.game_date ASC; -- Order ascending for chart display
  -- No LIMIT clause needed, as we want all games for the season
END;
$$;


--
-- Name: get_skaters_avg_stats(date, date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_skaters_avg_stats(start_date date, end_date date) RETURNS TABLE(id bigint, avggoals numeric, avgassists numeric, avgplusminus numeric, avgpim numeric, avghits numeric, avgblockedshots numeric, avgpowerplaypoints numeric, avgshots numeric, numgames bigint)
    LANGUAGE plpgsql
    AS $$BEGIN
   RETURN QUERY
      SELECT
       "skatersGameStats"."playerId" AS "id",
       AVG("skatersGameStats"."goals") AS "avgGoals",
       AVG("skatersGameStats"."assists") AS "avgAssists",
       AVG("skatersGameStats"."plusMinus") AS "avgPlusMinus",
       AVG("skatersGameStats"."pim") AS "avgPim",
       AVG("skatersGameStats"."hits") AS "avgHits",
       AVG("skatersGameStats"."blockedShots") AS "avgBlockedShots",
       AVG("skatersGameStats"."powerPlayPoints") AS "avgPowerPlayPoints",
       AVG("skatersGameStats"."shots") AS "avgShots",
       COUNT("skatersGameStats"."playerId") AS "numGames"
   FROM
       "skatersGameStats"
   INNER JOIN
       "games" ON "skatersGameStats"."gameId" = "games"."id"
   WHERE
       "games"."date" >= start_date AND
       "games"."date" <= end_date
   GROUP BY "skatersGameStats"."playerId";
END;$$;


--
-- Name: get_skaters_info_by_game_id(bigint); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_skaters_info_by_game_id(p_game_id bigint) RETURNS TABLE(id bigint, "teamId" smallint, "sweaterNumber" smallint, "position" text, "firstName" text, "lastName" text)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    WITH position_info AS (
  select "playerId", "skatersGameStats"."position"
  from "skatersGameStats"
  where "gameId" = 2023020845
),
season_info AS (
  select "seasonId", "homeTeamId", "awayTeamId" from games
  where "games"."id" = 2023020845
),
sweater_number_info AS (
  select "playerId", "rosters"."sweaterNumber", "rosters"."teamId" from rosters
  where "rosters"."seasonId" in (SELECT "seasonId" FROM season_info) AND ("rosters"."teamId" IN  (SELECT "homeTeamId" FROM  season_info) OR "rosters"."teamId" IN (SELECT "awayTeamId" FROM  season_info))
),
player_names_info AS (
  select players."id", players."firstName", players."lastName" from players
)
SELECT
position_info."playerId",
sweater_number_info."teamId",
sweater_number_info."sweaterNumber",
position_info."position"::TEXT AS position,
player_names_info."firstName",
player_names_info."lastName"
from position_info
LEFT JOIN sweater_number_info ON position_info."playerId" = sweater_number_info."playerId"
LEFT JOIN player_names_info ON position_info."playerId" = player_names_info."id";
END;
$$;


--
-- Name: get_unprocessed_line_combinations(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_unprocessed_line_combinations() RETURNS TABLE(id bigint)
    LANGUAGE plpgsql
    AS $$
BEGIN RETURN QUERY
 SELECT games.id
 FROM games
 WHERE games."startTime" <= now()
 AND games.id NOT IN (SELECT "gameId" FROM "lineCombinations")
 ORDER BY games."startTime" DESC;
END;
$$;


