--
-- Name: initialize_draft_ranking_from_yahoo(uuid, uuid, text, jsonb, bigint, integer, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.initialize_draft_ranking_from_yahoo(p_user_id uuid, p_operation_id uuid, p_operation_payload_hash text, p_scoring_profile jsonb DEFAULT '{}'::jsonb, p_target_season_id bigint DEFAULT 20262027, p_source_yahoo_season integer DEFAULT 2025, p_seed_revision text DEFAULT 'yahoo-2025-v1'::text) RETURNS jsonb
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public'
    AS $_$
declare
    v_ranking_id uuid;
    v_seed_run_id uuid;
    v_existing_status text;
    v_existing_result jsonb;
    v_existing_error jsonb;
    v_existing_operation_hash text;
    v_existing_entry_count bigint;
    v_source_count integer := 0;
    v_seeded_count integer := 0;
    v_invalid_adp_count integer := 0;
    v_unmapped_count integer := 0;
    v_fallback_count integer := 0;
    v_result jsonb;
begin
    if p_user_id is null or p_operation_id is null then
        raise exception using errcode = '22023', message = 'user and operation IDs are required';
    end if;
    if nullif(btrim(p_operation_payload_hash), '') is null
       or p_operation_payload_hash !~ '^[0-9a-f]{64}$' then
        raise exception using errcode = '22023', message = 'operation payload hash must be lowercase SHA-256';
    end if;
    if jsonb_typeof(p_scoring_profile) <> 'object' then
        raise exception using errcode = '22023', message = 'scoring profile must be a JSON object';
    end if;
    if p_target_season_id <> 20262027 or p_source_yahoo_season <> 2025 then
        raise exception using errcode = '22023', message = 'unsupported draft-ranker seed season';
    end if;
    if nullif(btrim(p_seed_revision), '') is null then
        raise exception using errcode = '22023', message = 'seed revision is required';
    end if;

    perform pg_catalog.pg_advisory_xact_lock(
        pg_catalog.hashtextextended(
            p_user_id::text || ':' || p_target_season_id::text,
            0
        )
    );

    select ranking.id
    into v_ranking_id
    from public.draft_rankings ranking
    where ranking.user_id = p_user_id
      and ranking.target_season_id = p_target_season_id
      and ranking.status = 'active'
      and ranking.is_default
    for update;

    if v_ranking_id is null then
        insert into public.draft_rankings (
            user_id,
            target_season_id,
            name,
            status,
            is_default,
            scoring_profile,
            schema_version,
            lock_version
        ) values (
            p_user_id,
            p_target_season_id,
            'My 2026-27 Draft Rankings',
            'active',
            true,
            p_scoring_profile,
            1,
            0
        )
        returning id into v_ranking_id;
    end if;

    select event.metadata->>'operation_payload_hash'
    into v_existing_operation_hash
    from public.draft_ranking_events event
    where event.ranking_id = v_ranking_id
      and event.operation_id = p_operation_id;

    if v_existing_operation_hash is not null then
        if v_existing_operation_hash <> p_operation_payload_hash then
            return jsonb_build_object(
                'status', 'conflict',
                'code', 'idempotency_conflict',
                'rankingId', v_ranking_id,
                'message', 'The operation ID was already used with a different payload.'
            );
        end if;
        select event.metadata->'result'
        into v_existing_result
        from public.draft_ranking_events event
        where event.ranking_id = v_ranking_id
          and event.operation_id = p_operation_id;
        return coalesce(v_existing_result, '{}'::jsonb)
            || jsonb_build_object('idempotentReplay', true);
    end if;

    select seed.status, seed.result_summary, seed.error_summary, seed.id
    into v_existing_status, v_existing_result, v_existing_error, v_seed_run_id
    from public.draft_ranking_seed_runs seed
    where seed.ranking_id = v_ranking_id
      and seed.seed_revision = p_seed_revision
    for update;

    if v_existing_status = 'completed' then
        select count(*) into v_existing_entry_count
        from public.draft_ranking_entries entry
        where entry.ranking_id = v_ranking_id;

        if v_existing_entry_count <> coalesce((v_existing_result->>'seededCount')::bigint, -1) then
            return jsonb_build_object(
                'status', 'failed',
                'code', 'seed_integrity_mismatch',
                'rankingId', v_ranking_id,
                'message', 'The completed seed record does not match the persisted ranking.'
            );
        end if;
        return coalesce(v_existing_result, '{}'::jsonb)
            || jsonb_build_object('idempotentReplay', true);
    end if;

    if v_existing_status = 'failed'
       and v_existing_error->>'operationId' = p_operation_id::text
       and v_existing_error->>'operationPayloadHash' <> p_operation_payload_hash then
        return jsonb_build_object(
            'status', 'conflict',
            'code', 'idempotency_conflict',
            'rankingId', v_ranking_id,
            'message', 'The operation ID was already used with a different payload.'
        );
    end if;

    if v_seed_run_id is null then
        insert into public.draft_ranking_seed_runs (
            ranking_id,
            user_id,
            seed_revision,
            source_season_id,
            status
        ) values (
            v_ranking_id,
            p_user_id,
            p_seed_revision,
            (p_source_yahoo_season::bigint * 10000) + p_source_yahoo_season + 1,
            'pending'
        )
        returning id into v_seed_run_id;
    else
        update public.draft_ranking_seed_runs
        set
            status = 'pending',
            source_count = 0,
            seeded_count = 0,
            invalid_adp_count = 0,
            unmapped_count = 0,
            fallback_count = 0,
            result_summary = '{}'::jsonb,
            error_summary = '{}'::jsonb,
            started_at = statement_timestamp(),
            completed_at = null
        where id = v_seed_run_id;
    end if;

    begin
        select count(*) into v_existing_entry_count
        from public.draft_ranking_entries entry
        where entry.ranking_id = v_ranking_id;

        if v_existing_entry_count <> 0 then
            update public.draft_ranking_seed_runs
            set
                status = 'failed',
                error_summary = jsonb_build_object(
                    'code', 'ranking_not_empty',
                    'operationId', p_operation_id,
                    'operationPayloadHash', p_operation_payload_hash,
                    'existingEntryCount', v_existing_entry_count
                ),
                completed_at = statement_timestamp()
            where id = v_seed_run_id;

            return jsonb_build_object(
                'status', 'failed',
                'code', 'ranking_not_empty',
                'rankingId', v_ranking_id,
                'message', 'The ranking already contains players and cannot be initialized.'
            );
        end if;

        with source as materialized (
            select
                yahoo.player_key,
                yahoo.average_draft_pick,
                case
                    when jsonb_typeof(yahoo.draft_analysis->'preseason_average_pick') = 'number'
                        then (yahoo.draft_analysis->>'preseason_average_pick')::numeric
                    when jsonb_typeof(yahoo.draft_analysis->'preseason_average_pick') = 'string'
                         and yahoo.draft_analysis->>'preseason_average_pick'
                            ~ '^\s*[0-9]+(?:\.[0-9]+)?\s*$'
                        then (yahoo.draft_analysis->>'preseason_average_pick')::numeric
                    else null
                end as preseason_adp
            from public.yahoo_players yahoo
            where yahoo.season = p_source_yahoo_season
        ),
        mapped as materialized (
            select
                source.*,
                mapping.fhfh_player_id,
                identity.lifecycle_status,
                identity.verification_status,
                identity.merged_into_id,
                case
                    when source.preseason_adp > 0 then source.preseason_adp
                    when source.average_draft_pick > 0 then source.average_draft_pick::numeric
                    else null
                end as seed_value,
                case
                    when source.preseason_adp > 0 then 'yahoo_prior_preseason_adp'
                    when source.average_draft_pick > 0 then 'yahoo_prior_average_pick_fallback'
                    else null
                end as seed_source
            from source
            join public.fhfh_player_external_identities mapping
              on mapping.provider = 'yahoo'
             and mapping.external_player_id = source.player_key
             and mapping.verification_status = 'verified'
            join public.fhfh_player_identities identity
              on identity.id = mapping.fhfh_player_id
        ),
        rankable as materialized (
            select mapped.*
            from mapped
            where mapped.verification_status = 'verified'
              and mapped.merged_into_id is null
              and mapped.lifecycle_status in (
                  'active_nhl', 'active_prospect', 'unsigned_relevant'
              )
        ),
        choices as materialized (
            select
                rankable.*,
                row_number() over (
                    partition by rankable.fhfh_player_id
                    order by
                        (rankable.seed_source = 'yahoo_prior_preseason_adp') desc,
                        rankable.seed_value,
                        rankable.player_key
                ) as identity_choice
            from rankable
            where rankable.seed_value > 0
        ),
        ranked as materialized (
            select
                choices.*,
                row_number() over (
                    order by
                        choices.seed_value,
                        (choices.seed_source = 'yahoo_prior_preseason_adp') desc,
                        choices.fhfh_player_id
                ) as seed_rank
            from choices
            where choices.identity_choice = 1
        ),
        inserted as (
            insert into public.draft_ranking_entries (
                ranking_id,
                user_id,
                fhfh_player_id,
                order_key,
                seed_source,
                seed_adp,
                seed_rank
            )
            select
                v_ranking_id,
                p_user_id,
                ranked.fhfh_player_id,
                ranked.seed_rank * 1048576,
                ranked.seed_source,
                ranked.seed_value,
                ranked.seed_rank
            from ranked
            returning fhfh_player_id
        )
        select
            (select count(*) from source),
            (select count(*) from inserted),
            (
                select count(distinct rankable.fhfh_player_id)
                from rankable
                where rankable.seed_value is null
            ),
            (
                select count(*)
                from source
                where not exists (
                    select 1
                    from public.fhfh_player_external_identities mapping
                    where mapping.provider = 'yahoo'
                      and mapping.external_player_id = source.player_key
                      and mapping.verification_status = 'verified'
                )
            ),
            (
                select count(*)
                from ranked
                where ranked.seed_source = 'yahoo_prior_average_pick_fallback'
            )
        into
            v_source_count,
            v_seeded_count,
            v_invalid_adp_count,
            v_unmapped_count,
            v_fallback_count;

        if v_seeded_count < 250 then
            delete from public.draft_ranking_entries
            where ranking_id = v_ranking_id;

            update public.draft_ranking_seed_runs
            set
                status = 'failed',
                source_count = v_source_count,
                seeded_count = v_seeded_count,
                invalid_adp_count = v_invalid_adp_count,
                unmapped_count = v_unmapped_count,
                fallback_count = v_fallback_count,
                error_summary = jsonb_build_object(
                    'code', 'insufficient_seed_candidates',
                    'operationId', p_operation_id,
                    'operationPayloadHash', p_operation_payload_hash,
                    'requiredCount', 250,
                    'availableCount', v_seeded_count
                ),
                completed_at = statement_timestamp()
            where id = v_seed_run_id;

            return jsonb_build_object(
                'status', 'failed',
                'code', 'insufficient_seed_candidates',
                'rankingId', v_ranking_id,
                'requiredCount', 250,
                'availableCount', v_seeded_count,
                'message', 'Fewer than 250 verified players have valid prior Yahoo ADP.'
            );
        end if;

        v_result := jsonb_build_object(
            'status', 'completed',
            'rankingId', v_ranking_id,
            'targetSeasonId', p_target_season_id,
            'sourceYahooSeason', p_source_yahoo_season,
            'seedRevision', p_seed_revision,
            'seededCount', v_seeded_count,
            'top250Count', least(v_seeded_count, 250),
            'candidateCount', greatest(v_seeded_count - 250, 0),
            'sourceCount', v_source_count,
            'invalidAdpCount', v_invalid_adp_count,
            'unmappedCount', v_unmapped_count,
            'fallbackCount', v_fallback_count,
            'idempotentReplay', false
        );

        update public.draft_ranking_seed_runs
        set
            status = 'completed',
            source_count = v_source_count,
            seeded_count = v_seeded_count,
            invalid_adp_count = v_invalid_adp_count,
            unmapped_count = v_unmapped_count,
            fallback_count = v_fallback_count,
            result_summary = v_result,
            error_summary = '{}'::jsonb,
            completed_at = statement_timestamp()
        where id = v_seed_run_id;

        update public.draft_rankings
        set
            scoring_profile = p_scoring_profile,
            seed_revision = p_seed_revision
        where id = v_ranking_id;

        insert into public.draft_ranking_events (
            ranking_id,
            user_id,
            event_type,
            event_source,
            operation_id,
            expected_version,
            resulting_version,
            before_state,
            after_state,
            metadata
        ) values (
            v_ranking_id,
            p_user_id,
            'ranking_initialized',
            'yahoo_prior_adp',
            p_operation_id,
            null,
            0,
            '{}'::jsonb,
            jsonb_build_object(
                'seededCount', v_seeded_count,
                'top250Count', least(v_seeded_count, 250),
                'candidateCount', greatest(v_seeded_count - 250, 0)
            ),
            jsonb_build_object(
                'operation_payload_hash', p_operation_payload_hash,
                'result', v_result
            )
        );

        return v_result;
    exception when others then
        update public.draft_ranking_seed_runs
        set
            status = 'failed',
            error_summary = jsonb_build_object(
                'code', 'seed_transaction_failed',
                'operationId', p_operation_id,
                'operationPayloadHash', p_operation_payload_hash,
                'sqlstate', sqlstate
            ),
            completed_at = statement_timestamp()
        where id = v_seed_run_id;

        return jsonb_build_object(
            'status', 'failed',
            'code', 'seed_transaction_failed',
            'rankingId', v_ranking_id,
            'message', 'The Yahoo seed transaction failed.'
        );
    end;
end;
$_$;


--
-- Name: FUNCTION initialize_draft_ranking_from_yahoo(p_user_id uuid, p_operation_id uuid, p_operation_payload_hash text, p_scoring_profile jsonb, p_target_season_id bigint, p_source_yahoo_season integer, p_seed_revision text); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.initialize_draft_ranking_from_yahoo(p_user_id uuid, p_operation_id uuid, p_operation_payload_hash text, p_scoring_profile jsonb, p_target_season_id bigint, p_source_yahoo_season integer, p_seed_revision text) IS 'Service-only, atomic, idempotent 2026-27 initialization from verified 2025 Yahoo ADP.';


--
-- Name: insert_into_statsupdatestatus(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.insert_into_statsupdatestatus() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
 INSERT INTO "statsUpdateStatus"("gameId", "updated") VALUES (NEW.id, false);
 RETURN NEW;
END;
$$;


--
-- Name: issue_draft_ranker_pair_prompt(uuid, uuid, bigint, bigint, text, text, text, bigint, uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.issue_draft_ranker_pair_prompt(p_user_id uuid, p_ranking_id uuid, p_player_a_id bigint, p_player_b_id bigint, p_queue_mode text, p_queue_reason text, p_algorithm_version text, p_expected_version bigint, p_operation_id uuid, p_operation_payload_hash text) RETURNS jsonb
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public'
    AS $_$
declare
    v_low_player_id bigint;
    v_high_player_id bigint;
    v_season_id bigint;
    v_current_version bigint;
    v_entry_count integer;
    v_existing public.draft_ranker_pair_prompts%rowtype;
    v_prompt public.draft_ranker_pair_prompts%rowtype;
begin
    if p_user_id is null or p_ranking_id is null
       or p_player_a_id is null or p_player_b_id is null
       or p_operation_id is null then
        raise exception using errcode = '22023', message = 'owner, ranking, players, and operation IDs are required';
    end if;
    if p_player_a_id = p_player_b_id then
        raise exception using errcode = '22023', message = 'a pair requires two different players';
    end if;
    if p_expected_version is null or p_expected_version < 0 then
        raise exception using errcode = '22023', message = 'expected version must be nonnegative';
    end if;
    if nullif(btrim(p_queue_mode), '') is null
       or nullif(btrim(p_queue_reason), '') is null
       or nullif(btrim(p_algorithm_version), '') is null then
        raise exception using errcode = '22023', message = 'queue mode, reason, and algorithm version are required';
    end if;
    if p_operation_payload_hash is null
       or p_operation_payload_hash !~ '^[0-9a-f]{64}$' then
        raise exception using errcode = '22023', message = 'operation payload hash must be lowercase SHA-256';
    end if;

    v_low_player_id := least(p_player_a_id, p_player_b_id);
    v_high_player_id := greatest(p_player_a_id, p_player_b_id);

    select prompt.* into v_existing
    from public.draft_ranker_pair_prompts prompt
    where prompt.user_id = p_user_id
      and prompt.issue_operation_id = p_operation_id;

    if v_existing.id is not null then
        if v_existing.issue_payload_hash <> p_operation_payload_hash then
            return jsonb_build_object(
                'status', 'conflict',
                'code', 'idempotency_conflict',
                'message', 'The operation ID was already used with a different payload.'
            );
        end if;
        return jsonb_build_object(
            'status', 'completed',
            'promptId', v_existing.id,
            'rankingId', v_existing.ranking_id,
            'seasonId', v_existing.season_id,
            'lowPlayerId', v_existing.low_player_id,
            'highPlayerId', v_existing.high_player_id,
            'rankingVersion', v_existing.ranking_version,
            'expiresAt', v_existing.expires_at,
            'idempotentReplay', true
        );
    end if;

    select ranking.target_season_id, ranking.lock_version
    into v_season_id, v_current_version
    from public.draft_rankings ranking
    where ranking.id = p_ranking_id
      and ranking.user_id = p_user_id
      and ranking.status = 'active'
    for update;

    if v_season_id is null then
        return jsonb_build_object(
            'status', 'not_found', 'code', 'not_found',
            'message', 'The requested ranking was not found.'
        );
    end if;
    if v_current_version <> p_expected_version then
        return jsonb_build_object(
            'status', 'conflict', 'code', 'stale_ranking_version',
            'expectedVersion', p_expected_version,
            'currentVersion', v_current_version,
            'message', 'The ranking changed. Reload before requesting comparisons.'
        );
    end if;

    select count(*) into v_entry_count
    from public.draft_ranking_entries entry
    where entry.ranking_id = p_ranking_id
      and entry.user_id = p_user_id
      and entry.fhfh_player_id in (v_low_player_id, v_high_player_id);

    if v_entry_count <> 2 then
        return jsonb_build_object(
            'status', 'failed', 'code', 'players_not_placed',
            'message', 'Both comparison players must be placed in this ranking.'
        );
    end if;

    update public.draft_ranker_pair_prompts prompt
    set status = 'expired'
    where prompt.user_id = p_user_id
      and prompt.ranking_id = p_ranking_id
      and prompt.status = 'issued'
      and prompt.expires_at <= statement_timestamp();

    insert into public.draft_ranker_pair_prompts (
        user_id, ranking_id, season_id, low_player_id, high_player_id,
        queue_mode, queue_reason, algorithm_version,
        issue_operation_id, issue_payload_hash, ranking_version,
        expires_at, metadata
    ) values (
        p_user_id, p_ranking_id, v_season_id, v_low_player_id, v_high_player_id,
        btrim(p_queue_mode), btrim(p_queue_reason), btrim(p_algorithm_version),
        p_operation_id, p_operation_payload_hash, v_current_version,
        statement_timestamp() + interval '15 minutes',
        jsonb_build_object('operation_payload_hash', p_operation_payload_hash)
    ) returning * into v_prompt;

    return jsonb_build_object(
        'status', 'completed',
        'promptId', v_prompt.id,
        'rankingId', v_prompt.ranking_id,
        'seasonId', v_prompt.season_id,
        'lowPlayerId', v_prompt.low_player_id,
        'highPlayerId', v_prompt.high_player_id,
        'rankingVersion', v_prompt.ranking_version,
        'expiresAt', v_prompt.expires_at,
        'idempotentReplay', false
    );
end;
$_$;


--
-- Name: issue_draft_ranker_pair_prompt_guarded(uuid, uuid, bigint, bigint, text, text, text, bigint, uuid, text, text, jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.issue_draft_ranker_pair_prompt_guarded(p_user_id uuid, p_ranking_id uuid, p_player_a_id bigint, p_player_b_id bigint, p_queue_mode text, p_queue_reason text, p_algorithm_version text, p_expected_version bigint, p_operation_id uuid, p_operation_payload_hash text, p_rate_operation_payload_hash text, p_rate_config jsonb) RETURNS jsonb
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public'
    AS $$
declare
    v_rate_result jsonb;
    v_result jsonb;
begin
    v_rate_result := public.enforce_draft_ranker_pairwise_rate_limit(
        p_user_id,
        'queue',
        p_operation_id,
        p_rate_operation_payload_hash,
        null,
        null,
        true,
        p_rate_config
    );

    if v_rate_result->>'status' in ('conflict', 'rate_limited') then
        return v_rate_result;
    end if;

    v_result := public.issue_draft_ranker_pair_prompt(
        p_user_id,
        p_ranking_id,
        p_player_a_id,
        p_player_b_id,
        p_queue_mode,
        p_queue_reason,
        p_algorithm_version,
        p_expected_version,
        p_operation_id,
        p_operation_payload_hash
    );

    return v_result || jsonb_build_object('rateLimit', v_rate_result);
end;
$$;


--
-- Name: persist_complete_game_stats_v1(bigint, jsonb, jsonb, jsonb, integer, integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.persist_complete_game_stats_v1(p_game_id bigint, p_team_rows jsonb, p_skater_rows jsonb, p_goalie_rows jsonb, p_expected_team_rows integer, p_expected_skater_rows integer, p_expected_goalie_rows integer) RETURNS TABLE(game_id bigint, outcome text, contract_version smallint, expected_team_rows integer, observed_team_rows integer, expected_skater_rows integer, observed_skater_rows integer, expected_goalie_rows integer, observed_goalie_rows integer, pruned_team_rows integer, pruned_skater_rows integer, pruned_goalie_rows integer, completed_at timestamp with time zone)
    LANGUAGE plpgsql
    SET search_path TO ''
    AS $$
declare
  v_team_payload_count integer;
  v_skater_payload_count integer;
  v_goalie_payload_count integer;
  v_team_distinct_count integer;
  v_skater_distinct_count integer;
  v_goalie_distinct_count integer;
  v_existing_team_count integer;
  v_existing_skater_count integer;
  v_existing_goalie_count integer;
  v_observed_team_count integer;
  v_observed_skater_count integer;
  v_observed_goalie_count integer;
  v_pruned_team_count integer := 0;
  v_pruned_skater_count integer := 0;
  v_pruned_goalie_count integer := 0;
  v_rows_are_valid boolean;
  v_completed_at timestamp with time zone := pg_catalog.transaction_timestamp();
begin
  if p_game_id is null or p_game_id <= 0 then
    raise exception using message = 'INVALID_GAME_STATS_GAME_ID';
  end if;

  if pg_catalog.jsonb_typeof(p_team_rows) is distinct from 'array'
    or pg_catalog.jsonb_typeof(p_skater_rows) is distinct from 'array'
    or pg_catalog.jsonb_typeof(p_goalie_rows) is distinct from 'array'
  then
    raise exception using message = 'INVALID_GAME_STATS_PAYLOAD_SHAPE';
  end if;

  v_team_payload_count := pg_catalog.jsonb_array_length(p_team_rows);
  v_skater_payload_count := pg_catalog.jsonb_array_length(p_skater_rows);
  v_goalie_payload_count := pg_catalog.jsonb_array_length(p_goalie_rows);

  if p_expected_team_rows is distinct from 2
    or v_team_payload_count is distinct from p_expected_team_rows
    or p_expected_skater_rows is null
    or p_expected_skater_rows not between 1 and 100
    or v_skater_payload_count is distinct from p_expected_skater_rows
    or p_expected_goalie_rows is null
    or p_expected_goalie_rows not between 1 and 100
    or v_goalie_payload_count is distinct from p_expected_goalie_rows
    or (p_expected_skater_rows + p_expected_goalie_rows) > 100
  then
    raise exception using message = 'INVALID_GAME_STATS_EXPECTED_COUNTS';
  end if;

  -- Cast and validate every input row before acquiring the lock or writing.
  select
    pg_catalog.count(*)::integer,
    pg_catalog.count(distinct incoming."teamId")::integer,
    coalesce(
      pg_catalog.bool_and(
        coalesce(
          (
            incoming."gameId" = p_game_id
            and incoming."teamId" > 0
            and incoming.score is not null
            and incoming.sog is not null
            and incoming."faceoffPctg" is not null
            and incoming.pim is not null
            and incoming.hits is not null
            and incoming."blockedShots" is not null
            and incoming.giveaways is not null
            and incoming.takeaways is not null
            and incoming."powerPlay" is not null
            and incoming."powerPlayConversion" is not null
            and incoming."powerPlayToi" is not null
          ),
          false
        )
      ),
      false
    )
  into v_team_payload_count, v_team_distinct_count, v_rows_are_valid
  from pg_catalog.jsonb_to_recordset(p_team_rows) as incoming(
    "gameId" bigint,
    "teamId" smallint,
    score smallint,
    sog smallint,
    "faceoffPctg" real,
    pim smallint,
    hits smallint,
    "blockedShots" smallint,
    giveaways smallint,
    takeaways smallint,
    "powerPlay" text,
    "powerPlayConversion" text,
    "powerPlayToi" text
  );

  if v_team_payload_count <> 2
    or v_team_distinct_count <> 2
    or not v_rows_are_valid
  then
    raise exception using message = 'INVALID_TEAM_GAME_STATS_ROWS';
  end if;

  select
    pg_catalog.count(*)::integer,
    pg_catalog.count(distinct incoming."playerId")::integer,
    coalesce(
      pg_catalog.bool_and(
        coalesce(
          (
            incoming."gameId" = p_game_id
            and incoming."playerId" > 0
            and incoming.position <> 'G'::public."NHL_Position_Code"
            and incoming.goals is not null
            and incoming.assists is not null
            and incoming.points is not null
            and incoming."plusMinus" is not null
            and incoming.pim is not null
            and incoming.hits is not null
            and incoming."blockedShots" is not null
            and incoming."powerPlayGoals" is not null
            and incoming."powerPlayPoints" is not null
            and incoming."shorthandedGoals" is not null
            and incoming."shPoints" is not null
            and incoming.shots is not null
            and incoming.faceoffs is not null
            and incoming."faceoffWinningPctg" is not null
            and incoming.toi is not null
            and incoming."powerPlayToi" is not null
            and incoming."shorthandedToi" is not null
          ),
          false
        )
      ),
      false
    )
  into v_skater_payload_count, v_skater_distinct_count, v_rows_are_valid
  from pg_catalog.jsonb_to_recordset(p_skater_rows) as incoming(
    "playerId" bigint,
    "gameId" bigint,
    position public."NHL_Position_Code",
    goals smallint,
    assists smallint,
    points smallint,
    "plusMinus" smallint,
    pim smallint,
    hits smallint,
    "blockedShots" smallint,
    "powerPlayGoals" smallint,
    "powerPlayPoints" smallint,
    "shorthandedGoals" smallint,
    "shPoints" smallint,
    shots smallint,
    faceoffs text,
    "faceoffWinningPctg" real,
    toi text,
    "powerPlayToi" text,
    "shorthandedToi" text
  );

  if v_skater_payload_count <> p_expected_skater_rows
    or v_skater_distinct_count <> p_expected_skater_rows
    or not v_rows_are_valid
  then
    raise exception using message = 'INVALID_SKATER_GAME_STATS_ROWS';
  end if;

  select
    pg_catalog.count(*)::integer,
    pg_catalog.count(distinct incoming."playerId")::integer,
    coalesce(
      pg_catalog.bool_and(
        coalesce(
          (
            incoming."gameId" = p_game_id
            and incoming."playerId" > 0
            and incoming.position = 'G'::public."NHL_Position_Code"
            and incoming."evenStrengthShotsAgainst" is not null
            and incoming."powerPlayShotsAgainst" is not null
            and incoming."shorthandedShotsAgainst" is not null
            and incoming."saveShotsAgainst" is not null
            and incoming."evenStrengthGoalsAgainst" is not null
            and incoming."powerPlayGoalsAgainst" is not null
            and incoming."shorthandedGoalsAgainst" is not null
            and incoming.pim is not null
            and incoming."goalsAgainst" is not null
            and incoming.toi is not null
            and incoming."savePctg" is not null
          ),
          false
        )
      ),
      false
    )
  into v_goalie_payload_count, v_goalie_distinct_count, v_rows_are_valid
  from pg_catalog.jsonb_to_recordset(p_goalie_rows) as incoming(
    "playerId" bigint,
    "gameId" bigint,
    position public."NHL_Position_Code",
    "evenStrengthShotsAgainst" text,
    "powerPlayShotsAgainst" text,
    "shorthandedShotsAgainst" text,
    "saveShotsAgainst" text,
    "evenStrengthGoalsAgainst" smallint,
    "powerPlayGoalsAgainst" smallint,
    "shorthandedGoalsAgainst" smallint,
    pim smallint,
    "goalsAgainst" smallint,
    toi text,
    "savePctg" real
  );

  if v_goalie_payload_count <> p_expected_goalie_rows
    or v_goalie_distinct_count <> p_expected_goalie_rows
    or not v_rows_are_valid
  then
    raise exception using message = 'INVALID_GOALIE_GAME_STATS_ROWS';
  end if;

  if exists (
    select 1
    from pg_catalog.jsonb_to_recordset(p_skater_rows)
      as skater("playerId" bigint)
    join pg_catalog.jsonb_to_recordset(p_goalie_rows)
      as goalie("playerId" bigint)
      on goalie."playerId" = skater."playerId"
  ) then
    raise exception using message = 'OVERLAPPING_SKATER_GOALIE_IDENTITIES';
  end if;

  perform pg_catalog.pg_advisory_xact_lock(
    pg_catalog.hashtextextended('fhfh:game-stats:' || p_game_id::text, 0)
  );

  if not exists (
    select 1 from public.games where id = p_game_id
  ) then
    raise exception using message = 'GAME_STATS_GAME_NOT_FOUND';
  end if;

  select pg_catalog.count(*)::integer
  into v_existing_team_count
  from public."teamGameStats"
  where "gameId" = p_game_id;

  select pg_catalog.count(*)::integer
  into v_existing_skater_count
  from public."skatersGameStats"
  where "gameId" = p_game_id;

  select pg_catalog.count(*)::integer
  into v_existing_goalie_count
  from public."goaliesGameStats"
  where "gameId" = p_game_id;

  if v_existing_team_count > 2
    or v_existing_skater_count > 100
    or v_existing_goalie_count > 100
  then
    raise exception using message = 'UNBOUNDED_EXISTING_GAME_STATS_ROWS';
  end if;

  insert into public."teamGameStats" (
    "gameId", "teamId", score, sog, "faceoffPctg", pim, hits,
    "blockedShots", giveaways, takeaways, "powerPlay",
    "powerPlayConversion", "powerPlayToi"
  )
  select
    incoming."gameId", incoming."teamId", incoming.score, incoming.sog,
    incoming."faceoffPctg", incoming.pim, incoming.hits,
    incoming."blockedShots", incoming.giveaways, incoming.takeaways,
    incoming."powerPlay", incoming."powerPlayConversion",
    incoming."powerPlayToi"
  from pg_catalog.jsonb_to_recordset(p_team_rows) as incoming(
    "gameId" bigint, "teamId" smallint, score smallint, sog smallint,
    "faceoffPctg" real, pim smallint, hits smallint, "blockedShots" smallint,
    giveaways smallint, takeaways smallint, "powerPlay" text,
    "powerPlayConversion" text, "powerPlayToi" text
  )
  on conflict ("gameId", "teamId") do update set
    score = excluded.score,
    sog = excluded.sog,
    "faceoffPctg" = excluded."faceoffPctg",
    pim = excluded.pim,
    hits = excluded.hits,
    "blockedShots" = excluded."blockedShots",
    giveaways = excluded.giveaways,
    takeaways = excluded.takeaways,
    "powerPlay" = excluded."powerPlay",
    "powerPlayConversion" = excluded."powerPlayConversion",
    "powerPlayToi" = excluded."powerPlayToi";

  insert into public."skatersGameStats" (
    "playerId", "gameId", position, goals, assists, points, "plusMinus",
    pim, hits, "blockedShots", "powerPlayGoals", "powerPlayPoints",
    "shorthandedGoals", "shPoints", shots, faceoffs,
    "faceoffWinningPctg", toi, "powerPlayToi", "shorthandedToi"
  )
  select
    incoming."playerId", incoming."gameId", incoming.position,
    incoming.goals, incoming.assists, incoming.points, incoming."plusMinus",
    incoming.pim, incoming.hits, incoming."blockedShots",
    incoming."powerPlayGoals", incoming."powerPlayPoints",
    incoming."shorthandedGoals", incoming."shPoints", incoming.shots,
    incoming.faceoffs, incoming."faceoffWinningPctg", incoming.toi,
    incoming."powerPlayToi", incoming."shorthandedToi"
  from pg_catalog.jsonb_to_recordset(p_skater_rows) as incoming(
    "playerId" bigint, "gameId" bigint, position public."NHL_Position_Code",
    goals smallint, assists smallint, points smallint, "plusMinus" smallint,
    pim smallint, hits smallint, "blockedShots" smallint,
    "powerPlayGoals" smallint, "powerPlayPoints" smallint,
    "shorthandedGoals" smallint, "shPoints" smallint, shots smallint,
    faceoffs text, "faceoffWinningPctg" real, toi text,
    "powerPlayToi" text, "shorthandedToi" text
  )
  on conflict ("playerId", "gameId") do update set
    position = excluded.position,
    goals = excluded.goals,
    assists = excluded.assists,
    points = excluded.points,
    "plusMinus" = excluded."plusMinus",
    pim = excluded.pim,
    hits = excluded.hits,
    "blockedShots" = excluded."blockedShots",
    "powerPlayGoals" = excluded."powerPlayGoals",
    "powerPlayPoints" = excluded."powerPlayPoints",
    "shorthandedGoals" = excluded."shorthandedGoals",
    "shPoints" = excluded."shPoints",
    shots = excluded.shots,
    faceoffs = excluded.faceoffs,
    "faceoffWinningPctg" = excluded."faceoffWinningPctg",
    toi = excluded.toi,
    "powerPlayToi" = excluded."powerPlayToi",
    "shorthandedToi" = excluded."shorthandedToi";

  insert into public."goaliesGameStats" (
    "playerId", "gameId", position, "evenStrengthShotsAgainst",
    "powerPlayShotsAgainst", "shorthandedShotsAgainst", "saveShotsAgainst",
    "evenStrengthGoalsAgainst", "powerPlayGoalsAgainst",
    "shorthandedGoalsAgainst", pim, "goalsAgainst", toi, "savePctg"
  )
  select
    incoming."playerId", incoming."gameId", incoming.position,
    incoming."evenStrengthShotsAgainst", incoming."powerPlayShotsAgainst",
    incoming."shorthandedShotsAgainst", incoming."saveShotsAgainst",
    incoming."evenStrengthGoalsAgainst", incoming."powerPlayGoalsAgainst",
    incoming."shorthandedGoalsAgainst", incoming.pim,
    incoming."goalsAgainst", incoming.toi, incoming."savePctg"
  from pg_catalog.jsonb_to_recordset(p_goalie_rows) as incoming(
    "playerId" bigint, "gameId" bigint, position public."NHL_Position_Code",
    "evenStrengthShotsAgainst" text, "powerPlayShotsAgainst" text,
    "shorthandedShotsAgainst" text, "saveShotsAgainst" text,
    "evenStrengthGoalsAgainst" smallint, "powerPlayGoalsAgainst" smallint,
    "shorthandedGoalsAgainst" smallint, pim smallint,
    "goalsAgainst" smallint, toi text, "savePctg" real
  )
  on conflict ("playerId", "gameId") do update set
    position = excluded.position,
    "evenStrengthShotsAgainst" = excluded."evenStrengthShotsAgainst",
    "powerPlayShotsAgainst" = excluded."powerPlayShotsAgainst",
    "shorthandedShotsAgainst" = excluded."shorthandedShotsAgainst",
    "saveShotsAgainst" = excluded."saveShotsAgainst",
    "evenStrengthGoalsAgainst" = excluded."evenStrengthGoalsAgainst",
    "powerPlayGoalsAgainst" = excluded."powerPlayGoalsAgainst",
    "shorthandedGoalsAgainst" = excluded."shorthandedGoalsAgainst",
    pim = excluded.pim,
    "goalsAgainst" = excluded."goalsAgainst",
    toi = excluded.toi,
    "savePctg" = excluded."savePctg";

  delete from public."teamGameStats" as existing
  where existing."gameId" = p_game_id
    and not exists (
      select 1
      from pg_catalog.jsonb_to_recordset(p_team_rows)
        as incoming("teamId" smallint)
      where incoming."teamId" = existing."teamId"
    );
  get diagnostics v_pruned_team_count = row_count;

  delete from public."skatersGameStats" as existing
  where existing."gameId" = p_game_id
    and not exists (
      select 1
      from pg_catalog.jsonb_to_recordset(p_skater_rows)
        as incoming("playerId" bigint)
      where incoming."playerId" = existing."playerId"
    );
  get diagnostics v_pruned_skater_count = row_count;

  delete from public."goaliesGameStats" as existing
  where existing."gameId" = p_game_id
    and not exists (
      select 1
      from pg_catalog.jsonb_to_recordset(p_goalie_rows)
        as incoming("playerId" bigint)
      where incoming."playerId" = existing."playerId"
    );
  get diagnostics v_pruned_goalie_count = row_count;

  select pg_catalog.count(*)::integer
  into v_observed_team_count
  from public."teamGameStats"
  where "gameId" = p_game_id;

  select pg_catalog.count(*)::integer
  into v_observed_skater_count
  from public."skatersGameStats"
  where "gameId" = p_game_id;

  select pg_catalog.count(*)::integer
  into v_observed_goalie_count
  from public."goaliesGameStats"
  where "gameId" = p_game_id;

  if v_observed_team_count <> p_expected_team_rows
    or v_observed_skater_count <> p_expected_skater_rows
    or v_observed_goalie_count <> p_expected_goalie_rows
  then
    raise exception using message = 'GAME_STATS_CARDINALITY_MISMATCH';
  end if;

  insert into public."statsUpdateStatus" (
    "gameId", updated, outcome, reason, contract_version,
    expected_team_rows, observed_team_rows,
    expected_skater_rows, observed_skater_rows,
    expected_goalie_rows, observed_goalie_rows, completed_at
  ) values (
    p_game_id, true, 'complete', null, 1,
    p_expected_team_rows, v_observed_team_count,
    p_expected_skater_rows, v_observed_skater_count,
    p_expected_goalie_rows, v_observed_goalie_count, v_completed_at
  )
  on conflict ("gameId") do update set
    updated = excluded.updated,
    outcome = excluded.outcome,
    reason = excluded.reason,
    contract_version = excluded.contract_version,
    expected_team_rows = excluded.expected_team_rows,
    observed_team_rows = excluded.observed_team_rows,
    expected_skater_rows = excluded.expected_skater_rows,
    observed_skater_rows = excluded.observed_skater_rows,
    expected_goalie_rows = excluded.expected_goalie_rows,
    observed_goalie_rows = excluded.observed_goalie_rows,
    completed_at = excluded.completed_at;

  return query select
    p_game_id,
    'complete'::text,
    1::smallint,
    p_expected_team_rows,
    v_observed_team_count,
    p_expected_skater_rows,
    v_observed_skater_count,
    p_expected_goalie_rows,
    v_observed_goalie_count,
    v_pruned_team_count,
    v_pruned_skater_count,
    v_pruned_goalie_count,
    v_completed_at;
end;
$$;


