-- Name: prevent_nhl_api_game_payloads_raw_mutation(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.prevent_nhl_api_game_payloads_raw_mutation() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  RAISE EXCEPTION 'nhl_api_game_payloads_raw rows are immutable';
END;
$$;


--
-- Name: process_team_goalie_projections(integer, integer, date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.process_team_goalie_projections(p_game_id integer, p_team_id integer, p_date date) RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_team_abbrev TEXT;
    v_league_sv_pct NUMERIC := 0.900; -- Conservative league average
BEGIN
    -- Get Team Abbreviation
    SELECT abbreviation INTO v_team_abbrev FROM teams WHERE id = p_team_id;

    -- If team not found, exit
    IF v_team_abbrev IS NULL THEN
        RETURN;
    END IF;

    -- Calculate and Insert Projections
    WITH last_games AS (
        -- Get dates of the last 10 games for this team
        SELECT date
        FROM wgo_team_stats
        WHERE team_id = p_team_id AND date < p_date
        ORDER BY date DESC
        LIMIT 10
    ),
    goalie_stats AS (
        -- Aggregate stats for goalies in those games
        SELECT
            gs.goalie_id,
            SUM(gs.games_started) as starts,
            SUM(gs.shots_against) as sa,
            SUM(gs.goals_against) as ga,
            SUM(gs.time_on_ice) as toi -- Assuming minutes
        FROM wgo_goalie_stats gs
        WHERE gs.team_abbreviation = v_team_abbrev
          AND gs.date IN (SELECT date FROM last_games)
        GROUP BY gs.goalie_id
    ),
    total_stats AS (
        -- Total starts in the sample (should be ~10)
        SELECT SUM(starts) as total_starts FROM goalie_stats
    )
    INSERT INTO goalie_start_projections (
        game_id,
        team_id,
        player_id,
        start_probability,
        projected_gsaa_per_60,
        confirmed_status
    )
    SELECT
        p_game_id,
        p_team_id,
        gs.goalie_id,
        -- Probability: starts / total_starts
        COALESCE(gs.starts::NUMERIC / NULLIF((SELECT total_starts FROM total_stats), 0), 0),
        -- GSAA per 60: ((SA * AvgSv%) - GA) / TOI * 60
        CASE
            WHEN gs.toi > 0 THEN
                (((gs.sa * v_league_sv_pct) - gs.ga) / gs.toi) * 60
            ELSE 0
        END,
        FALSE -- Default confirmed status
    FROM goalie_stats gs
    ON CONFLICT (game_id, player_id) DO UPDATE SET
        start_probability = EXCLUDED.start_probability,
        projected_gsaa_per_60 = EXCLUDED.projected_gsaa_per_60,
        updated_at = NOW();

END;
$$;


--
-- Name: quarantine_game_stats_v1(bigint[], text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.quarantine_game_stats_v1(p_game_ids bigint[], p_reason text) RETURNS TABLE(game_id bigint, outcome text, reason text, contract_version smallint, expected_team_rows integer, observed_team_rows integer, expected_skater_rows integer, observed_skater_rows integer, expected_goalie_rows integer, observed_goalie_rows integer, completed_at timestamp with time zone)
    LANGUAGE plpgsql
    SET search_path TO ''
    AS $$
declare
  v_game_ids bigint[];
  v_game_id bigint;
  v_game_count integer;
  v_status_count integer;
  v_completed_at timestamp with time zone := pg_catalog.transaction_timestamp();
begin
  if p_reason is distinct from 'game_not_finished' then
    raise exception using message = 'INVALID_GAME_STATS_QUARANTINE_REASON';
  end if;

  if p_game_ids is null
    or pg_catalog.cardinality(p_game_ids) not between 1 and 10
    or exists (
      select 1
      from pg_catalog.unnest(p_game_ids) as requested(game_id)
      where requested.game_id is null or requested.game_id <= 0
    )
  then
    raise exception using message = 'INVALID_GAME_STATS_QUARANTINE_IDS';
  end if;

  select pg_catalog.array_agg(requested.game_id order by requested.game_id)
  into v_game_ids
  from (
    select distinct requested.game_id
    from pg_catalog.unnest(p_game_ids) as requested(game_id)
  ) as requested;

  if pg_catalog.cardinality(v_game_ids) <> pg_catalog.cardinality(p_game_ids) then
    raise exception using message = 'DUPLICATE_GAME_STATS_QUARANTINE_IDS';
  end if;

  foreach v_game_id in array v_game_ids loop
    perform pg_catalog.pg_advisory_xact_lock(
      pg_catalog.hashtextextended('fhfh:game-stats:' || v_game_id::text, 0)
    );
  end loop;

  select pg_catalog.count(*)::integer
  into v_game_count
  from public.games
  where id = any(v_game_ids)
    and date < (current_date - 30);

  if v_game_count <> pg_catalog.cardinality(v_game_ids) then
    raise exception using message = 'GAME_STATS_QUARANTINE_GAME_NOT_ELIGIBLE';
  end if;

  if exists (
    select 1 from public."teamGameStats" where "gameId" = any(v_game_ids)
    union all
    select 1 from public."skatersGameStats" where "gameId" = any(v_game_ids)
    union all
    select 1 from public."goaliesGameStats" where "gameId" = any(v_game_ids)
  ) then
    raise exception using message = 'GAME_STATS_QUARANTINE_PARTIAL_DATA_PRESENT';
  end if;

  update public."statsUpdateStatus" as status
  set
    updated = true,
    outcome = 'quarantined',
    reason = p_reason,
    contract_version = 1,
    expected_team_rows = 0,
    observed_team_rows = 0,
    expected_skater_rows = 0,
    observed_skater_rows = 0,
    expected_goalie_rows = 0,
    observed_goalie_rows = 0,
    completed_at = v_completed_at
  from pg_catalog.unnest(v_game_ids) as requested(game_id)
  where status."gameId" = requested.game_id
    and status.updated = false
    and status.outcome = 'pending'
    and status.reason is null
    and status.contract_version = 1
    and status.expected_team_rows is null
    and status.observed_team_rows is null
    and status.expected_skater_rows is null
    and status.observed_skater_rows is null
    and status.expected_goalie_rows is null
    and status.observed_goalie_rows is null
    and status.completed_at is null;
  get diagnostics v_status_count = row_count;

  if v_status_count <> pg_catalog.cardinality(v_game_ids) then
    raise exception using message = 'GAME_STATS_QUARANTINE_STATUS_NOT_PENDING';
  end if;

  return query
  select
    requested.game_id,
    'quarantined'::text,
    p_reason,
    1::smallint,
    0, 0, 0, 0, 0, 0,
    v_completed_at
  from pg_catalog.unnest(v_game_ids) as requested(game_id)
  order by requested.game_id;
end;
$$;


--
-- Name: refresh_player_lineup_deployment_tallies(integer, bigint); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.refresh_player_lineup_deployment_tallies(p_season_id integer DEFAULT NULL::integer, p_player_id bigint DEFAULT NULL::bigint) RETURNS TABLE(deleted_rows integer, inserted_rows integer)
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
declare
  v_deleted_rows integer := 0;
  v_inserted_rows integer := 0;
begin
  delete from public.player_lineup_deployment_tallies t
  where (p_season_id is null or t.season_id = p_season_id)
    and (p_player_id is null or t.player_id = p_player_id);

  get diagnostics v_deleted_rows = row_count;

  insert into public.player_lineup_deployment_tallies (
    player_id,
    season_id,
    game_type,
    deployment_group,
    deployment_code,
    deployment_label,
    line_number,
    slot_number,
    slot_label,
    unit_number,
    games,
    total_games,
    share,
    team_ids,
    first_game_date,
    last_game_date,
    source_table,
    updated_at
  )
  with forward_source as (
    select distinct
      f.player_id::bigint as player_id,
      g."seasonId"::integer as season_id,
      g.type::integer as game_type,
      lc."gameId"::bigint as game_id,
      g.date::date as game_date,
      lc."teamId"::integer as team_id,
      (floor((f.ordinality - 1) / 3)::integer + 1) as line_number,
      case
        when upper(p.position::text) in ('LW', 'L') then 'LW'
        when upper(p.position::text) = 'C' then 'C'
        when upper(p.position::text) in ('RW', 'R') then 'RW'
        else null
      end as slot_label
    from public."lineCombinations" lc
    join public.games g on g.id = lc."gameId"
    cross join lateral unnest(lc.forwards) with ordinality as f(player_id, ordinality)
    left join public.players p on p.id = f.player_id
    where f.ordinality <= 12
      and g.type in (2, 3)
      and (p_season_id is null or g."seasonId"::integer = p_season_id)
      and (p_player_id is null or f.player_id::bigint = p_player_id)
  ),
  forward_counts as (
    select
      player_id,
      season_id,
      game_type,
      'forward'::text as deployment_group,
      ('F' || line_number::text || '_' || slot_label)::text as deployment_code,
      ('Forward Line ' || line_number::text || ' ' || slot_label)::text as deployment_label,
      line_number,
      case slot_label when 'LW' then 1 when 'C' then 2 when 'RW' then 3 end as slot_number,
      slot_label,
      null::integer as unit_number,
      count(distinct game_id)::integer as games,
      array_remove(array_agg(distinct team_id order by team_id), null)::integer[] as team_ids,
      min(game_date) as first_game_date,
      max(game_date) as last_game_date,
      'lineCombinations'::text as source_table
    from forward_source
    where slot_label in ('LW', 'C', 'RW')
    group by player_id, season_id, game_type, line_number, slot_label
  ),
  defense_source as (
    select distinct
      d.player_id::bigint as player_id,
      g."seasonId"::integer as season_id,
      g.type::integer as game_type,
      lc."gameId"::bigint as game_id,
      g.date::date as game_date,
      lc."teamId"::integer as team_id,
      (floor((d.ordinality - 1) / 2)::integer + 1) as line_number,
      case ((d.ordinality - 1) % 2)
        when 0 then 'LD'
        else 'RD'
      end as slot_label
    from public."lineCombinations" lc
    join public.games g on g.id = lc."gameId"
    cross join lateral unnest(lc.defensemen) with ordinality as d(player_id, ordinality)
    where d.ordinality <= 6
      and g.type in (2, 3)
      and (p_season_id is null or g."seasonId"::integer = p_season_id)
      and (p_player_id is null or d.player_id::bigint = p_player_id)
  ),
  defense_counts as (
    select
      player_id,
      season_id,
      game_type,
      'defense'::text as deployment_group,
      ('D' || line_number::text || '_' || slot_label)::text as deployment_code,
      ('Defense Pair ' || line_number::text || ' ' || slot_label)::text as deployment_label,
      line_number,
      case slot_label when 'LD' then 1 when 'RD' then 2 end as slot_number,
      slot_label,
      null::integer as unit_number,
      count(distinct game_id)::integer as games,
      array_remove(array_agg(distinct team_id order by team_id), null)::integer[] as team_ids,
      min(game_date) as first_game_date,
      max(game_date) as last_game_date,
      'lineCombinations'::text as source_table
    from defense_source
    where line_number between 1 and 3
    group by player_id, season_id, game_type, line_number, slot_label
  ),
  power_play_source as (
    select distinct on (pp."playerId", g."seasonId", g.type, pp."gameId")
      pp."playerId"::bigint as player_id,
      g."seasonId"::integer as season_id,
      g.type::integer as game_type,
      pp."gameId"::bigint as game_id,
      g.date::date as game_date,
      case
        when g."homeTeamId" = lc."teamId" or g."awayTeamId" = lc."teamId"
          then lc."teamId"::integer
        else null
      end as team_id,
      pp.unit::integer as unit_number
    from public."powerPlayCombinations" pp
    join public.games g on g.id = pp."gameId"
    left join public."lineCombinations" lc
      on lc."gameId" = pp."gameId"
     and pp."playerId" = any(lc.forwards || lc.defensemen)
    where pp.unit in (1, 2)
      and g.type in (2, 3)
      and (p_season_id is null or g."seasonId"::integer = p_season_id)
      and (p_player_id is null or pp."playerId"::bigint = p_player_id)
    order by pp."playerId", g."seasonId", g.type, pp."gameId", pp.unit
  ),
  power_play_counts as (
    select
      player_id,
      season_id,
      game_type,
      'power_play'::text as deployment_group,
      ('PP' || unit_number::text)::text as deployment_code,
      ('Power Play ' || unit_number::text)::text as deployment_label,
      null::integer as line_number,
      unit_number as slot_number,
      ('PP' || unit_number::text)::text as slot_label,
      unit_number,
      count(distinct game_id)::integer as games,
      array_remove(array_agg(distinct team_id order by team_id), null)::integer[] as team_ids,
      min(game_date) as first_game_date,
      max(game_date) as last_game_date,
      'powerPlayCombinations'::text as source_table
    from power_play_source
    group by player_id, season_id, game_type, unit_number
  ),
  combined_counts as (
    select * from forward_counts
    union all
    select * from defense_counts
    union all
    select * from power_play_counts
  ),
  with_totals as (
    select
      c.*,
      sum(c.games) over (
        partition by c.player_id, c.season_id, c.game_type, c.deployment_group
      )::integer as total_games
    from combined_counts c
  )
  select
    player_id,
    season_id,
    game_type,
    deployment_group,
    deployment_code,
    deployment_label,
    line_number,
    slot_number,
    slot_label,
    unit_number,
    games,
    total_games,
    round((games::numeric / nullif(total_games, 0)::numeric), 4) as share,
    team_ids,
    first_game_date,
    last_game_date,
    source_table,
    now() as updated_at
  from with_totals
  where total_games > 0;

  get diagnostics v_inserted_rows = row_count;

  return query select v_deleted_rows, v_inserted_rows;
end;
$$;


--
-- Name: FUNCTION refresh_player_lineup_deployment_tallies(p_season_id integer, p_player_id bigint); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.refresh_player_lineup_deployment_tallies(p_season_id integer, p_player_id bigint) IS 'Refreshes player lineup deployment tallies from lineCombinations and powerPlayCombinations. Optional filters bound the refresh to a season or player.';


