--
-- Name: reorder_draft_ranking(uuid, uuid, bigint, text, integer, bigint, bigint, uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.reorder_draft_ranking(p_user_id uuid, p_ranking_id uuid, p_player_id bigint, p_action text, p_target_rank integer, p_anchor_player_id bigint, p_expected_version bigint, p_operation_id uuid, p_operation_payload_hash text) RETURNS jsonb
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public'
    AS $_$
declare
    v_original_version bigint;
    v_current_version bigint;
    v_existing_hash text;
    v_existing_result jsonb;
    v_entry_count integer;
    v_current_rank integer;
    v_destination_rank integer;
    v_anchor_rank integer;
    v_old_key bigint;
    v_new_key bigint;
    v_new_key_numeric numeric;
    v_prev_key bigint;
    v_next_key bigint;
    v_normalized boolean := false;
    v_before_250 bigint;
    v_before_251 bigint;
    v_after_250 bigint;
    v_after_251 bigint;
    v_conflict_count integer := 0;
    v_result jsonb;
begin
    if p_user_id is null or p_ranking_id is null or p_player_id is null
       or p_operation_id is null then
        raise exception using errcode = '22023', message = 'owner, ranking, player, and operation IDs are required';
    end if;
    if p_expected_version is null or p_expected_version < 0 then
        raise exception using errcode = '22023', message = 'expected version must be nonnegative';
    end if;
    if nullif(btrim(p_operation_payload_hash), '') is null
       or p_operation_payload_hash !~ '^[0-9a-f]{64}$' then
        raise exception using errcode = '22023', message = 'operation payload hash must be lowercase SHA-256';
    end if;
    if p_action not in (
        'move_to_rank', 'insert_above', 'insert_below', 'remove_to_bench'
    ) then
        raise exception using errcode = '22023', message = 'unsupported reorder action';
    end if;

    select ranking.lock_version
    into v_original_version
    from public.draft_rankings ranking
    where ranking.id = p_ranking_id
      and ranking.user_id = p_user_id
      and ranking.status = 'active'
    for update;

    if v_original_version is null then
        return jsonb_build_object(
            'status', 'not_found',
            'code', 'not_found',
            'message', 'The requested ranking was not found.'
        );
    end if;

    select
        event.metadata->>'operation_payload_hash',
        event.metadata->'result'
    into v_existing_hash, v_existing_result
    from public.draft_ranking_events event
    where event.ranking_id = p_ranking_id
      and event.operation_id = p_operation_id;

    if v_existing_hash is not null then
        if v_existing_hash <> p_operation_payload_hash then
            return jsonb_build_object(
                'status', 'conflict',
                'code', 'idempotency_conflict',
                'rankingId', p_ranking_id,
                'message', 'The operation ID was already used with a different payload.'
            );
        end if;
        return coalesce(v_existing_result, '{}'::jsonb)
            || jsonb_build_object('idempotentReplay', true);
    end if;

    if v_original_version <> p_expected_version then
        return jsonb_build_object(
            'status', 'conflict',
            'code', 'stale_ranking_version',
            'rankingId', p_ranking_id,
            'expectedVersion', p_expected_version,
            'currentVersion', v_original_version,
            'message', 'The ranking changed. Reload before retrying.'
        );
    end if;

    select count(*) into v_entry_count
    from public.draft_ranking_entries entry
    where entry.ranking_id = p_ranking_id
      and entry.user_id = p_user_id;

    select ranked.visible_rank, ranked.order_key
    into v_current_rank, v_old_key
    from (
        select
            entry.fhfh_player_id,
            entry.order_key,
            row_number() over (
                order by entry.order_key, entry.fhfh_player_id
            )::integer as visible_rank
        from public.draft_ranking_entries entry
        where entry.ranking_id = p_ranking_id
          and entry.user_id = p_user_id
    ) ranked
    where ranked.fhfh_player_id = p_player_id;

    if v_current_rank is null then
        return jsonb_build_object(
            'status', 'not_found',
            'code', 'not_found',
            'rankingId', p_ranking_id,
            'message', 'The requested player is not placed in this ranking.'
        );
    end if;

    if p_action = 'move_to_rank' then
        if p_target_rank is null
           or p_target_rank < 1
           or p_target_rank > v_entry_count then
            return jsonb_build_object(
                'status', 'failed',
                'code', 'invalid_target_rank',
                'rankingId', p_ranking_id,
                'entryCount', v_entry_count,
                'message', 'The requested global rank is outside this ranking.'
            );
        end if;
        v_destination_rank := p_target_rank;
    elsif p_action in ('insert_above', 'insert_below') then
        if p_anchor_player_id is null or p_anchor_player_id = p_player_id then
            return jsonb_build_object(
                'status', 'failed',
                'code', 'invalid_anchor',
                'rankingId', p_ranking_id,
                'message', 'A different placed anchor player is required.'
            );
        end if;

        select ordered.position
        into v_anchor_rank
        from (
            select
                entry.fhfh_player_id,
                row_number() over (
                    order by entry.order_key, entry.fhfh_player_id
                )::integer as position
            from public.draft_ranking_entries entry
            where entry.ranking_id = p_ranking_id
              and entry.user_id = p_user_id
              and entry.fhfh_player_id <> p_player_id
        ) ordered
        where ordered.fhfh_player_id = p_anchor_player_id;

        if v_anchor_rank is null then
            return jsonb_build_object(
                'status', 'not_found',
                'code', 'not_found',
                'rankingId', p_ranking_id,
                'message', 'The anchor player is not placed in this ranking.'
            );
        end if;
        v_destination_rank := v_anchor_rank
            + case when p_action = 'insert_below' then 1 else 0 end;
    else
        v_destination_rank := least(251, v_entry_count);
    end if;

    select
        max(entry.fhfh_player_id) filter (where entry.visible_rank = 250),
        max(entry.fhfh_player_id) filter (where entry.visible_rank = 251)
    into v_before_250, v_before_251
    from (
        select
            placed.fhfh_player_id,
            row_number() over (
                order by placed.order_key, placed.fhfh_player_id
            )::integer as visible_rank
        from public.draft_ranking_entries placed
        where placed.ranking_id = p_ranking_id
    ) entry;

    select
        max(ordered.order_key) filter (
            where ordered.position = v_destination_rank - 1
        ),
        max(ordered.order_key) filter (
            where ordered.position = v_destination_rank
        )
    into v_prev_key, v_next_key
    from (
        select
            entry.order_key,
            row_number() over (
                order by entry.order_key, entry.fhfh_player_id
            )::integer as position
        from public.draft_ranking_entries entry
        where entry.ranking_id = p_ranking_id
          and entry.user_id = p_user_id
          and entry.fhfh_player_id <> p_player_id
    ) ordered;

    if v_prev_key is not null and v_next_key is not null
       and v_next_key::numeric - v_prev_key::numeric <= 1 then
        set constraints draft_entries_order_unique deferred;

        with ordered as (
            select
                entry.fhfh_player_id,
                row_number() over (
                    order by entry.order_key, entry.fhfh_player_id
                )::bigint as position
            from public.draft_ranking_entries entry
            where entry.ranking_id = p_ranking_id
              and entry.user_id = p_user_id
        )
        update public.draft_ranking_entries entry
        set order_key = ordered.position * 1048576
        from ordered
        where entry.ranking_id = p_ranking_id
          and entry.fhfh_player_id = ordered.fhfh_player_id;

        v_current_version := v_original_version + 1;
        update public.draft_rankings
        set lock_version = v_current_version
        where id = p_ranking_id;

        insert into public.draft_ranking_events (
            ranking_id, user_id, event_type, event_source, operation_id,
            expected_version, resulting_version, before_state, after_state, metadata
        ) values (
            p_ranking_id, p_user_id, 'order_normalized', 'system', gen_random_uuid(),
            v_original_version, v_current_version,
            jsonb_build_object('reason', 'midpoint_exhausted'),
            jsonb_build_object('stride', 1048576, 'entryCount', v_entry_count),
            jsonb_build_object('triggeringOperationId', p_operation_id)
        );
        v_normalized := true;

        select
            max(ordered.order_key) filter (
                where ordered.position = v_destination_rank - 1
            ),
            max(ordered.order_key) filter (
                where ordered.position = v_destination_rank
            )
        into v_prev_key, v_next_key
        from (
            select
                entry.order_key,
                row_number() over (
                    order by entry.order_key, entry.fhfh_player_id
                )::integer as position
            from public.draft_ranking_entries entry
            where entry.ranking_id = p_ranking_id
              and entry.user_id = p_user_id
              and entry.fhfh_player_id <> p_player_id
        ) ordered;
    else
        v_current_version := v_original_version;
    end if;

    if v_prev_key is null and v_next_key is null then
        v_new_key_numeric := v_old_key;
    elsif v_prev_key is null then
        v_new_key_numeric := v_next_key::numeric - 1048576;
    elsif v_next_key is null then
        v_new_key_numeric := v_prev_key::numeric + 1048576;
    else
        v_new_key_numeric := v_prev_key::numeric
            + floor((v_next_key::numeric - v_prev_key::numeric) / 2);
    end if;

    if v_new_key_numeric < -9223372036854775808::numeric
       or v_new_key_numeric > 9223372036854775807::numeric then
        return jsonb_build_object(
            'status', 'failed',
            'code', 'order_key_overflow',
            'rankingId', p_ranking_id,
            'message', 'The ranking order requires operator repair.'
        );
    end if;
    v_new_key := v_new_key_numeric::bigint;

    update public.draft_ranking_entries
    set
        order_key = v_new_key,
        first_interacted_at = coalesce(first_interacted_at, statement_timestamp()),
        last_interacted_at = statement_timestamp()
    where ranking_id = p_ranking_id
      and user_id = p_user_id
      and fhfh_player_id = p_player_id;

    v_current_version := v_current_version + 1;
    update public.draft_rankings
    set lock_version = v_current_version
    where id = p_ranking_id;

    select ranked.visible_rank
    into v_destination_rank
    from (
        select
            entry.fhfh_player_id,
            row_number() over (
                order by entry.order_key, entry.fhfh_player_id
            )::integer as visible_rank
        from public.draft_ranking_entries entry
        where entry.ranking_id = p_ranking_id
    ) ranked
    where ranked.fhfh_player_id = p_player_id;

    select
        max(entry.fhfh_player_id) filter (where entry.visible_rank = 250),
        max(entry.fhfh_player_id) filter (where entry.visible_rank = 251)
    into v_after_250, v_after_251
    from (
        select
            placed.fhfh_player_id,
            row_number() over (
                order by placed.order_key, placed.fhfh_player_id
            )::integer as visible_rank
        from public.draft_ranking_entries placed
        where placed.ranking_id = p_ranking_id
    ) entry;

    select count(*) into v_conflict_count
    from public.draft_ranker_pair_preferences preference
    join public.draft_ranking_entries low_entry
      on low_entry.ranking_id = preference.ranking_id
     and low_entry.fhfh_player_id = preference.low_player_id
    join public.draft_ranking_entries high_entry
      on high_entry.ranking_id = preference.ranking_id
     and high_entry.fhfh_player_id = preference.high_player_id
    where preference.ranking_id = p_ranking_id
      and preference.user_id = p_user_id
      and p_player_id in (preference.low_player_id, preference.high_player_id)
      and (
          (preference.preferred_player_id = preference.low_player_id
           and low_entry.order_key > high_entry.order_key)
          or
          (preference.preferred_player_id = preference.high_player_id
           and high_entry.order_key > low_entry.order_key)
      );

    v_result := jsonb_build_object(
        'status', 'completed',
        'rankingId', p_ranking_id,
        'playerId', p_player_id,
        'action', p_action,
        'previousRank', v_current_rank,
        'resultingRank', v_destination_rank,
        'previousOrderKey', v_old_key,
        'resultingOrderKey', v_new_key,
        'expectedVersion', p_expected_version,
        'resultingVersion', v_current_version,
        'normalized', v_normalized,
        'comparisonConflictCount', v_conflict_count,
        'beforeCutoff', jsonb_build_object(
            'rank250PlayerId', v_before_250,
            'rank251PlayerId', v_before_251
        ),
        'afterCutoff', jsonb_build_object(
            'rank250PlayerId', v_after_250,
            'rank251PlayerId', v_after_251
        ),
        'idempotentReplay', false
    );

    insert into public.draft_ranking_events (
        ranking_id, user_id, fhfh_player_id, event_type, event_source,
        operation_id, expected_version, resulting_version,
        before_state, after_state, metadata
    ) values (
        p_ranking_id, p_user_id, p_player_id, 'player_reordered', 'direct_edit',
        p_operation_id, p_expected_version, v_current_version,
        jsonb_build_object(
            'rank', v_current_rank,
            'orderKey', v_old_key,
            'rank250PlayerId', v_before_250,
            'rank251PlayerId', v_before_251
        ),
        jsonb_build_object(
            'rank', v_destination_rank,
            'orderKey', v_new_key,
            'rank250PlayerId', v_after_250,
            'rank251PlayerId', v_after_251
        ),
        jsonb_build_object(
            'operation_payload_hash', p_operation_payload_hash,
            'normalized', v_normalized,
            'comparisonConflictCount', v_conflict_count,
            'result', v_result
        )
    );

    return v_result;
end;
$_$;


--
-- Name: repair_draft_ranking_ordering(uuid, bigint, uuid, text, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.repair_draft_ranking_ordering(p_ranking_id uuid, p_expected_version bigint, p_operation_id uuid, p_operation_payload_hash text, p_reason text, p_confirmation text) RETURNS jsonb
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public'
    AS $_$
declare
    v_user_id uuid;
    v_current_version bigint;
    v_existing_hash text;
    v_existing_version bigint;
    v_entry_count integer := 0;
    v_mismatch_count integer := 0;
    v_before_min bigint;
    v_before_max bigint;
    v_after_min bigint;
    v_after_max bigint;
    v_resulting_version bigint;
    v_result jsonb;
begin
    if p_ranking_id is null or p_operation_id is null then
        raise exception using errcode = '22023', message = 'ranking and operation IDs are required';
    end if;
    if p_expected_version is null or p_expected_version < 0 then
        raise exception using errcode = '22023', message = 'expected version must be nonnegative';
    end if;
    if p_operation_payload_hash is null
       or p_operation_payload_hash !~ '^[0-9a-f]{64}$' then
        raise exception using errcode = '22023', message = 'operation payload hash must be lowercase SHA-256';
    end if;
    if nullif(btrim(p_reason), '') is null or char_length(p_reason) > 500 then
        raise exception using errcode = '22023', message = 'a bounded repair reason is required';
    end if;
    if p_confirmation <> 'NORMALIZE_ORDERING' then
        return jsonb_build_object(
            'status', 'failed',
            'code', 'confirmation_required',
            'message', 'Exact normalization confirmation is required.'
        );
    end if;

    perform pg_advisory_xact_lock(
        hashtextextended('draft-ranking-repair:' || p_ranking_id::text, 0)
    );

    select ranking.user_id, ranking.lock_version
    into v_user_id, v_current_version
    from public.draft_rankings ranking
    where ranking.id = p_ranking_id
    for update;

    if not found then
        return jsonb_build_object(
            'status', 'not_found',
            'code', 'ranking_not_found',
            'message', 'The ranking was not found.'
        );
    end if;

    select
        event.metadata->>'operationPayloadHash',
        event.resulting_version
    into v_existing_hash, v_existing_version
    from public.draft_ranking_events event
    where event.ranking_id = p_ranking_id
      and event.operation_id = p_operation_id;

    if found then
        if v_existing_hash <> p_operation_payload_hash then
            return jsonb_build_object(
                'status', 'conflict',
                'code', 'idempotency_conflict',
                'message', 'The operation ID was already used with a different repair payload.'
            );
        end if;
        return jsonb_build_object(
            'status', 'completed',
            'rankingId', p_ranking_id,
            'resultingVersion', v_existing_version,
            'idempotentReplay', true
        );
    end if;

    if v_current_version <> p_expected_version then
        return jsonb_build_object(
            'status', 'conflict',
            'code', 'stale_ranking_version',
            'message', 'The ranking changed before the repair could run.',
            'expectedVersion', p_expected_version,
            'currentVersion', v_current_version
        );
    end if;

    with ordered as (
        select
            entry.order_key,
            row_number() over (
                order by entry.order_key, entry.fhfh_player_id
            )::bigint * 1024 as normalized_key
        from public.draft_ranking_entries entry
        where entry.ranking_id = p_ranking_id
    )
    select
        count(*)::integer,
        count(*) filter (where order_key <> normalized_key)::integer,
        min(order_key),
        max(order_key)
    into v_entry_count, v_mismatch_count, v_before_min, v_before_max
    from ordered;

    if v_mismatch_count > 0 then
        with ordered as (
            select
                entry.fhfh_player_id,
                row_number() over (
                    order by entry.order_key, entry.fhfh_player_id
                )::bigint * 1024 as normalized_key
            from public.draft_ranking_entries entry
            where entry.ranking_id = p_ranking_id
        )
        update public.draft_ranking_entries entry
        set order_key = ordered.normalized_key,
            updated_at = statement_timestamp()
        from ordered
        where entry.ranking_id = p_ranking_id
          and entry.fhfh_player_id = ordered.fhfh_player_id;

        v_resulting_version := v_current_version + 1;
        update public.draft_rankings
        set lock_version = v_resulting_version,
            updated_at = statement_timestamp()
        where id = p_ranking_id;
        v_after_min := case when v_entry_count > 0 then 1024 else null end;
        v_after_max := case when v_entry_count > 0 then v_entry_count::bigint * 1024 else null end;
    else
        v_resulting_version := v_current_version;
        v_after_min := v_before_min;
        v_after_max := v_before_max;
    end if;

    v_result := jsonb_build_object(
        'status', 'completed',
        'rankingId', p_ranking_id,
        'entryCount', v_entry_count,
        'changedEntryCount', v_mismatch_count,
        'previousVersion', v_current_version,
        'resultingVersion', v_resulting_version,
        'idempotentReplay', false
    );

    insert into public.draft_ranking_events (
        ranking_id, user_id, fhfh_player_id, event_type, event_source,
        operation_id, expected_version, resulting_version,
        before_state, after_state, metadata
    ) values (
        p_ranking_id,
        v_user_id,
        null,
        case when v_mismatch_count > 0 then 'normalize_ordering' else 'normalize_ordering_noop' end,
        'admin_repair',
        p_operation_id,
        case when v_mismatch_count > 0 then v_current_version else null end,
        v_resulting_version,
        jsonb_build_object(
            'entryCount', v_entry_count,
            'minimumOrderKey', v_before_min,
            'maximumOrderKey', v_before_max
        ),
        jsonb_build_object(
            'entryCount', v_entry_count,
            'minimumOrderKey', v_after_min,
            'maximumOrderKey', v_after_max
        ),
        jsonb_build_object(
            'operationPayloadHash', p_operation_payload_hash,
            'reason', btrim(p_reason),
            'changedEntryCount', v_mismatch_count,
            'result', v_result
        )
    );

    return v_result;
end;
$_$;


--
-- Name: FUNCTION repair_draft_ranking_ordering(p_ranking_id uuid, p_expected_version bigint, p_operation_id uuid, p_operation_payload_hash text, p_reason text, p_confirmation text); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.repair_draft_ranking_ordering(p_ranking_id uuid, p_expected_version bigint, p_operation_id uuid, p_operation_payload_hash text, p_reason text, p_confirmation text) IS 'DR-071 service-only deterministic sparse-order normalization with immutable audit evidence.';


--
-- Name: replace_draft_ranker_community_snapshot(bigint, timestamp with time zone, text, text, uuid, text, text, uuid, jsonb, jsonb, integer, integer, integer, jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.replace_draft_ranker_community_snapshot(p_target_season_id bigint, p_snapshot_as_of timestamp with time zone, p_cadence text, p_model_version text, p_operation_id uuid, p_operation_payload_hash text, p_source_fingerprint text, p_requested_by uuid, p_source_summary jsonb, p_exclusion_summary jsonb, p_accepted_comparison_count integer, p_excluded_comparison_count integer, p_deduplicated_comparison_count integer, p_results jsonb) RETURNS jsonb
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public'
    AS $_$
declare
    v_run_id uuid;
    v_snapshot_id uuid;
    v_previous_snapshot_id uuid;
    v_existing_hash text;
    v_existing_snapshot_id uuid;
    v_player_count integer;
    v_public_display_count integer;
    v_public_top250_count integer;
begin
    if p_target_season_id is null or p_snapshot_as_of is null
       or p_operation_id is null then
        raise exception using errcode = '22023',
            message = 'target season, snapshot time, and operation ID are required';
    end if;
    if p_cadence not in ('daily', 'weekly', 'manual') then
        raise exception using errcode = '22023', message = 'unsupported snapshot cadence';
    end if;
    if nullif(btrim(p_model_version), '') is null
       or char_length(p_model_version) > 80 then
        raise exception using errcode = '22023', message = 'model version is required';
    end if;
    if p_operation_payload_hash is null
       or p_operation_payload_hash !~ '^[0-9a-f]{64}$'
       or p_source_fingerprint is null
       or p_source_fingerprint !~ '^[0-9a-f]{64}$' then
        raise exception using errcode = '22023',
            message = 'payload and source hashes must be lowercase SHA-256';
    end if;
    if jsonb_typeof(coalesce(p_source_summary, '{}'::jsonb)) <> 'object'
       or jsonb_typeof(coalesce(p_exclusion_summary, '{}'::jsonb)) <> 'object'
       or jsonb_typeof(coalesce(p_results, '[]'::jsonb)) <> 'array' then
        raise exception using errcode = '22023', message = 'community snapshot JSON has an invalid shape';
    end if;
    if jsonb_array_length(coalesce(p_results, '[]'::jsonb)) > 10000 then
        raise exception using errcode = '22023', message = 'community snapshot exceeds supported bounds';
    end if;
    if p_accepted_comparison_count < 0 or p_excluded_comparison_count < 0
       or p_deduplicated_comparison_count < 0 then
        raise exception using errcode = '22023', message = 'community evidence counts must be nonnegative';
    end if;

    perform pg_advisory_xact_lock(
        hashtextextended('draft-ranker-community:' || p_target_season_id::text, 0)
    );

    select run.id, run.operation_payload_hash, snapshot.id
    into v_run_id, v_existing_hash, v_existing_snapshot_id
    from public.draft_ranker_community_refresh_runs run
    join public.draft_ranker_community_snapshots snapshot on snapshot.run_id = run.id
    where run.operation_id = p_operation_id;

    if found then
        if v_existing_hash <> p_operation_payload_hash then
            return jsonb_build_object(
                'status', 'conflict',
                'code', 'idempotency_conflict',
                'message', 'The operation ID was already used with a different community payload.'
            );
        end if;
        select snapshot.player_count, snapshot.public_display_count,
               snapshot.public_top250_count
        into v_player_count, v_public_display_count, v_public_top250_count
        from public.draft_ranker_community_snapshots snapshot
        where snapshot.id = v_existing_snapshot_id;
        return jsonb_build_object(
            'status', 'completed',
            'runId', v_run_id,
            'snapshotId', v_existing_snapshot_id,
            'playerCount', v_player_count,
            'publicDisplayCount', v_public_display_count,
            'publicTop250Count', v_public_top250_count,
            'idempotentReplay', true,
            'sourceReplay', false
        );
    end if;

    select snapshot.run_id, snapshot.id, snapshot.player_count,
           snapshot.public_display_count, snapshot.public_top250_count
    into v_run_id, v_existing_snapshot_id, v_player_count,
         v_public_display_count, v_public_top250_count
    from public.draft_ranker_community_snapshots snapshot
    where snapshot.target_season_id = p_target_season_id
      and snapshot.snapshot_as_of = p_snapshot_as_of
      and snapshot.model_version = p_model_version
      and snapshot.source_fingerprint = p_source_fingerprint;

    if found then
        return jsonb_build_object(
            'status', 'completed',
            'runId', v_run_id,
            'snapshotId', v_existing_snapshot_id,
            'playerCount', v_player_count,
            'publicDisplayCount', v_public_display_count,
            'publicTop250Count', v_public_top250_count,
            'idempotentReplay', false,
            'sourceReplay', true
        );
    end if;

    select snapshot.id into v_previous_snapshot_id
    from public.draft_ranker_community_snapshots snapshot
    where snapshot.target_season_id = p_target_season_id
    order by snapshot.published_at desc, snapshot.id desc
    limit 1;

    insert into public.draft_ranker_community_refresh_runs (
        target_season_id, operation_id, operation_payload_hash,
        source_fingerprint, model_version, requested_by,
        source_summary, exclusion_summary,
        accepted_comparison_count, excluded_comparison_count,
        deduplicated_comparison_count, status, completed_at
    ) values (
        p_target_season_id, p_operation_id, p_operation_payload_hash,
        p_source_fingerprint, btrim(p_model_version), p_requested_by,
        coalesce(p_source_summary, '{}'::jsonb),
        coalesce(p_exclusion_summary, '{}'::jsonb),
        p_accepted_comparison_count, p_excluded_comparison_count,
        p_deduplicated_comparison_count, 'completed', statement_timestamp()
    ) returning id into v_run_id;

    v_player_count := jsonb_array_length(coalesce(p_results, '[]'::jsonb));
    select count(*) filter (where coalesce((result->>'public_display_eligible')::boolean, false)),
           count(*) filter (where result->>'public_rank' is not null)
    into v_public_display_count, v_public_top250_count
    from jsonb_array_elements(coalesce(p_results, '[]'::jsonb)) result;

    insert into public.draft_ranker_community_snapshots (
        run_id, target_season_id, previous_snapshot_id, snapshot_as_of,
        cadence, model_version, source_fingerprint, player_count,
        public_display_count, public_top250_count, metadata
    ) values (
        v_run_id, p_target_season_id, v_previous_snapshot_id, p_snapshot_as_of,
        p_cadence, btrim(p_model_version), p_source_fingerprint, v_player_count,
        v_public_display_count, v_public_top250_count,
        jsonb_build_object(
            'acceptedComparisonCount', p_accepted_comparison_count,
            'excludedComparisonCount', p_excluded_comparison_count,
            'deduplicatedComparisonCount', p_deduplicated_comparison_count
        )
    ) returning id into v_snapshot_id;

    insert into public.draft_ranker_community_player_results (
        snapshot_id, target_season_id, fhfh_player_id,
        model_rank, public_rank, model_score, market_rank, prior_state,
        market_prior_weight, evidence_state, confidence_label,
        independent_users, comparison_count, distinct_opponents,
        cutoff_opponents_inside, cutoff_opponents_outside,
        stability_buffer_ranks, conservative_rank,
        public_display_eligible, public_top250_eligible, admission_basis,
        previous_public_rank, rank_delta, last_evidence_at, metadata
    )
    select
        v_snapshot_id, p_target_season_id, result.fhfh_player_id,
        result.model_rank, result.public_rank, result.model_score,
        result.market_rank, result.prior_state, result.market_prior_weight,
        result.evidence_state, result.confidence_label,
        result.independent_users, result.comparison_count,
        result.distinct_opponents, result.cutoff_opponents_inside,
        result.cutoff_opponents_outside, result.stability_buffer_ranks,
        result.conservative_rank, result.public_display_eligible,
        result.public_top250_eligible, result.admission_basis,
        result.previous_public_rank, result.rank_delta,
        result.last_evidence_at, coalesce(result.metadata, '{}'::jsonb)
    from jsonb_to_recordset(coalesce(p_results, '[]'::jsonb)) as result(
        fhfh_player_id bigint,
        model_rank integer,
        public_rank integer,
        model_score numeric,
        market_rank numeric,
        prior_state text,
        market_prior_weight numeric,
        evidence_state text,
        confidence_label text,
        independent_users integer,
        comparison_count integer,
        distinct_opponents integer,
        cutoff_opponents_inside integer,
        cutoff_opponents_outside integer,
        stability_buffer_ranks integer,
        conservative_rank integer,
        public_display_eligible boolean,
        public_top250_eligible boolean,
        admission_basis text,
        previous_public_rank integer,
        rank_delta integer,
        last_evidence_at timestamptz,
        metadata jsonb
    );

    return jsonb_build_object(
        'status', 'completed',
        'runId', v_run_id,
        'snapshotId', v_snapshot_id,
        'previousSnapshotId', v_previous_snapshot_id,
        'playerCount', v_player_count,
        'publicDisplayCount', v_public_display_count,
        'publicTop250Count', v_public_top250_count,
        'idempotentReplay', false,
        'sourceReplay', false
    );
end;
$_$;


--
-- Name: FUNCTION replace_draft_ranker_community_snapshot(p_target_season_id bigint, p_snapshot_as_of timestamp with time zone, p_cadence text, p_model_version text, p_operation_id uuid, p_operation_payload_hash text, p_source_fingerprint text, p_requested_by uuid, p_source_summary jsonb, p_exclusion_summary jsonb, p_accepted_comparison_count integer, p_excluded_comparison_count integer, p_deduplicated_comparison_count integer, p_results jsonb); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.replace_draft_ranker_community_snapshot(p_target_season_id bigint, p_snapshot_as_of timestamp with time zone, p_cadence text, p_model_version text, p_operation_id uuid, p_operation_payload_hash text, p_source_fingerprint text, p_requested_by uuid, p_source_summary jsonb, p_exclusion_summary jsonb, p_accepted_comparison_count integer, p_excluded_comparison_count integer, p_deduplicated_comparison_count integer, p_results jsonb) IS 'Atomically publishes an idempotent versioned Community Ranking snapshot under a per-season advisory lock.';


--
-- Name: replace_draft_ranker_discovery_snapshot(bigint, uuid, text, text, text, uuid, jsonb, jsonb, jsonb, jsonb, jsonb, jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.replace_draft_ranker_discovery_snapshot(p_target_season_id bigint, p_operation_id uuid, p_operation_payload_hash text, p_source_fingerprint text, p_algorithm_version text, p_requested_by uuid, p_source_summary jsonb, p_group_counts jsonb, p_warning_codes jsonb, p_source_health jsonb, p_projection_consensus jsonb, p_signals jsonb) RETURNS jsonb
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public'
    AS $_$
declare
    v_run_id uuid;
    v_existing_payload_hash text;
    v_existing_status text;
    v_existing_group_counts jsonb;
    v_health_count integer;
    v_consensus_count integer;
    v_signal_count integer;
begin
    if p_target_season_id is null or p_operation_id is null then
        raise exception using errcode = '22023', message = 'target season and operation ID are required';
    end if;
    if p_operation_payload_hash is null
       or p_operation_payload_hash !~ '^[0-9a-f]{64}$'
       or p_source_fingerprint is null
       or p_source_fingerprint !~ '^[0-9a-f]{64}$' then
        raise exception using errcode = '22023', message = 'payload and source hashes must be lowercase SHA-256';
    end if;
    if nullif(btrim(p_algorithm_version), '') is null
       or char_length(p_algorithm_version) > 80 then
        raise exception using errcode = '22023', message = 'algorithm version is required';
    end if;
    if jsonb_typeof(coalesce(p_source_summary, '{}'::jsonb)) <> 'object'
       or jsonb_typeof(coalesce(p_group_counts, '{}'::jsonb)) <> 'object'
       or jsonb_typeof(coalesce(p_warning_codes, '[]'::jsonb)) <> 'array'
       or jsonb_typeof(coalesce(p_source_health, '[]'::jsonb)) <> 'array'
       or jsonb_typeof(coalesce(p_projection_consensus, '[]'::jsonb)) <> 'array'
       or jsonb_typeof(coalesce(p_signals, '[]'::jsonb)) <> 'array' then
        raise exception using errcode = '22023', message = 'discovery snapshot JSON has an invalid shape';
    end if;
    if jsonb_array_length(coalesce(p_source_health, '[]'::jsonb)) > 100
       or jsonb_array_length(coalesce(p_projection_consensus, '[]'::jsonb)) > 5000
       or jsonb_array_length(coalesce(p_signals, '[]'::jsonb)) > 10000 then
        raise exception using errcode = '22023', message = 'discovery snapshot exceeds supported bounds';
    end if;

    perform pg_advisory_xact_lock(
        hashtextextended('draft-ranker-discovery:' || p_target_season_id::text, 0)
    );

    select run.id, run.operation_payload_hash, run.status, run.group_counts
    into v_run_id, v_existing_payload_hash, v_existing_status, v_existing_group_counts
    from public.draft_ranker_discovery_refresh_runs run
    where run.operation_id = p_operation_id;

    if found then
        if v_existing_payload_hash <> p_operation_payload_hash then
            return jsonb_build_object(
                'status', 'conflict',
                'code', 'idempotency_conflict',
                'message', 'The operation ID was already used with a different discovery payload.'
            );
        end if;

        select count(*) into v_health_count
        from public.draft_ranker_discovery_source_health health
        where health.run_id = v_run_id;
        select count(*) into v_signal_count
        from public.draft_ranker_discovery_signals signal
        where signal.run_id = v_run_id;
        select count(*) into v_consensus_count
        from public.draft_ranker_discovery_projection_consensus consensus
        where consensus.run_id = v_run_id;

        return jsonb_build_object(
            'status', v_existing_status,
            'runId', v_run_id,
            'sourceHealthCount', v_health_count,
            'projectionConsensusCount', v_consensus_count,
            'signalCount', v_signal_count,
            'groupCounts', v_existing_group_counts,
            'idempotentReplay', true
        );
    end if;

    insert into public.draft_ranker_discovery_refresh_runs (
        target_season_id,
        operation_id,
        operation_payload_hash,
        source_fingerprint,
        algorithm_version,
        requested_by,
        source_summary,
        group_counts,
        warning_codes,
        status
    ) values (
        p_target_season_id,
        p_operation_id,
        p_operation_payload_hash,
        p_source_fingerprint,
        p_algorithm_version,
        p_requested_by,
        coalesce(p_source_summary, '{}'::jsonb),
        coalesce(p_group_counts, '{}'::jsonb),
        coalesce(p_warning_codes, '[]'::jsonb),
        'pending'
    ) returning id into v_run_id;

    insert into public.draft_ranker_discovery_source_health (
        run_id,
        source_key,
        health_state,
        source_season_id,
        source_date,
        source_observed_at,
        expires_at,
        row_count,
        mapped_player_count,
        eligible_player_count,
        warning_codes,
        metadata
    )
    select
        v_run_id,
        source.source_key,
        source.health_state,
        source.source_season_id,
        source.source_date,
        source.source_observed_at,
        source.expires_at,
        coalesce(source.row_count, 0),
        coalesce(source.mapped_player_count, 0),
        coalesce(source.eligible_player_count, 0),
        coalesce(source.warning_codes, '[]'::jsonb),
        coalesce(source.metadata, '{}'::jsonb)
    from jsonb_to_recordset(coalesce(p_source_health, '[]'::jsonb)) as source(
        source_key text,
        health_state text,
        source_season_id bigint,
        source_date date,
        source_observed_at timestamptz,
        expires_at timestamptz,
        row_count integer,
        mapped_player_count integer,
        eligible_player_count integer,
        warning_codes jsonb,
        metadata jsonb
    );
    get diagnostics v_health_count = row_count;

    insert into public.draft_ranker_discovery_projection_consensus (
        run_id,
        target_season_id,
        fhfh_player_id,
        consensus_rank,
        source_count,
        source_keys,
        source_observed_at,
        expires_at,
        evidence
    )
    select
        v_run_id,
        p_target_season_id,
        consensus.fhfh_player_id,
        consensus.consensus_rank,
        consensus.source_count,
        array(
            select jsonb_array_elements_text(consensus.source_keys)
        ),
        consensus.source_observed_at,
        consensus.expires_at,
        coalesce(consensus.evidence, '{}'::jsonb)
    from jsonb_to_recordset(coalesce(p_projection_consensus, '[]'::jsonb)) as consensus(
        fhfh_player_id bigint,
        consensus_rank numeric,
        source_count integer,
        source_keys jsonb,
        source_observed_at timestamptz,
        expires_at timestamptz,
        evidence jsonb
    );
    get diagnostics v_consensus_count = row_count;

    insert into public.draft_ranker_discovery_signals (
        run_id,
        target_season_id,
        fhfh_player_id,
        signal_type,
        score,
        reason_code,
        reason_text,
        source_keys,
        source_date,
        source_observed_at,
        expires_at,
        algorithm_version,
        evidence
    )
    select
        v_run_id,
        p_target_season_id,
        signal.fhfh_player_id,
        signal.signal_type,
        signal.score,
        signal.reason_code,
        signal.reason_text,
        array(
            select jsonb_array_elements_text(signal.source_keys)
        ),
        signal.source_date,
        signal.source_observed_at,
        signal.expires_at,
        p_algorithm_version,
        coalesce(signal.evidence, '{}'::jsonb)
    from jsonb_to_recordset(coalesce(p_signals, '[]'::jsonb)) as signal(
        fhfh_player_id bigint,
        signal_type text,
        score numeric,
        reason_code text,
        reason_text text,
        source_keys jsonb,
        source_date date,
        source_observed_at timestamptz,
        expires_at timestamptz,
        evidence jsonb
    );
    get diagnostics v_signal_count = row_count;

    update public.draft_ranker_discovery_refresh_runs
    set status = 'completed', completed_at = statement_timestamp()
    where id = v_run_id;

    return jsonb_build_object(
        'status', 'completed',
        'runId', v_run_id,
        'sourceHealthCount', v_health_count,
        'projectionConsensusCount', v_consensus_count,
        'signalCount', v_signal_count,
        'groupCounts', coalesce(p_group_counts, '{}'::jsonb),
        'idempotentReplay', false
    );
end;
$_$;


--
-- Name: FUNCTION replace_draft_ranker_discovery_snapshot(p_target_season_id bigint, p_operation_id uuid, p_operation_payload_hash text, p_source_fingerprint text, p_algorithm_version text, p_requested_by uuid, p_source_summary jsonb, p_group_counts jsonb, p_warning_codes jsonb, p_source_health jsonb, p_projection_consensus jsonb, p_signals jsonb); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.replace_draft_ranker_discovery_snapshot(p_target_season_id bigint, p_operation_id uuid, p_operation_payload_hash text, p_source_fingerprint text, p_algorithm_version text, p_requested_by uuid, p_source_summary jsonb, p_group_counts jsonb, p_warning_codes jsonb, p_source_health jsonb, p_projection_consensus jsonb, p_signals jsonb) IS 'Atomically persists one idempotent completed discovery snapshot from service-validated source evidence.';


--
-- Name: request_fhfh_player_addition(uuid, text, jsonb, bigint[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.request_fhfh_player_addition(p_user_id uuid, p_raw_name text, p_submitted_context jsonb DEFAULT '{}'::jsonb, p_candidate_fhfh_player_ids bigint[] DEFAULT '{}'::bigint[]) RETURNS jsonb
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog'
    AS $$
declare
    v_normalized_name text;
    v_dedupe_key text;
    v_existing public.fhfh_player_identity_review_queue%rowtype;
    v_recent_count integer;
    v_retry_after_seconds integer;
    v_request public.fhfh_player_identity_review_queue%rowtype;
begin
    if p_user_id is null then
        return jsonb_build_object(
            'status', 'failed',
            'code', 'invalid_user',
            'message', 'An authenticated account is required.'
        );
    end if;

    if p_raw_name is null or length(btrim(p_raw_name)) not between 2 and 120 then
        return jsonb_build_object(
            'status', 'failed',
            'code', 'invalid_name',
            'message', 'Player name must be between 2 and 120 characters.'
        );
    end if;

    if p_submitted_context is null
       or jsonb_typeof(p_submitted_context) <> 'object'
       or octet_length(p_submitted_context::text) > 8192 then
        return jsonb_build_object(
            'status', 'failed',
            'code', 'invalid_context',
            'message', 'Request context must be an object no larger than 8 KB.'
        );
    end if;

    if coalesce(cardinality(p_candidate_fhfh_player_ids), 0) > 10 then
        return jsonb_build_object(
            'status', 'failed',
            'code', 'too_many_candidates',
            'message', 'No more than 10 candidate identities may be supplied.'
        );
    end if;

    if exists (
        select 1
        from unnest(coalesce(p_candidate_fhfh_player_ids, '{}'::bigint[])) id
        where not exists (
            select 1
            from public.fhfh_player_identities identity
            where identity.id = id
        )
    ) then
        return jsonb_build_object(
            'status', 'failed',
            'code', 'invalid_candidate',
            'message', 'One or more candidate identities do not exist.'
        );
    end if;

    v_normalized_name := regexp_replace(
        public.immutable_unaccent(lower(btrim(p_raw_name))),
        '[^[:alnum:]]+',
        ' ',
        'g'
    );
    v_normalized_name := regexp_replace(btrim(v_normalized_name), '\s+', ' ', 'g');
    v_dedupe_key := 'player_addition:' || p_user_id::text || ':' || md5(v_normalized_name);

    perform pg_advisory_xact_lock(
        hashtextextended('fhfh-player-addition:' || p_user_id::text, 0)
    );

    select review.*
    into v_existing
    from public.fhfh_player_identity_review_queue review
    where review.dedupe_key = v_dedupe_key
      and review.status in ('pending', 'in_review')
    order by review.created_at desc
    limit 1;

    if found then
        return jsonb_build_object(
            'status', 'duplicate',
            'requestId', v_existing.id,
            'requestStatus', v_existing.status,
            'created', false
        );
    end if;

    select count(*)::integer
    into v_recent_count
    from public.fhfh_player_identity_review_queue review
    where review.requested_by = p_user_id
      and review.review_type = 'player_addition'
      and review.created_at >= statement_timestamp() - interval '24 hours';

    if v_recent_count >= 5 then
        select greatest(
            1,
            ceil(extract(epoch from (
                min(review.created_at) + interval '24 hours'
                - statement_timestamp()
            )))::integer
        )
        into v_retry_after_seconds
        from public.fhfh_player_identity_review_queue review
        where review.requested_by = p_user_id
          and review.review_type = 'player_addition'
          and review.created_at >= statement_timestamp() - interval '24 hours';

        return jsonb_build_object(
            'status', 'rate_limited',
            'code', 'player_addition_rate_limit',
            'message', 'You can submit up to five player requests per day.',
            'retryAfterSeconds', coalesce(v_retry_after_seconds, 86400)
        );
    end if;

    insert into public.fhfh_player_identity_review_queue (
        review_type,
        requested_by,
        raw_name,
        submitted_context,
        candidate_fhfh_player_ids,
        source_evidence,
        dedupe_key,
        status
    ) values (
        'player_addition',
        p_user_id,
        btrim(p_raw_name),
        p_submitted_context,
        coalesce(p_candidate_fhfh_player_ids, '{}'::bigint[]),
        jsonb_build_object(
            'source', 'draft_ranker_search',
            'submittedAt', statement_timestamp()
        ),
        v_dedupe_key,
        'pending'
    )
    returning * into v_request;

    return jsonb_build_object(
        'status', 'completed',
        'requestId', v_request.id,
        'requestStatus', v_request.status,
        'created', true
    );
end;
$$;


--
-- Name: FUNCTION request_fhfh_player_addition(p_user_id uuid, p_raw_name text, p_submitted_context jsonb, p_candidate_fhfh_player_ids bigint[]); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.request_fhfh_player_addition(p_user_id uuid, p_raw_name text, p_submitted_context jsonb, p_candidate_fhfh_player_ids bigint[]) IS 'Service-only, deduplicated and rate-limited player-addition request intake.';


--
-- Name: rpc_sko_player_series(bigint, integer, numeric, numeric, integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rpc_sko_player_series(p_player_id bigint, p_span integer DEFAULT 5, p_lambda_hot numeric DEFAULT 1.8, p_lambda_cold numeric DEFAULT 1.6, p_l_hot integer DEFAULT 2, p_l_cold integer DEFAULT 3) RETURNS jsonb
    LANGUAGE sql SECURITY DEFINER
    AS $$
  SELECT analytics.rpc_sko_player_series(
    p_player_id,
    p_span,
    p_lambda_hot,
    p_lambda_cold,
    p_L_hot,
    p_L_cold
  );
$$;


--
-- Name: safe_z(double precision, double precision, double precision); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.safe_z(val double precision, mu double precision, sigma double precision) RETURNS double precision
    LANGUAGE sql IMMUTABLE
    AS $$
  SELECT CASE WHEN val IS NULL OR sigma IS NULL OR sigma = 0 THEN NULL
              ELSE (val - mu) / sigma
         END;
$$;


--
-- Name: search_fhfh_draft_players(text, boolean, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.search_fhfh_draft_players(p_query text, p_include_archived boolean DEFAULT false, p_limit integer DEFAULT 20) RETURNS TABLE(player_id bigint, canonical_name text, birth_year smallint, canonical_position text, current_organization_name text, current_organization_type text, lifecycle_status text, headshot_url text, nhl_player_id bigint, yahoo_player_id text, external_providers text[], is_rankable boolean, match_kind text, similarity_score real)
    LANGUAGE sql STABLE
    SET search_path TO 'pg_catalog'
    AS $$
with input as (
    select
        public.immutable_unaccent(lower(btrim(p_query))) as normalized_query,
        least(greatest(coalesce(p_limit, 20), 1), 25) as result_limit
),
alias_matches as (
    select
        alias.fhfh_player_id,
        bool_or(
            public.immutable_unaccent(lower(alias.normalized_alias))
                = input.normalized_query
        ) as exact_match,
        bool_or(
            public.immutable_unaccent(lower(alias.normalized_alias))
                like input.normalized_query || '%'
        ) as prefix_match,
        max(
            public.similarity(
                public.immutable_unaccent(lower(alias.normalized_alias)),
                input.normalized_query
            )
        )::real as similarity_score
    from public.fhfh_player_identity_aliases alias
    cross join input
    where alias.verification_status = 'verified'
      and (
          public.immutable_unaccent(lower(alias.normalized_alias))
              = input.normalized_query
          or public.immutable_unaccent(lower(alias.normalized_alias))
              like input.normalized_query || '%'
          or public.similarity(
              public.immutable_unaccent(lower(alias.normalized_alias)),
              input.normalized_query
          ) >= 0.25
      )
    group by alias.fhfh_player_id
),
external_identity as (
    select
        external.fhfh_player_id,
        array_agg(distinct external.provider order by external.provider)
            filter (where external.verification_status = 'verified')
            as providers,
        max(external.external_player_id)
            filter (
                where external.provider = 'yahoo'
                  and external.verification_status = 'verified'
            ) as yahoo_player_id,
        bool_or(
            external.verification_status = 'verified'
            and lower(external.external_player_id) = input.normalized_query
        ) as external_id_match
    from public.fhfh_player_external_identities external
    cross join input
    group by external.fhfh_player_id
),
matched as (
    select
        identity.id as player_id,
        identity.canonical_name,
        extract(year from identity.birth_date)::smallint as birth_year,
        identity.canonical_position::text as canonical_position,
        identity.current_organization_name,
        identity.current_organization_type,
        identity.lifecycle_status,
        identity.headshot_url,
        identity.nhl_player_id,
        external.yahoo_player_id,
        coalesce(external.providers, '{}'::text[]) as external_providers,
        identity.lifecycle_status in (
            'active_nhl',
            'active_prospect',
            'unsigned_relevant'
        ) as is_rankable,
        public.immutable_unaccent(lower(identity.canonical_name))
            = input.normalized_query as canonical_exact,
        public.immutable_unaccent(lower(identity.canonical_name))
            like input.normalized_query || '%' as canonical_prefix,
        coalesce(alias_match.exact_match, false) as alias_exact,
        coalesce(alias_match.prefix_match, false) as alias_prefix,
        coalesce(external.external_id_match, false)
            or identity.nhl_player_id::text = input.normalized_query
            as external_id_exact,
        greatest(
            public.similarity(
                public.immutable_unaccent(lower(identity.canonical_name)),
                input.normalized_query
            ),
            coalesce(alias_match.similarity_score, 0)
        )::real as best_similarity,
        input.result_limit
    from public.fhfh_player_identities identity
    cross join input
    left join alias_matches alias_match
        on alias_match.fhfh_player_id = identity.id
    left join external_identity external
        on external.fhfh_player_id = identity.id
    where length(input.normalized_query) between 2 and 80
      and identity.verification_status = 'verified'
      and (
          identity.lifecycle_status in (
              'active_nhl',
              'active_prospect',
              'unsigned_relevant'
          )
          or (
              p_include_archived
              and identity.lifecycle_status in (
                  'inactive',
                  'retired',
                  'overseas',
                  'deceased'
              )
          )
      )
      and (
          public.immutable_unaccent(lower(identity.canonical_name))
              = input.normalized_query
          or public.immutable_unaccent(lower(identity.canonical_name))
              like input.normalized_query || '%'
          or public.similarity(
              public.immutable_unaccent(lower(identity.canonical_name)),
              input.normalized_query
          ) >= 0.25
          or alias_match.fhfh_player_id is not null
          or coalesce(external.external_id_match, false)
          or identity.nhl_player_id::text = input.normalized_query
      )
)
select
    matched.player_id,
    matched.canonical_name,
    matched.birth_year,
    matched.canonical_position,
    matched.current_organization_name,
    matched.current_organization_type,
    matched.lifecycle_status,
    matched.headshot_url,
    matched.nhl_player_id,
    matched.yahoo_player_id,
    matched.external_providers,
    matched.is_rankable,
    case
        when matched.external_id_exact then 'external_id_exact'
        when matched.canonical_exact then 'canonical_exact'
        when matched.alias_exact then 'alias_exact'
        when matched.canonical_prefix then 'canonical_prefix'
        when matched.alias_prefix then 'alias_prefix'
        else 'fuzzy'
    end as match_kind,
    matched.best_similarity as similarity_score
from matched
order by
    matched.external_id_exact desc,
    matched.canonical_exact desc,
    matched.alias_exact desc,
    matched.canonical_prefix desc,
    matched.alias_prefix desc,
    matched.is_rankable desc,
    (matched.lifecycle_status = 'active_nhl') desc,
    (matched.current_organization_type = 'nhl') desc,
    (matched.yahoo_player_id is not null) desc,
    matched.best_similarity desc,
    matched.canonical_name,
    matched.player_id
limit (select result_limit from input);
$$;


