CREATE FUNCTION public.upsert_connected_account_tokens_secure(p_connected_account_id uuid, p_user_id uuid, p_provider text, p_access_token text DEFAULT NULL::text, p_refresh_token text DEFAULT NULL::text, p_token_type text DEFAULT NULL::text, p_scopes jsonb DEFAULT NULL::jsonb, p_provider_user_id text DEFAULT NULL::text, p_expires_at timestamp with time zone DEFAULT NULL::timestamp with time zone, p_refresh_expires_at timestamp with time zone DEFAULT NULL::timestamp with time zone, p_last_refreshed_at timestamp with time zone DEFAULT NULL::timestamp with time zone, p_secret_metadata jsonb DEFAULT NULL::jsonb) RETURNS uuid
