--
-- Name: upsert_current_roster_membership(bigint, bigint, smallint, smallint); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.upsert_current_roster_membership(_playerid bigint, _seasonid bigint, _teamid smallint, _sweater_number smallint DEFAULT 0) RETURNS void
    LANGUAGE plpgsql
    AS $$
begin
  update public.rosters
  set
    is_current = false,
    ended_at = now()
  where "playerId" = _playerid
    and "seasonId" = _seasonid
    and is_current = true
    and "teamId" <> _teamid;

  insert into public.rosters (
    "playerId",
    "seasonId",
    "teamId",
    "sweaterNumber",
    is_current,
    ended_at
  )
  values (
    _playerid,
    _seasonid,
    _teamid,
    _sweater_number,
    true,
    null
  )
  on conflict ("playerId", "seasonId", "teamId")
  do update set
    "sweaterNumber" = excluded."sweaterNumber",
    is_current = true,
    ended_at = null;
end;
$$;


--
-- Name: upsert_players_batch(jsonb[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.upsert_players_batch(players_data jsonb[]) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    player_data JSONB; -- Loop variable for each player object in the array
    _player_key TEXT;
    _current_ownership_value NUMERIC;
    _today DATE;
    new_ownership_entry JSONB;
BEGIN
    -- Loop through each player object in the input array
    FOREACH player_data IN ARRAY players_data
    LOOP
        -- Extract required fields for the CURRENT player in the loop
        _player_key := player_data ->> 'player_key';
        _current_ownership_value := (player_data ->> 'current_ownership_value')::NUMERIC;
        _today := (player_data ->> 'current_date')::DATE;

        -- Create the new JSONB object to append for the CURRENT player
        new_ownership_entry := jsonb_build_object('date', to_char(_today, 'YYYY-MM-DD'), 'value', _current_ownership_value);

        -- Perform the UPSERT operation for the CURRENT player
        INSERT INTO public.yahoo_players (
            player_key, player_id, player_name, draft_analysis, average_draft_pick,
            average_draft_round, average_draft_cost, percent_drafted, editorial_player_key,
            editorial_team_abbreviation, editorial_team_full_name, eligible_positions,
            display_position, headshot_url, injury_note, full_name, percent_ownership, -- Keep if needed
            position_type, status, status_full, last_updated, uniform_number,
            ownership_timeline
        )
        VALUES (
            _player_key,
            player_data ->> 'player_id', player_data ->> 'player_name', (player_data ->> 'draft_analysis')::jsonb,
            (player_data ->> 'average_draft_pick')::double precision, (player_data ->> 'average_draft_round')::double precision,
            (player_data ->> 'average_draft_cost')::double precision, (player_data ->> 'percent_drafted')::double precision,
            player_data ->> 'editorial_player_key', player_data ->> 'editorial_team_abbreviation',
            player_data ->> 'editorial_team_full_name', (player_data ->> 'eligible_positions')::jsonb,
            player_data ->> 'display_position', player_data ->> 'headshot_url', player_data ->> 'injury_note',
            player_data ->> 'full_name', (player_data ->> 'percent_ownership')::double precision, -- Keep if needed
            player_data ->> 'position_type', player_data ->> 'status', player_data ->> 'status_full',
            (player_data ->> 'last_updated')::timestamp without time zone, (player_data ->> 'uniform_number')::smallint,
            jsonb_build_array(new_ownership_entry) -- Initial value for INSERT
        )
        ON CONFLICT (player_key) DO UPDATE SET
            player_id = EXCLUDED.player_id,
            player_name = EXCLUDED.player_name,
            draft_analysis = EXCLUDED.draft_analysis,
            average_draft_pick = EXCLUDED.average_draft_pick,
            average_draft_round = EXCLUDED.average_draft_round,
            average_draft_cost = EXCLUDED.average_draft_cost,
            percent_drafted = EXCLUDED.percent_drafted,
            editorial_player_key = EXCLUDED.editorial_player_key,
            editorial_team_abbreviation = EXCLUDED.editorial_team_abbreviation,
            editorial_team_full_name = EXCLUDED.editorial_team_full_name,
            eligible_positions = EXCLUDED.eligible_positions,
            display_position = EXCLUDED.display_position,
            headshot_url = EXCLUDED.headshot_url,
            injury_note = EXCLUDED.injury_note,
            full_name = EXCLUDED.full_name,
            percent_ownership = EXCLUDED.percent_ownership, -- Keep if needed
            position_type = EXCLUDED.position_type,
            status = EXCLUDED.status,
            status_full = EXCLUDED.status_full,
            last_updated = EXCLUDED.last_updated,
            uniform_number = EXCLUDED.uniform_number,
            -- Use the same append logic, it runs for each player row within the loop
            ownership_timeline = COALESCE(yahoo_players.ownership_timeline, '[]'::jsonb) || new_ownership_entry;

    END LOOP; -- End of loop for the current batch

END;
$$;


--
-- Name: upsert_players_batch(jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.upsert_players_batch(players_data jsonb) RETURNS jsonb
    LANGUAGE plpgsql
    AS $$
declare
  rec jsonb;
  processed int := 0;
  history int := 0;
begin
  if players_data is null then
    return jsonb_build_object('processed', 0, 'history_inserted', 0);
  end if;

  for rec in select * from jsonb_array_elements(players_data) loop
    processed := processed + 1;

    -- Upsert latest player snapshot into yahoo_players
    begin
      insert into public.yahoo_players (
        player_key, player_id, player_name, draft_analysis, average_draft_pick,
        average_draft_round, average_draft_cost, percent_drafted, editorial_player_key,
        editorial_team_abbreviation, editorial_team_full_name, eligible_positions,
        display_position, headshot_url, injury_note, full_name, percent_ownership,
        percent_owned_value, position_type, status, status_full, last_updated, uniform_number
      ) values (
        rec->>'player_key', rec->>'player_id', rec->>'player_name', rec->'draft_analysis',
        (rec->>'average_draft_pick')::numeric, (rec->>'average_draft_round')::numeric, (rec->>'average_draft_cost')::numeric,
        (rec->>'percent_drafted')::numeric, rec->>'editorial_player_key', rec->>'editorial_team_abbreviation', rec->>'editorial_team_full_name',
        (rec->'eligible_positions')::jsonb, rec->>'display_position', rec->>'headshot_url', rec->>'injury_note', rec->>'full_name',
        (rec->>'percent_ownership')::numeric, (rec->>'percent_owned_value')::numeric, rec->>'position_type', rec->>'status', rec->>'status_full', now(),
        (rec->>'uniform_number')::int
      ) on conflict (player_key) do update set
        player_id = excluded.player_id,
        player_name = excluded.player_name,
        draft_analysis = excluded.draft_analysis,
        average_draft_pick = excluded.average_draft_pick,
        average_draft_round = excluded.average_draft_round,
        average_draft_cost = excluded.average_draft_cost,
        percent_drafted = excluded.percent_drafted,
        editorial_player_key = excluded.editorial_player_key,
        editorial_team_abbreviation = excluded.editorial_team_abbreviation,
        editorial_team_full_name = excluded.editorial_team_full_name,
        eligible_positions = excluded.eligible_positions,
        display_position = excluded.display_position,
        headshot_url = excluded.headshot_url,
        injury_note = excluded.injury_note,
        full_name = excluded.full_name,
        percent_ownership = excluded.percent_ownership,
        percent_owned_value = excluded.percent_owned_value,
        position_type = excluded.position_type,
        status = excluded.status,
        status_full = excluded.status_full,
        last_updated = now(),
        uniform_number = excluded.uniform_number;
    exception when others then
      -- swallow individual errors to allow batch progress; log minimal info
      raise notice 'Upsert yahoo_players failed for player_key=%', rec->>'player_key';
    end;

    -- Append ownership history if ownership information present
    begin
      if rec ? 'percent_ownership' then
        insert into public.yahoo_player_ownership_history(
          player_key, captured_at, ownership_pct, percent_drafted, average_draft_pick,
          average_draft_round, average_draft_cost, raw, source
        ) values (
          rec->>'player_key', now(), (rec->>'percent_ownership')::numeric, (rec->>'percent_drafted')::numeric,
          (rec->>'average_draft_pick')::numeric, (rec->>'average_draft_round')::numeric, (rec->>'average_draft_cost')::numeric, rec, 'yahoo'
        );
        history := history + 1;
      end if;
    exception when others then
      raise notice 'Append ownership history failed for player_key=%', rec->>'player_key';
    end;

    -- Append draft analysis history if draft_analysis present
    begin
      if rec ? 'draft_analysis' then
        insert into public.yahoo_player_draft_analysis_history(
          player_key, captured_at, average_draft_pick, average_draft_round, average_draft_cost, percent_drafted, raw, source
        ) values (
          rec->>'player_key', now(), (rec->>'average_draft_pick')::numeric, (rec->>'average_draft_round')::numeric,
          (rec->>'average_draft_cost')::numeric, (rec->>'percent_drafted')::numeric, rec, 'yahoo'
        );
      end if;
    exception when others then
      raise notice 'Append draft history failed for player_key=%', rec->>'player_key';
    end;

  end loop;

  return jsonb_build_object('processed', processed, 'history_inserted', history);
end; $$;


--
-- Name: upsert_yahoo_players_v3(jsonb[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.upsert_yahoo_players_v3(players_data jsonb[]) RETURNS void
    LANGUAGE plpgsql
    AS $_$-- upsert_yahoo_players_v3(players_data jsonb[])
DECLARE
  p jsonb;
  new_owner_entry jsonb;
BEGIN
  FOREACH p IN ARRAY players_data LOOP

    -- Build the new JSONB entry once (if percent_ownership present)
    IF (p->>'percent_ownership') IS NOT NULL THEN
      new_owner_entry :=
        jsonb_build_object(
          'date',  p->>'current_date',
          'value', (p->>'percent_ownership')::numeric
        );
    ELSE
      new_owner_entry := NULL;
    END IF;

    INSERT INTO public.yahoo_players (
      player_key, player_id, player_name, draft_analysis, average_draft_pick, average_draft_round, average_draft_cost,
      percent_drafted, editorial_player_key, editorial_team_abbreviation, editorial_team_full_name, eligible_positions,
      display_position, headshot_url, injury_note, full_name, percent_ownership, game_id, season, position_type, status,
      status_full, last_updated, uniform_number, ownership_timeline
    )
    VALUES (
      p->>'player_key',
      (p->>'player_id')::integer,
      p->>'player_name',
      (p->'draft_analysis'),
      COALESCE(NULLIF((p->>'average_draft_pick'),'')::numeric,0),
      COALESCE(NULLIF((p->>'average_draft_round'),'')::numeric,0),
      COALESCE(NULLIF((p->>'average_draft_cost'),'')::numeric,0),
      COALESCE(NULLIF((p->>'percent_drafted'),'')::numeric,0),
      p->>'editorial_player_key',
      p->>'editorial_team_abbreviation',
      p->>'editorial_team_full_name',
      p->'eligible_positions',
      p->>'display_position',
      p->>'headshot_url',
      p->>'injury_note',
      p->>'full_name',
      COALESCE(NULLIF((p->>'percent_ownership'),'')::numeric,0),
      CASE WHEN (p->>'game_id')~'^[0-9]+$' THEN (p->>'game_id')::integer ELSE NULL END,
      CASE WHEN (p->>'season')~'^[0-9]+$' THEN (p->>'season')::integer ELSE NULL END,
      p->>'position_type',
      p->>'status',
      p->>'status_full',
      CASE WHEN (p->>'last_updated') IS NOT NULL THEN (p->>'last_updated')::timestamptz ELSE now() END,
      CASE WHEN (p->>'uniform_number')~'^[0-9]+$' THEN (p->>'uniform_number')::integer ELSE NULL END,

      /* ⬇️ Initial timeline value: payload array (if any) + new_owner_entry */
      COALESCE(p->'ownership_timeline','[]'::jsonb) ||
      COALESCE(
        CASE WHEN new_owner_entry IS NOT NULL
             THEN jsonb_build_array(new_owner_entry)
             ELSE '[]'::jsonb
        END,
        '[]'::jsonb
      )
    )
    ON CONFLICT (player_key) DO UPDATE SET
      player_id = EXCLUDED.player_id,
      player_name = COALESCE(EXCLUDED.player_name, yahoo_players.player_name),
      draft_analysis = COALESCE(EXCLUDED.draft_analysis, yahoo_players.draft_analysis),
      average_draft_pick = COALESCE(NULLIF(EXCLUDED.average_draft_pick,0), yahoo_players.average_draft_pick),
      average_draft_round = COALESCE(NULLIF(EXCLUDED.average_draft_round,0), yahoo_players.average_draft_round),
      average_draft_cost = COALESCE(NULLIF(EXCLUDED.average_draft_cost,0), yahoo_players.average_draft_cost),
      percent_drafted = COALESCE(NULLIF(EXCLUDED.percent_drafted,0), yahoo_players.percent_drafted),
      editorial_player_key = COALESCE(EXCLUDED.editorial_player_key, yahoo_players.editorial_player_key),
      editorial_team_abbreviation = COALESCE(EXCLUDED.editorial_team_abbreviation, yahoo_players.editorial_team_abbreviation),
      editorial_team_full_name = COALESCE(EXCLUDED.editorial_team_full_name, yahoo_players.editorial_team_full_name),
      eligible_positions = COALESCE(EXCLUDED.eligible_positions, yahoo_players.eligible_positions),
      display_position = COALESCE(EXCLUDED.display_position, yahoo_players.display_position),
      headshot_url = COALESCE(EXCLUDED.headshot_url, yahoo_players.headshot_url),
      injury_note = COALESCE(EXCLUDED.injury_note, yahoo_players.injury_note),
      full_name = COALESCE(EXCLUDED.full_name, yahoo_players.full_name),
      percent_ownership = COALESCE(NULLIF(EXCLUDED.percent_ownership,0), yahoo_players.percent_ownership),
      game_id = COALESCE(EXCLUDED.game_id, yahoo_players.game_id),
      season = COALESCE(EXCLUDED.season, yahoo_players.season),
      position_type = COALESCE(EXCLUDED.position_type, yahoo_players.position_type),
      status = COALESCE(EXCLUDED.status, yahoo_players.status),
      status_full = COALESCE(EXCLUDED.status_full, yahoo_players.status_full),
      last_updated = GREATEST(COALESCE(EXCLUDED.last_updated, now()), yahoo_players.last_updated),
      uniform_number = COALESCE(EXCLUDED.uniform_number, yahoo_players.uniform_number),

      /* ⬇️ Idempotent daily append:
            1) drop any existing object with the same date
            2) append the new entry (if we have one)
       */
      ownership_timeline = (
        COALESCE((
          SELECT jsonb_agg(elem)
          FROM jsonb_array_elements(COALESCE(yahoo_players.ownership_timeline,'[]'::jsonb)) AS t(elem)
          WHERE (p->>'current_date') IS NULL
             OR elem->>'date' IS DISTINCT FROM p->>'current_date'
        ), '[]'::jsonb)
        ||
        COALESCE(
          CASE WHEN new_owner_entry IS NOT NULL
               THEN jsonb_build_array(new_owner_entry)
               ELSE '[]'::jsonb
          END,
          '[]'::jsonb
        )
      );

    -- Keep your normalized per-day history (one row per day per player)
    IF (p->>'percent_ownership') IS NOT NULL THEN
      new_owner_entry := jsonb_build_object(
        'date', p->>'current_date',
        'percent_ownership', (p->>'percent_ownership')::numeric,
        'source', 'upsert_yahoo_players_v3'
      );
      BEGIN
        INSERT INTO public.yahoo_player_ownership_history (
          player_key, ownership_date, ownership_pct, source, inserted_at
        )
        VALUES (
          p->>'player_key',
          (p->>'current_date')::date,
          (p->>'percent_ownership')::numeric,
          'upsert_yahoo_players_v3',
          now()
        )
        ON CONFLICT (player_key, ownership_date) DO NOTHING;
      EXCEPTION WHEN others THEN
        NULL;
      END;
    END IF;

  END LOOP;
END;$_$;


--
-- Name: validate_draft_ranking_order(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.validate_draft_ranking_order(p_user_id uuid, p_ranking_id uuid) RETURNS jsonb
    LANGUAGE sql STABLE
    SET search_path TO 'pg_catalog', 'public'
    AS $$
    with owned as (
        select ranking.id, ranking.lock_version
        from public.draft_rankings ranking
        where ranking.id = p_ranking_id
          and ranking.user_id = p_user_id
    ),
    ordered as (
        select
            entry.order_key,
            lag(entry.order_key) over (
                order by entry.order_key, entry.fhfh_player_id
            ) as previous_key
        from public.draft_ranking_entries entry
        join owned on owned.id = entry.ranking_id
    )
    select case
        when not exists (select 1 from owned) then jsonb_build_object(
            'status', 'not_found',
            'code', 'not_found'
        )
        else jsonb_build_object(
            'status', 'completed',
            'rankingId', p_ranking_id,
            'lockVersion', (select lock_version from owned),
            'entryCount', (select count(*) from ordered),
            'minimumGap', (
                select min(order_key - previous_key)
                from ordered
                where previous_key is not null
            ),
            'isValid', not exists (
                select 1 from ordered
                where previous_key is not null
                  and order_key <= previous_key
            )
        )
    end;
$$;


