--
-- Name: admin__column_catalog; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.admin__column_catalog AS
 SELECT c.table_schema AS schema,
    c.table_name AS "table",
    c.column_name AS "column",
    lower((c.column_name)::text) AS column_lc,
    c.data_type,
    c.udt_name,
    ((c.is_nullable)::text = 'YES'::text) AS is_nullable,
    s.null_frac,
    s.n_distinct
   FROM (information_schema.columns c
     LEFT JOIN pg_stats s ON (((s.schemaname = (c.table_schema)::name) AND (s.tablename = (c.table_name)::name) AND (s.attname = (c.column_name)::name))))
  WHERE ((c.table_schema)::name = 'public'::name);


