    aliases text[] DEFAULT '{}'::text[],
    required boolean DEFAULT true
);


--
-- Name: admin__table_profile; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.admin__table_profile AS
 WITH parents AS (
         SELECT c.oid AS parent_oid,
            n.nspname AS schema,
            c.relname AS "table",
            pg_total_relation_size((c.oid)::regclass) AS bytes,
            (c.reltuples)::bigint AS est_rows_parent,
            s.n_live_tup AS live_rows_parent,
            (EXISTS ( SELECT 1
                   FROM pg_partitioned_table pt
                  WHERE (pt.partrelid = c.oid))) AS is_partitioned
           FROM ((pg_class c
             JOIN pg_namespace n ON ((n.oid = c.relnamespace)))
             LEFT JOIN pg_stat_all_tables s ON ((s.relid = c.oid)))
          WHERE ((c.relkind = 'r'::"char") AND (n.nspname = 'public'::name))
        ), children AS (
         SELECT i.inhparent AS parent_oid,
            i.inhrelid AS child_oid
           FROM pg_inherits i
        ), child_stats AS (
         SELECT ch.parent_oid,
            (sum(ss.n_live_tup))::bigint AS live_rows_children,
            (sum(cc.reltuples))::bigint AS est_rows_children
           FROM ((children ch
             LEFT JOIN pg_stat_all_tables ss ON ((ss.relid = ch.child_oid)))
             LEFT JOIN pg_class cc ON ((cc.oid = ch.child_oid)))
          GROUP BY ch.parent_oid
        )
 SELECT p.schema,
    p."table",
    p.bytes,
    p.is_partitioned,
    COALESCE(p.live_rows_parent, (0)::bigint) AS live_rows_parent,
    COALESCE(cs.live_rows_children, (0)::bigint) AS live_rows_children,
    COALESCE(p.est_rows_parent, (0)::bigint) AS est_rows_parent,
    COALESCE(cs.est_rows_children, (0)::bigint) AS est_rows_children,
        CASE
            WHEN p.is_partitioned THEN COALESCE(cs.live_rows_children, (0)::bigint)
            ELSE COALESCE(p.live_rows_parent, (0)::bigint)
        END AS live_rows_effective,
        CASE
            WHEN p.is_partitioned THEN COALESCE(cs.est_rows_children, (0)::bigint)
            ELSE COALESCE(p.est_rows_parent, (0)::bigint)
        END AS est_rows_effective
   FROM (parents p
     LEFT JOIN child_stats cs ON ((cs.parent_oid = p.parent_oid)));


--
-- Name: admin__table_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.admin__table_summary AS
 SELECT n.nspname AS schema,
    c.relname AS "table",
    pg_total_relation_size((c.oid)::regclass) AS bytes,
    pg_size_pretty(pg_total_relation_size((c.oid)::regclass)) AS size_pretty,
    COALESCE(s.n_live_tup, (0)::bigint) AS live_rows,
    (c.reltuples)::bigint AS est_rows,
    c.relrowsecurity AS rls_enabled,
    c.relforcerowsecurity AS rls_forced
   FROM ((pg_class c
     JOIN pg_namespace n ON ((n.oid = c.relnamespace)))
     LEFT JOIN pg_stat_all_tables s ON ((s.relid = c.oid)))
  WHERE ((c.relkind = ANY (ARRAY['r'::"char", 'm'::"char"])) AND (n.nspname <> ALL (ARRAY['pg_catalog'::name, 'information_schema'::name])))
  ORDER BY (pg_total_relation_size((c.oid)::regclass)) DESC;


