    ltg_missed_shots integer,
    ltg_hits integer,
    ltg_power_play_goals_for integer,
    ltg_pp_opportunities integer,
    ltg_sh_goals_against integer,
    std_date_range text,
    ltg_date_range text,
    std_pim integer,
    ltg_pim integer,
    pim integer,
    opponent_wins integer,
    opponent_losses integer,
    opponent_ot_losses integer,
    std_opponent_wins integer,
    std_opponent_losses integer,
    std_opponent_ot_losses integer,
    ltg_opponent_wins integer,
    ltg_opponent_losses integer,
    ltg_opponent_ot_losses integer
);


--
-- Name: combined_sos; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.combined_sos AS
 SELECT t.id AS team_id,
    t.name AS team_name,
    t.abbreviation,
    COALESCE(( SELECT avg(op.ltg_point_pct) AS avg
           FROM ( SELECT rg.ltg_point_pct
                   FROM public.rolling_games rg
                  WHERE ((rg.team_id = t.id) AND (rg.game_date < CURRENT_DATE))
                  ORDER BY rg.game_date DESC
                 LIMIT 10) op), (0)::numeric) AS past_sos,
    COALESCE(( SELECT avg(op.ltg_point_pct) AS avg
           FROM ( SELECT rg.ltg_point_pct
                   FROM public.rolling_games rg
                  WHERE ((rg.team_id = t.id) AND (rg.game_date >= CURRENT_DATE))
                  ORDER BY rg.game_date
                 LIMIT 10) op), (0)::numeric) AS future_sos
   FROM public.teams t;


