--
-- Name: cron_job_report; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.cron_job_report AS
 SELECT j.jobname,
    rd.start_time AS scheduled_time,
    rd.status,
    rd.command AS sql_text,
    rd.return_message,
    rd.end_time,
    rd.jobid,
    rd.runid
   FROM (cron.job_run_details rd
     JOIN cron.job j USING (jobid));


