--
-- Name: draft_ranker_community_moderation_exclusions; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.draft_ranker_community_moderation_exclusions (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    target_season_id bigint NOT NULL,
    exclusion_scope text NOT NULL,
    user_id uuid,
    comparison_id uuid,
    low_player_id bigint,
    high_player_id bigint,
    reason_code text NOT NULL,
    active boolean DEFAULT true NOT NULL,
    expires_at timestamp with time zone,
    created_by uuid,
    metadata jsonb DEFAULT '{}'::jsonb NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT draft_community_exclusion_expiry_valid CHECK (((expires_at IS NULL) OR (expires_at > created_at))),
    CONSTRAINT draft_community_exclusion_metadata_object CHECK ((jsonb_typeof(metadata) = 'object'::text)),
    CONSTRAINT draft_community_exclusion_reason_valid CHECK (((NULLIF(btrim(reason_code), ''::text) IS NOT NULL) AND (char_length(reason_code) <= 120))),
    CONSTRAINT draft_community_exclusion_scope_valid CHECK ((exclusion_scope = ANY (ARRAY['user'::text, 'comparison'::text, 'pair'::text]))),
    CONSTRAINT draft_community_exclusion_target_valid CHECK ((((exclusion_scope = 'user'::text) AND (user_id IS NOT NULL) AND (comparison_id IS NULL) AND (low_player_id IS NULL) AND (high_player_id IS NULL)) OR ((exclusion_scope = 'comparison'::text) AND (user_id IS NULL) AND (comparison_id IS NOT NULL) AND (low_player_id IS NULL) AND (high_player_id IS NULL)) OR ((exclusion_scope = 'pair'::text) AND (user_id IS NULL) AND (comparison_id IS NULL) AND (low_player_id IS NOT NULL) AND (high_player_id IS NOT NULL) AND (low_player_id < high_player_id))))
);


