--
-- Name: draft_ranker_community_player_results; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.draft_ranker_community_player_results (
    snapshot_id uuid NOT NULL,
    target_season_id bigint NOT NULL,
    fhfh_player_id bigint NOT NULL,
    model_rank integer NOT NULL,
    public_rank integer,
    model_score numeric NOT NULL,
    market_rank numeric,
    prior_state text NOT NULL,
    market_prior_weight numeric NOT NULL,
    evidence_state text NOT NULL,
    confidence_label text NOT NULL,
    independent_users integer NOT NULL,
    comparison_count integer NOT NULL,
    distinct_opponents integer NOT NULL,
    cutoff_opponents_inside integer NOT NULL,
    cutoff_opponents_outside integer NOT NULL,
    stability_buffer_ranks integer NOT NULL,
    conservative_rank integer NOT NULL,
    public_display_eligible boolean NOT NULL,
    public_top250_eligible boolean NOT NULL,
    admission_basis text,
    previous_public_rank integer,
    rank_delta integer,
    last_evidence_at timestamp with time zone,
    metadata jsonb DEFAULT '{}'::jsonb NOT NULL,
    CONSTRAINT draft_community_result_admission_valid CHECK (((public_top250_eligible AND (admission_basis = ANY (ARRAY['market_prior'::text, 'community_evidence'::text]))) OR ((NOT public_top250_eligible) AND (admission_basis IS NULL)))),
    CONSTRAINT draft_community_result_confidence_valid CHECK ((confidence_label = ANY (ARRAY['market prior'::text, 'building'::text, 'limited'::text, 'established'::text]))),
    CONSTRAINT draft_community_result_counts_valid CHECK (((independent_users >= 0) AND (comparison_count >= 0) AND (distinct_opponents >= 0) AND (cutoff_opponents_inside >= 0) AND (cutoff_opponents_outside >= 0) AND ((cutoff_opponents_inside + cutoff_opponents_outside) <= distinct_opponents) AND (stability_buffer_ranks >= 0) AND (conservative_rank >= model_rank))),
    CONSTRAINT draft_community_result_display_valid CHECK (((public_rank IS NULL) OR (public_display_eligible AND public_top250_eligible))),
    CONSTRAINT draft_community_result_evidence_state_valid CHECK ((evidence_state = ANY (ARRAY['market_seeded'::text, 'building'::text, 'emerging'::text, 'established'::text]))),
    CONSTRAINT draft_community_result_metadata_object CHECK ((jsonb_typeof(metadata) = 'object'::text)),
    CONSTRAINT draft_community_result_prior_state_valid CHECK ((prior_state = ANY (ARRAY['market_ranked'::text, 'previously_undrafted'::text]))),
    CONSTRAINT draft_community_result_prior_weight_valid CHECK ((market_prior_weight >= (0)::numeric)),
    CONSTRAINT draft_community_result_ranks_valid CHECK (((model_rank > 0) AND ((public_rank IS NULL) OR ((public_rank >= 1) AND (public_rank <= 250))) AND ((market_rank IS NULL) OR (market_rank > (0)::numeric)) AND ((previous_public_rank IS NULL) OR ((previous_public_rank >= 1) AND (previous_public_rank <= 250))))),
    CONSTRAINT draft_community_result_score_finite CHECK ((model_score <> ALL (ARRAY['NaN'::numeric, 'Infinity'::numeric, '-Infinity'::numeric])))
);


--
-- Name: TABLE draft_ranker_community_player_results; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE public.draft_ranker_community_player_results IS 'Immutable aggregate-only Community Ranking results; contains no account identifiers or user histories.';


--
-- Name: draft_ranker_community_refresh_runs; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.draft_ranker_community_refresh_runs (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    target_season_id bigint NOT NULL,
    operation_id uuid NOT NULL,
