    requested_by uuid,
    source_summary jsonb DEFAULT '{}'::jsonb NOT NULL,
    exclusion_summary jsonb DEFAULT '{}'::jsonb NOT NULL,
    accepted_comparison_count integer DEFAULT 0 NOT NULL,
    excluded_comparison_count integer DEFAULT 0 NOT NULL,
    deduplicated_comparison_count integer DEFAULT 0 NOT NULL,
    started_at timestamp with time zone DEFAULT now() NOT NULL,
    completed_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT draft_community_run_completion_valid CHECK ((completed_at >= started_at)),
    CONSTRAINT draft_community_run_counts_valid CHECK (((accepted_comparison_count >= 0) AND (excluded_comparison_count >= 0) AND (deduplicated_comparison_count >= 0))),
    CONSTRAINT draft_community_run_hash_valid CHECK (((operation_payload_hash ~ '^[0-9a-f]{64}$'::text) AND (source_fingerprint ~ '^[0-9a-f]{64}$'::text))),
    CONSTRAINT draft_community_run_json_valid CHECK (((jsonb_typeof(source_summary) = 'object'::text) AND (jsonb_typeof(exclusion_summary) = 'object'::text))),
    CONSTRAINT draft_community_run_model_nonblank CHECK (((NULLIF(btrim(model_version), ''::text) IS NOT NULL) AND (char_length(model_version) <= 80))),
    CONSTRAINT draft_community_run_status_valid CHECK ((status = 'completed'::text))
);


