    CONSTRAINT draft_community_snapshot_cadence_valid CHECK ((cadence = ANY (ARRAY['daily'::text, 'weekly'::text, 'manual'::text]))),
    CONSTRAINT draft_community_snapshot_counts_valid CHECK (((player_count >= 0) AND ((public_display_count >= 0) AND (public_display_count <= player_count)) AND ((public_top250_count >= 0) AND (public_top250_count <= LEAST(250, public_display_count))))),
    CONSTRAINT draft_community_snapshot_hash_valid CHECK ((source_fingerprint ~ '^[0-9a-f]{64}$'::text)),
    CONSTRAINT draft_community_snapshot_metadata_object CHECK ((jsonb_typeof(metadata) = 'object'::text)),
    CONSTRAINT draft_community_snapshot_model_nonblank CHECK (((NULLIF(btrim(model_version), ''::text) IS NOT NULL) AND (char_length(model_version) <= 80)))
);


