    CONSTRAINT draft_contribution_events_source_nonblank CHECK ((btrim(update_source) <> ''::text)),
    CONSTRAINT draft_contribution_events_state_objects CHECK (((jsonb_typeof(before_state) = 'object'::text) AND (jsonb_typeof(after_state) = 'object'::text) AND (jsonb_typeof(result) = 'object'::text)))
);


