    CONSTRAINT draft_discovery_run_hash_valid CHECK (((operation_payload_hash ~ '^[0-9a-f]{64}$'::text) AND (source_fingerprint ~ '^[0-9a-f]{64}$'::text))),
    CONSTRAINT draft_discovery_run_status_valid CHECK ((status = ANY (ARRAY['pending'::text, 'completed'::text, 'failed'::text]))),
    CONSTRAINT draft_discovery_run_summary_objects CHECK (((jsonb_typeof(source_summary) = 'object'::text) AND (jsonb_typeof(group_counts) = 'object'::text) AND (jsonb_typeof(warning_codes) = 'array'::text) AND (jsonb_typeof(error_summary) = 'object'::text)))
);


