    source_observed_at timestamp with time zone NOT NULL,
    expires_at timestamp with time zone NOT NULL,
    algorithm_version text NOT NULL,
    evidence jsonb DEFAULT '{}'::jsonb NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT draft_discovery_signal_algorithm_nonblank CHECK (((NULLIF(btrim(algorithm_version), ''::text) IS NOT NULL) AND (char_length(algorithm_version) <= 80))),
    CONSTRAINT draft_discovery_signal_evidence_object CHECK ((jsonb_typeof(evidence) = 'object'::text)),
    CONSTRAINT draft_discovery_signal_expiry_valid CHECK ((expires_at > source_observed_at)),
    CONSTRAINT draft_discovery_signal_reason_valid CHECK (((NULLIF(btrim(reason_code), ''::text) IS NOT NULL) AND (char_length(reason_code) <= 120) AND (NULLIF(btrim(reason_text), ''::text) IS NOT NULL) AND (char_length(reason_text) <= 500))),
    CONSTRAINT draft_discovery_signal_score_finite CHECK ((score <> ALL (ARRAY['NaN'::numeric, 'Infinity'::numeric, '-Infinity'::numeric]))),
    CONSTRAINT draft_discovery_signal_sources_valid CHECK (((cardinality(source_keys) > 0) AND (array_position(source_keys, NULL::text) IS NULL))),
    CONSTRAINT draft_discovery_signal_type_valid CHECK ((signal_type = ANY (ARRAY['projection_gap'::text, 'previously_undrafted'::text, 'ownership_riser'::text, 'opportunity_change'::text])))
);


