    CONSTRAINT draft_discovery_health_counts_valid CHECK (((row_count >= 0) AND (mapped_player_count >= 0) AND (eligible_player_count >= 0) AND (mapped_player_count <= row_count) AND (eligible_player_count <= mapped_player_count))),
    CONSTRAINT draft_discovery_health_expiry_valid CHECK (((expires_at IS NULL) OR (source_observed_at IS NULL) OR (expires_at > source_observed_at))),
    CONSTRAINT draft_discovery_health_json_valid CHECK (((jsonb_typeof(warning_codes) = 'array'::text) AND (jsonb_typeof(metadata) = 'object'::text))),
    CONSTRAINT draft_discovery_health_key_nonblank CHECK (((NULLIF(btrim(source_key), ''::text) IS NOT NULL) AND (char_length(source_key) <= 120))),
    CONSTRAINT draft_discovery_health_state_valid CHECK ((health_state = ANY (ARRAY['available'::text, 'stale'::text, 'season_mismatch'::text, 'insufficient_sources'::text, 'unmapped'::text, 'unavailable'::text])))
);


