    CONSTRAINT draft_pair_comps_community_valid CHECK (((NOT community_eligible) OR (consent_enabled AND (consent_policy_version IS NOT NULL) AND (outcome = ANY (ARRAY['low'::text, 'high'::text]))))),
    CONSTRAINT draft_pair_comps_metadata_object CHECK ((jsonb_typeof(metadata) = 'object'::text)),
    CONSTRAINT draft_pair_comps_outcome_valid CHECK ((outcome = ANY (ARRAY['low'::text, 'high'::text, 'too_close'::text, 'skip'::text]))),
