    CONSTRAINT draft_pair_comps_reason_valid CHECK ((community_eligible OR (NULLIF(btrim(community_ineligible_reason), ''::text) IS NOT NULL))),
    CONSTRAINT draft_pair_comps_version_nonnegative CHECK ((ranking_version >= 0))
);


