    ranking_version bigint,
    CONSTRAINT draft_pair_prompts_algorithm_nonblank CHECK ((btrim(algorithm_version) <> ''::text)),
    CONSTRAINT draft_pair_prompts_canonical_pair CHECK ((low_player_id < high_player_id)),
    CONSTRAINT draft_pair_prompts_completion_valid CHECK ((((status = 'completed'::text) AND (completed_at IS NOT NULL)) OR (status <> 'completed'::text))),
    CONSTRAINT draft_pair_prompts_expiry_valid CHECK ((expires_at > issued_at)),
    CONSTRAINT draft_pair_prompts_issue_context_valid CHECK ((((issue_operation_id IS NULL) AND (issue_payload_hash IS NULL) AND (ranking_version IS NULL)) OR ((issue_operation_id IS NOT NULL) AND (issue_payload_hash ~ '^[0-9a-f]{64}$'::text) AND (ranking_version >= 0)))),
