--

CREATE TABLE public.draft_ranker_placement_sessions (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    user_id uuid NOT NULL,
    ranking_id uuid NOT NULL,
    fhfh_player_id bigint NOT NULL,
    status text DEFAULT 'active'::text NOT NULL,
    rough_range text,
    interval_low integer NOT NULL,
    interval_high integer NOT NULL,
    plausible_low integer,
    plausible_high integer,
    question_count smallint DEFAULT 0 NOT NULL,
    contradiction_count smallint DEFAULT 0 NOT NULL,
    ranking_version bigint NOT NULL,
    issued_anchors jsonb DEFAULT '[]'::jsonb NOT NULL,
    answers jsonb DEFAULT '[]'::jsonb NOT NULL,
    suggested_rank integer,
    expires_at timestamp with time zone NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    completed_at timestamp with time zone,
    engine_version text DEFAULT 'deterministic_v1'::text NOT NULL,
    confidence text DEFAULT 'developing'::text NOT NULL,
    completion_reason text,
    CONSTRAINT draft_placement_anchors_array CHECK ((jsonb_typeof(issued_anchors) = 'array'::text)),
    CONSTRAINT draft_placement_answers_array CHECK ((jsonb_typeof(answers) = 'array'::text)),
    CONSTRAINT draft_placement_completion_valid CHECK ((((status = 'active'::text) AND (completed_at IS NULL)) OR ((status <> 'active'::text) AND (completed_at IS NOT NULL)))),
    CONSTRAINT draft_placement_confidence_valid CHECK ((confidence = ANY (ARRAY['developing'::text, 'moderate'::text, 'strong'::text]))),
    CONSTRAINT draft_placement_counts_valid CHECK ((((question_count >= 0) AND (question_count <= 16)) AND ((contradiction_count >= 0) AND (contradiction_count <= 16)))),
    CONSTRAINT draft_placement_engine_version_nonblank CHECK ((btrim(engine_version) <> ''::text)),
    CONSTRAINT draft_placement_expiry_valid CHECK ((expires_at > created_at)),
    CONSTRAINT draft_placement_range_valid CHECK (((interval_low > 0) AND (interval_high >= interval_low) AND (((plausible_low IS NULL) AND (plausible_high IS NULL)) OR ((plausible_low IS NOT NULL) AND (plausible_low > 0) AND (plausible_high IS NOT NULL) AND (plausible_high >= plausible_low))))),
    CONSTRAINT draft_placement_ready_state_valid CHECK ((((suggested_rank IS NULL) AND (completion_reason IS NULL)) OR ((suggested_rank IS NOT NULL) AND (NULLIF(btrim(completion_reason), ''::text) IS NOT NULL)))),
    CONSTRAINT draft_placement_rough_range_valid CHECK (((rough_range IS NULL) OR (rough_range = ANY (ARRAY['top_50'::text, '51_100'::text, '101_150'::text, '151_200'::text, '201_250'::text, 'outside_250'::text, 'unsure'::text])))),
    CONSTRAINT draft_placement_status_valid CHECK ((status = ANY (ARRAY['active'::text, 'confirmed'::text, 'cancelled'::text, 'expired'::text]))),
    CONSTRAINT draft_placement_suggested_positive CHECK (((suggested_rank IS NULL) OR (suggested_rank > 0))),
    CONSTRAINT draft_placement_version_nonnegative CHECK ((ranking_version >= 0))
);


