    CONSTRAINT game_prediction_feature_snapshots_scope_check CHECK ((prediction_scope = ANY (ARRAY['pregame'::text, 'in_game'::text]))),
    CONSTRAINT game_prediction_feature_snapshots_teams_check CHECK ((home_team_id <> away_team_id))
);


