--
-- Name: game_prediction_history; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.game_prediction_history (
    prediction_id uuid DEFAULT gen_random_uuid() NOT NULL,
    feature_snapshot_id uuid NOT NULL,
    run_id uuid,
    snapshot_date date NOT NULL,
    game_id bigint NOT NULL,
    prediction_scope text DEFAULT 'pregame'::text NOT NULL,
    prediction_cutoff_at timestamp with time zone NOT NULL,
    model_name text NOT NULL,
    model_version text NOT NULL,
    feature_set_version text NOT NULL,
    home_team_id smallint NOT NULL,
    away_team_id smallint NOT NULL,
    home_win_probability double precision NOT NULL,
    away_win_probability double precision NOT NULL,
    home_expected_goals double precision,
    away_expected_goals double precision,
    total_expected_goals double precision,
    spread_projection double precision,
    predicted_winner_team_id smallint,
    confidence_label text,
    top_factors jsonb DEFAULT '[]'::jsonb NOT NULL,
    components jsonb DEFAULT '{}'::jsonb NOT NULL,
    provenance jsonb DEFAULT '{}'::jsonb NOT NULL,
    metadata jsonb DEFAULT '{}'::jsonb NOT NULL,
    is_public boolean DEFAULT true NOT NULL,
    computed_at timestamp with time zone DEFAULT now() NOT NULL,
    published_at timestamp with time zone,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT game_prediction_history_cutoff_check CHECK ((computed_at >= prediction_cutoff_at)),
    CONSTRAINT game_prediction_history_probability_check CHECK (((home_win_probability >= (0)::double precision) AND (home_win_probability <= (1)::double precision) AND (away_win_probability >= (0)::double precision) AND (away_win_probability <= (1)::double precision) AND (abs(((home_win_probability + away_win_probability) - (1)::double precision)) <= (0.000001)::double precision))),
    CONSTRAINT game_prediction_history_scope_check CHECK ((prediction_scope = ANY (ARRAY['pregame'::text, 'in_game'::text]))),
    CONSTRAINT game_prediction_history_teams_check CHECK ((home_team_id <> away_team_id)),
    CONSTRAINT game_prediction_history_winner_check CHECK (((predicted_winner_team_id IS NULL) OR (predicted_winner_team_id = home_team_id) OR (predicted_winner_team_id = away_team_id)))
);


--
-- Name: TABLE game_prediction_history; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE public.game_prediction_history IS 'Append-only game-prediction history for honest backtests, repeated same-day pregame refreshes, and model evaluation.';


--
-- Name: game_prediction_market_odds_snapshots; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.game_prediction_market_odds_snapshots (
    odds_snapshot_id uuid DEFAULT gen_random_uuid() NOT NULL,
    game_id bigint NOT NULL,
    espn_game_id text,
    provider text NOT NULL,
    captured_at timestamp with time zone NOT NULL,
    requested_date date NOT NULL,
    game_date date NOT NULL,
    event_start_at timestamp with time zone,
    home_team_id smallint NOT NULL,
    away_team_id smallint NOT NULL,
    home_team_abbreviation text NOT NULL,
    away_team_abbreviation text NOT NULL,
    home_moneyline integer NOT NULL,
    away_moneyline integer NOT NULL,
    home_market_no_vig_probability double precision,
    away_market_no_vig_probability double precision,
    market_overround double precision,
    home_spread_line double precision,
    home_spread_odds integer,
    away_spread_line double precision,
    away_spread_odds integer,
    total_line double precision,
    over_odds integer,
    under_odds integer,
    source_url text NOT NULL,
    source_payload jsonb DEFAULT '{}'::jsonb NOT NULL,
    provenance jsonb DEFAULT '{}'::jsonb NOT NULL,
    metadata jsonb DEFAULT '{}'::jsonb NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT game_prediction_market_odds_snapshots_moneyline_check CHECK (((home_moneyline <> 0) AND (away_moneyline <> 0))),
    CONSTRAINT game_prediction_market_odds_snapshots_no_vig_check CHECK ((((home_market_no_vig_probability IS NULL) AND (away_market_no_vig_probability IS NULL)) OR ((home_market_no_vig_probability >= (0)::double precision) AND (home_market_no_vig_probability <= (1)::double precision) AND (away_market_no_vig_probability >= (0)::double precision) AND (away_market_no_vig_probability <= (1)::double precision) AND (abs(((home_market_no_vig_probability + away_market_no_vig_probability) - (1)::double precision)) <= (0.00001)::double precision)))),
    CONSTRAINT game_prediction_market_odds_snapshots_overround_check CHECK (((market_overround IS NULL) OR (market_overround > ('-0.05'::numeric)::double precision))),
    CONSTRAINT game_prediction_market_odds_snapshots_provider_check CHECK ((length(TRIM(BOTH FROM provider)) > 0)),
    CONSTRAINT game_prediction_market_odds_snapshots_teams_check CHECK ((home_team_id <> away_team_id))
);


