    CONSTRAINT game_prediction_model_metrics_games_check CHECK ((evaluated_games >= 0)),
    CONSTRAINT game_prediction_model_metrics_probability_metric_check CHECK ((((brier_score IS NULL) OR (brier_score >= (0)::double precision)) AND ((log_loss IS NULL) OR (log_loss >= (0)::double precision)) AND ((accuracy IS NULL) OR ((accuracy >= (0)::double precision) AND (accuracy <= (1)::double precision))) AND ((auc IS NULL) OR ((auc >= (0)::double precision) AND (auc <= (1)::double precision))))),
    CONSTRAINT game_prediction_model_metrics_window_check CHECK ((evaluation_start_date <= evaluation_end_date))
);


