--
-- Name: players; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.players (
    id bigint NOT NULL,
    "firstName" text NOT NULL,
    "lastName" text NOT NULL,
    "fullName" text NOT NULL,
    "position" public."NHL_Position_Code" NOT NULL,
    "birthDate" date NOT NULL,
    "birthCity" text,
    "birthCountry" text DEFAULT 'USA'::text,
    "heightInCentimeters" smallint NOT NULL,
    "weightInKilograms" smallint NOT NULL,
    image_url text,
    team_id smallint,
    sweater_number smallint
);


--
-- Name: COLUMN players."position"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.players."position" IS 'L, C, R, D, G';


--
-- Name: COLUMN players."birthCountry"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.players."birthCountry" IS 'birthCountry abbreviation';


