    npr.rebound_attempts_against_per_60 AS nst_pp_rates_rebound_attempts_against_per_60,
        CASE
            WHEN (n5c.player_id IS NOT NULL) THEN true
            ELSE false
        END AS has_nst_5v5_counts,
        CASE
            WHEN (n5r.player_id IS NOT NULL) THEN true
            ELSE false
        END AS has_nst_5v5_rates,
        CASE
            WHEN (nac.player_id IS NOT NULL) THEN true
            ELSE false
        END AS has_nst_all_counts,
        CASE
            WHEN (nar.player_id IS NOT NULL) THEN true
            ELSE false
        END AS has_nst_all_rates,
        CASE
            WHEN (nec.player_id IS NOT NULL) THEN true
            ELSE false
        END AS has_nst_ev_counts,
        CASE
            WHEN (ner.player_id IS NOT NULL) THEN true
            ELSE false
        END AS has_nst_ev_rates,
        CASE
            WHEN (nkc.player_id IS NOT NULL) THEN true
            ELSE false
        END AS has_nst_pk_counts,
        CASE
            WHEN (nkr.player_id IS NOT NULL) THEN true
            ELSE false
        END AS has_nst_pk_rates,
        CASE
            WHEN (npc.player_id IS NOT NULL) THEN true
            ELSE false
        END AS has_nst_pp_counts,
        CASE
            WHEN (npr.player_id IS NOT NULL) THEN true
            ELSE false
        END AS has_nst_pp_rates,
    CURRENT_TIMESTAMP AS materialized_at
   FROM (((((((((((public.wgo_goalie_stats w
     LEFT JOIN public.players p ON ((w.goalie_id = p.id)))
     LEFT JOIN public.nst_gamelog_goalie_5v5_counts n5c ON (((w.goalie_id = n5c.player_id) AND (w.date = n5c.date_scraped) AND (w.season_id = n5c.season))))
     LEFT JOIN public.nst_gamelog_goalie_5v5_rates n5r ON (((w.goalie_id = n5r.player_id) AND (w.date = n5r.date_scraped) AND (w.season_id = n5r.season))))
     LEFT JOIN public.nst_gamelog_goalie_all_counts nac ON (((w.goalie_id = nac.player_id) AND (w.date = nac.date_scraped) AND (w.season_id = nac.season))))
     LEFT JOIN public.nst_gamelog_goalie_all_rates nar ON (((w.goalie_id = nar.player_id) AND (w.date = nar.date_scraped) AND (w.season_id = nar.season))))
     LEFT JOIN public.nst_gamelog_goalie_ev_counts nec ON (((w.goalie_id = nec.player_id) AND (w.date = nec.date_scraped) AND (w.season_id = nec.season))))
     LEFT JOIN public.nst_gamelog_goalie_ev_rates ner ON (((w.goalie_id = ner.player_id) AND (w.date = ner.date_scraped) AND (w.season_id = ner.season))))
     LEFT JOIN public.nst_gamelog_goalie_pk_counts nkc ON (((w.goalie_id = nkc.player_id) AND (w.date = nkc.date_scraped) AND (w.season_id = nkc.season))))
     LEFT JOIN public.nst_gamelog_goalie_pk_rates nkr ON (((w.goalie_id = nkr.player_id) AND (w.date = nkr.date_scraped) AND (w.season_id = nkr.season))))
     LEFT JOIN public.nst_gamelog_goalie_pp_counts npc ON (((w.goalie_id = npc.player_id) AND (w.date = npc.date_scraped) AND (w.season_id = npc.season))))
     LEFT JOIN public.nst_gamelog_goalie_pp_rates npr ON (((w.goalie_id = npr.player_id) AND (w.date = npr.date_scraped) AND (w.season_id = npr.season))))
  WHERE ((w.games_played = 1) AND (w.date >= '2023-01-01'::date) AND (w.goalie_id IS NOT NULL) AND (w.date IS NOT NULL))
  ORDER BY w.goalie_id, w.date;


