CREATE VIEW public.vw_goalie_stats_unified AS
 WITH nst_supported_seasons AS (
         SELECT DISTINCT s.season
           FROM ( SELECT nst_gamelog_goalie_5v5_counts.season
                   FROM public.nst_gamelog_goalie_5v5_counts
                UNION
                 SELECT nst_gamelog_goalie_5v5_rates.season
                   FROM public.nst_gamelog_goalie_5v5_rates
                UNION
                 SELECT nst_gamelog_goalie_all_counts.season
                   FROM public.nst_gamelog_goalie_all_counts
                UNION
                 SELECT nst_gamelog_goalie_all_rates.season
                   FROM public.nst_gamelog_goalie_all_rates
                UNION
                 SELECT nst_gamelog_goalie_ev_counts.season
                   FROM public.nst_gamelog_goalie_ev_counts
                UNION
                 SELECT nst_gamelog_goalie_ev_rates.season
                   FROM public.nst_gamelog_goalie_ev_rates
                UNION
                 SELECT nst_gamelog_goalie_pk_counts.season
                   FROM public.nst_gamelog_goalie_pk_counts
                UNION
                 SELECT nst_gamelog_goalie_pk_rates.season
                   FROM public.nst_gamelog_goalie_pk_rates
                UNION
                 SELECT nst_gamelog_goalie_pp_counts.season
                   FROM public.nst_gamelog_goalie_pp_counts
                UNION
                 SELECT nst_gamelog_goalie_pp_rates.season
                   FROM public.nst_gamelog_goalie_pp_rates) s
          WHERE (s.season IS NOT NULL)
        )
 SELECT src.assists,
