           FROM public.vw_goalie_stats_unified_source
        )
 SELECT agg.player_id,
    agg.season_id,
    max(agg.player_name) AS player_name,
    array_agg(DISTINCT agg.team_id) AS team_ids,
    max(agg.position_code) AS position_code,
    max(agg.shoots_catches) AS shoots_catches,
    sum(agg.games_played) AS games_played,
    sum(agg.games_started) AS games_started,
    sum(agg.wins) AS wins,
    sum(agg.losses) AS losses,
    sum(agg.ot_losses) AS ot_losses,
    sum(agg.saves) AS saves,
    sum(agg.goals_against) AS goals_against,
    sum(agg.shots_against) AS shots_against,
    sum(agg.time_on_ice) AS time_on_ice,
    sum(agg.shutouts) AS shutouts,
    sum(agg.goals) AS goals,
    sum(agg.assists) AS assists,
    sum(agg.complete_games) AS complete_games,
    sum(agg.incomplete_games) AS incomplete_games,
    sum(agg.quality_start) AS quality_starts,
    sum(agg.regulation_losses) AS regulation_losses,
    sum(agg.regulation_wins) AS regulation_wins,
    ((sum(agg.saves))::numeric / (NULLIF(sum(agg.shots_against), 0))::numeric) AS save_pct,
    (((sum(agg.goals_against))::numeric * 3600.0) / (NULLIF(sum(agg.time_on_ice), (0)::double precision))::numeric) AS goals_against_avg,
    ((sum(agg.complete_games))::numeric / (NULLIF(sum(agg.games_started), 0))::numeric) AS complete_game_pct,
    ((sum(agg.quality_start))::numeric / (NULLIF(sum(agg.games_started), 0))::numeric) AS quality_starts_pct,
    (((sum(agg.shots_against))::numeric * 3600.0) / (NULLIF(sum(agg.time_on_ice), (0)::double precision))::numeric) AS shots_against_per_60,
    sum(agg.nst_all_counts_toi) AS nst_all_toi,
    sum(agg.nst_all_counts_shots_against) AS nst_all_shots_against,
    sum(agg.nst_all_counts_saves) AS nst_all_saves,
    sum(agg.nst_all_counts_goals_against) AS nst_all_goals_against,
    sum(agg.nst_all_counts_gsaa) AS nst_all_gsaa,
    sum(agg.nst_all_counts_xg_against) AS nst_all_xg_against,
    sum(agg.nst_all_counts_hd_shots_against) AS nst_all_hd_shots_against,
    sum(agg.nst_all_counts_hd_saves) AS nst_all_hd_saves,
    sum(agg.nst_all_counts_hd_gsaa) AS nst_all_hd_gsaa,
    sum(agg.nst_all_counts_rush_attempts_against) AS nst_all_rush_attempts_against,
    sum(agg.nst_all_counts_rebound_attempts_against) AS nst_all_rebound_attempts_against,
    sum(agg.nst_5v5_counts_toi) AS nst_5v5_toi,
    sum(agg.nst_5v5_counts_shots_against) AS nst_5v5_shots_against,
    sum(agg.nst_5v5_counts_saves) AS nst_5v5_saves,
    sum(agg.nst_5v5_counts_goals_against) AS nst_5v5_goals_against,
    sum(agg.nst_5v5_counts_gsaa) AS nst_5v5_gsaa,
    sum(agg.nst_5v5_counts_xg_against) AS nst_5v5_xg_against,
    sum(agg.nst_5v5_counts_hd_shots_against) AS nst_5v5_hd_shots_against,
    sum(agg.nst_5v5_counts_hd_saves) AS nst_5v5_hd_saves,
    sum(agg.nst_5v5_counts_hd_gsaa) AS nst_5v5_hd_gsaa,
    ((sum(agg.nst_all_counts_saves))::numeric / (NULLIF(sum(agg.nst_all_counts_shots_against), 0))::numeric) AS nst_all_sv_percentage,
    (((sum(agg.nst_all_counts_goals_against))::numeric * 3600.0) / NULLIF(sum(agg.nst_all_counts_toi), (0)::numeric)) AS nst_all_gaa,
    (((sum(agg.nst_all_counts_shots_against))::numeric * 3600.0) / NULLIF(sum(agg.nst_all_counts_toi), (0)::numeric)) AS nst_all_shots_against_per_60,
    (((sum(agg.nst_all_counts_saves))::numeric * 3600.0) / NULLIF(sum(agg.nst_all_counts_toi), (0)::numeric)) AS nst_all_saves_per_60,
    ((sum(agg.nst_all_counts_gsaa) * 3600.0) / NULLIF(sum(agg.nst_all_counts_toi), (0)::numeric)) AS nst_all_gsaa_per_60,
    ((sum(agg.nst_all_counts_xg_against) * 3600.0) / NULLIF(sum(agg.nst_all_counts_toi), (0)::numeric)) AS nst_all_xg_against_per_60,
    ((sum(agg.nst_5v5_counts_saves))::numeric / (NULLIF(sum(agg.nst_5v5_counts_shots_against), 0))::numeric) AS nst_5v5_sv_percentage,
    (((sum(agg.nst_5v5_counts_goals_against))::numeric * 3600.0) / NULLIF(sum(agg.nst_5v5_counts_toi), (0)::numeric)) AS nst_5v5_gaa,
    ((sum(agg.nst_5v5_counts_gsaa) * 3600.0) / NULLIF(sum(agg.nst_5v5_counts_toi), (0)::numeric)) AS nst_5v5_gsaa_per_60,
    ((sum(agg.nst_5v5_counts_xg_against) * 3600.0) / NULLIF(sum(agg.nst_5v5_counts_toi), (0)::numeric)) AS nst_5v5_xg_against_per_60,
    ((sum(agg.nst_5v5_counts_hd_saves))::numeric / (NULLIF(sum(agg.nst_5v5_counts_hd_shots_against), 0))::numeric) AS nst_5v5_hd_sv_percentage,
    bool_or(agg.has_nst_5v5_counts) AS has_nst_5v5_counts,
    bool_or(agg.has_nst_5v5_rates) AS has_nst_5v5_rates,
    bool_or(agg.has_nst_all_counts) AS has_nst_all_counts,
    bool_or(agg.has_nst_all_rates) AS has_nst_all_rates,
    bool_or(agg.has_nst_ev_counts) AS has_nst_ev_counts,
    bool_or(agg.has_nst_ev_rates) AS has_nst_ev_rates,
    bool_or(agg.has_nst_pk_counts) AS has_nst_pk_counts,
    bool_or(agg.has_nst_pk_rates) AS has_nst_pk_rates,
    bool_or(agg.has_nst_pp_counts) AS has_nst_pp_counts,
    bool_or(agg.has_nst_pp_rates) AS has_nst_pp_rates,
    CURRENT_TIMESTAMP AS materialized_at
   FROM game_data agg
  GROUP BY agg.player_id, agg.season_id;


