--
-- Name: wigo_goalies; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.wigo_goalies AS
 SELECT wgo.goalie_id,
    wgo.goalie_name,
    wgo.date,
    counts.team,
    counts.season,
    wgo.shoots_catches,
    wgo.position_code,
    wgo.games_played,
    wgo.games_started,
    wgo.wins,
    wgo.losses,
    wgo.ot_losses,
    wgo.saves,
    wgo.goals_against,
    wgo.shots_against,
    wgo.shutouts,
    wgo.goals AS goals_scored_by_goalie,
    wgo.assists AS assists_by_goalie,
    wgo.complete_games,
    wgo.incomplete_games,
    wgo.quality_start,
    wgo.regulation_losses,
    wgo.regulation_wins,
    wgo.save_pct AS save_percentage,
    wgo.goals_against_avg AS gaa,
    wgo.time_on_ice AS time_on_ice_seconds,
    wgo.complete_game_pct,
    wgo.quality_starts_pct,
    wgo.games_played_days_rest_0,
    wgo.games_played_days_rest_1,
    wgo.games_played_days_rest_2,
    wgo.games_played_days_rest_3,
    wgo.games_played_days_rest_4_plus,
    wgo.save_pct_days_rest_0,
    wgo.save_pct_days_rest_1,
    wgo.save_pct_days_rest_2,
    wgo.save_pct_days_rest_3,
    wgo.save_pct_days_rest_4_plus,
    counts.gsaa,
    counts.xg_against,
    counts.hd_shots_against,
    counts.hd_saves,
    counts.hd_sv_percentage,
    counts.hd_gaa,
    counts.hd_gsaa,
    counts.md_shots_against,
    counts.md_saves,
    counts.md_goals_against,
    counts.md_sv_percentage,
    counts.md_gaa,
    counts.md_gsaa,
    counts.ld_shots_against,
    counts.ld_sv_percentage,
    counts.ld_gaa,
    counts.ld_gsaa,
    counts.rush_attempts_against,
    counts.rebound_attempts_against,
    counts.avg_shot_distance,
    counts.avg_goal_distance,
    rates.toi_per_gp,
    rates.shots_against_per_60,
    rates.saves_per_60,
    rates.gsaa_per_60,
    rates.xg_against_per_60,
    rates.hd_shots_against_per_60,
    rates.hd_saves_per_60,
    rates.hd_gsaa_per_60,
    rates.md_shots_against_per_60,
    rates.md_saves_per_60,
    rates.md_gsaa_per_60,
    rates.ld_shots_against_per_60,
    rates.ld_saves_per_60,
    rates.ld_gsaa_per_60,
    rates.rush_attempts_against_per_60,
    rates.rebound_attempts_against_per_60
   FROM ((public.wgo_goalie_stats wgo
     JOIN public.nst_gamelog_goalie_all_counts counts ON (((wgo.goalie_id = counts.player_id) AND (wgo.date = counts.date_scraped))))
     JOIN public.nst_gamelog_goalie_all_rates rates ON (((wgo.goalie_id = rates.player_id) AND (wgo.date = rates.date_scraped))));


--
-- Name: VIEW wigo_goalies; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.wigo_goalies IS 'Combines goalie gamelogs from wgo_goalie_stats, nst_gamelog_goalie_all_counts, and nst_gamelog_goalie_all_rates based on goalie ID and date. Preferences applied for overlapping stats.';


