            w.opponent_id,
            m.nst_abbr AS map_nst_abbr,
            m.wgo_abbrev AS map_wgo_abbrev
           FROM (public.wgo_team_stats w
             LEFT JOIN public.dim_team_map m ON ((m.team_id = w.team_id)))
        )
 SELECT COALESCE(nst.map_team_id, wgo.team_id) AS team_id,
    COALESCE(wgo.map_nst_abbr, nst.team_abbreviation) AS team_abbreviation,
    COALESCE(nst.date, wgo.date) AS date,
    ((('TEAM:'::text || (COALESCE(nst.map_team_id, wgo.team_id))::text) || ':DATE:'::text) || (COALESCE(nst.date, wgo.date))::text) AS row_id,
