--
-- Name: news_feed_item_players; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.news_feed_item_players (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    news_item_id uuid NOT NULL,
    player_id integer,
    player_name text NOT NULL,
    team_id integer,
    role text DEFAULT 'subject'::text NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT news_feed_item_players_player_name_check CHECK ((btrim(player_name) <> ''::text)),
    CONSTRAINT news_feed_item_players_role_check CHECK ((btrim(role) <> ''::text))
);


--
-- Name: TABLE news_feed_item_players; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE public.news_feed_item_players IS 'Player assignments attached to distilled news cards so one update can affect multiple players.';


--
-- Name: news_feed_items; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.news_feed_items (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    source_review_item_id uuid,
    source_tweet_id text,
    source_url text,
    tweet_url text,
    source_label text,
    source_account text,
    team_id bigint,
    team_abbreviation text,
    headline text NOT NULL,
    blurb text DEFAULT ''::text NOT NULL,
    category text NOT NULL,
    subcategory text,
    card_status text DEFAULT 'draft'::text NOT NULL,
    observed_at timestamp with time zone,
    published_at timestamp with time zone,
    metadata jsonb DEFAULT '{}'::jsonb NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT news_feed_items_card_status_check CHECK ((card_status = ANY (ARRAY['draft'::text, 'published'::text, 'archived'::text]))),
    CONSTRAINT news_feed_items_category_check CHECK ((btrim(category) <> ''::text)),
    CONSTRAINT news_feed_items_headline_check CHECK ((btrim(headline) <> ''::text))
);


--
-- Name: TABLE news_feed_items; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE public.news_feed_items IS 'Distilled hockey news cards derived from reviewed tweet updates and reusable across feed, player flags, line-combo badges, and other site surfaces.';


--
-- Name: news_feed_keyword_phrases; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.news_feed_keyword_phrases (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    source_review_item_id uuid,
    source text DEFAULT 'manual_review'::text NOT NULL,
    phrase text NOT NULL,
    normalized_phrase text NOT NULL,
    scope_key text NOT NULL,
    category text,
    subcategory text,
    notes text,
    status text DEFAULT 'active'::text NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT news_feed_keyword_phrases_phrase_check CHECK ((btrim(phrase) <> ''::text)),
    CONSTRAINT news_feed_keyword_phrases_status_check CHECK ((status = ANY (ARRAY['active'::text, 'ignored'::text])))
);


--
-- Name: TABLE news_feed_keyword_phrases; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE public.news_feed_keyword_phrases IS 'Manual keyword and phrase candidates captured during tweet review for future classifier and regex updates.';


--
