--
-- Name: nhl_api_pbp_events; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.nhl_api_pbp_events (
    game_id bigint NOT NULL,
    season_id bigint,
    game_date date,
    event_id bigint NOT NULL,
    sort_order integer,
    period_number integer,
    period_type text,
    time_in_period text,
    time_remaining text,
    period_seconds_elapsed integer,
    time_remaining_seconds integer,
    situation_code text,
    away_goalie smallint,
    away_skaters smallint,
    home_skaters smallint,
    home_goalie smallint,
    strength_exact text,
    strength_state text,
    home_team_defending_side text,
    type_code integer,
    type_desc_key text,
    event_owner_team_id bigint,
    event_owner_side text,
    is_shot_like boolean DEFAULT false NOT NULL,
    is_goal boolean DEFAULT false NOT NULL,
    is_penalty boolean DEFAULT false NOT NULL,
    details jsonb DEFAULT '{}'::jsonb NOT NULL,
    losing_player_id bigint,
    winning_player_id bigint,
    shooting_player_id bigint,
    scoring_player_id bigint,
    goalie_in_net_id bigint,
    blocking_player_id bigint,
    hitting_player_id bigint,
    hittee_player_id bigint,
    committed_by_player_id bigint,
    drawn_by_player_id bigint,
    served_by_player_id bigint,
    player_id bigint,
    assist1_player_id bigint,
    assist2_player_id bigint,
    shot_type text,
    penalty_type_code text,
    penalty_desc_key text,
    penalty_duration_minutes integer,
    reason text,
    secondary_reason text,
    x_coord numeric,
    y_coord numeric,
    zone_code text,
    home_score integer,
    away_score integer,
    home_sog integer,
    away_sog integer,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    source_play_by_play_hash text NOT NULL,
    parser_version integer DEFAULT 1 NOT NULL,
    strength_version integer DEFAULT 1 NOT NULL,
    raw_event jsonb DEFAULT '{}'::jsonb NOT NULL,
    CONSTRAINT nhl_api_pbp_events_away_goalie_chk CHECK (((away_goalie IS NULL) OR (away_goalie = ANY (ARRAY[0, 1])))),
    CONSTRAINT nhl_api_pbp_events_home_goalie_chk CHECK (((home_goalie IS NULL) OR (home_goalie = ANY (ARRAY[0, 1])))),
    CONSTRAINT nhl_api_pbp_events_owner_side_chk CHECK (((event_owner_side IS NULL) OR (event_owner_side = ANY (ARRAY['home'::text, 'away'::text])))),
    CONSTRAINT nhl_api_pbp_events_parser_version_chk CHECK ((parser_version >= 1)),
    CONSTRAINT nhl_api_pbp_events_source_pbp_hash_nonempty_chk CHECK ((btrim(source_play_by_play_hash) <> ''::text)),
    CONSTRAINT nhl_api_pbp_events_strength_exact_chk CHECK (((strength_exact IS NULL) OR (strength_exact ~ '^[0-9]+v[0-9]+$'::text))),
    CONSTRAINT nhl_api_pbp_events_strength_state_chk CHECK (((strength_state IS NULL) OR (strength_state = ANY (ARRAY['EV'::text, 'PP'::text, 'SH'::text, 'EN'::text])))),
    CONSTRAINT nhl_api_pbp_events_strength_version_chk CHECK ((strength_version >= 1))
);


