    nhl_api_pbp_events.period_seconds_elapsed,
    nhl_api_pbp_events.time_remaining_seconds,
    nhl_api_pbp_events.situation_code,
    nhl_api_pbp_events.away_goalie,
    nhl_api_pbp_events.away_skaters,
    nhl_api_pbp_events.home_skaters,
    nhl_api_pbp_events.home_goalie,
    nhl_api_pbp_events.strength_exact,
    nhl_api_pbp_events.strength_state,
    nhl_api_pbp_events.type_code,
    nhl_api_pbp_events.type_desc_key,
    nhl_api_pbp_events.event_owner_team_id,
    nhl_api_pbp_events.event_owner_side,
    nhl_api_pbp_events.details,
    nhl_api_pbp_events.shooting_player_id,
    nhl_api_pbp_events.scoring_player_id,
    nhl_api_pbp_events.goalie_in_net_id,
    nhl_api_pbp_events.blocking_player_id,
    nhl_api_pbp_events.shot_type,
    nhl_api_pbp_events.reason,
    nhl_api_pbp_events.x_coord,
    nhl_api_pbp_events.y_coord,
    nhl_api_pbp_events.zone_code,
