COMMENT ON TABLE public.nhl_xg_shot_features IS 'Versioned in-house NHL xG shot feature rows derived from normalized NHL play-by-play and shift rows.';


--
-- Name: nhl_xg_shot_predictions; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.nhl_xg_shot_predictions (
    model_version text NOT NULL,
    prediction_type text NOT NULL,
    feature_version integer NOT NULL,
    game_id bigint NOT NULL,
    event_id bigint NOT NULL,
    season_id bigint,
    game_date date,
    event_owner_team_id bigint,
    shooter_player_id bigint,
    goalie_in_net_id bigint,
    shot_event_type text,
    label boolean,
    xg double precision NOT NULL,
    raw_probability double precision NOT NULL,
    calibrated_probability double precision,
    model_family text NOT NULL,
    model_artifact_tag text NOT NULL,
    model_artifact_path text,
    model_approved boolean DEFAULT false NOT NULL,
    feature_payload_hash text,
    provenance jsonb DEFAULT '{}'::jsonb NOT NULL,
    created_at timestamp with time zone DEFAULT timezone('utc'::text, now()) NOT NULL,
    updated_at timestamp with time zone DEFAULT timezone('utc'::text, now()) NOT NULL,
    CONSTRAINT nhl_xg_shot_predictions_prediction_type_check CHECK ((prediction_type = ANY (ARRAY['shot_goal'::text, 'rebound_creation'::text]))),
    CONSTRAINT nhl_xg_shot_predictions_probability_check CHECK (((raw_probability >= (0)::double precision) AND (raw_probability <= (1)::double precision) AND (xg >= (0)::double precision) AND (xg <= (1)::double precision) AND ((calibrated_probability IS NULL) OR ((calibrated_probability >= (0)::double precision) AND (calibrated_probability <= (1)::double precision)))))
);


--
-- Name: TABLE nhl_xg_shot_predictions; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE public.nhl_xg_shot_predictions IS 'Versioned in-house NHL xG shot and rebound prediction rows produced from persisted shot features.';


