-- Name: nhl_xg_transition_events; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.nhl_xg_transition_events (
    model_version text NOT NULL,
    feature_version integer NOT NULL,
    game_id bigint NOT NULL,
    event_id bigint NOT NULL,
    transition_type text NOT NULL,
    season_id bigint,
    game_date date,
    team_id bigint,
    player_id bigint,
    source_event_id bigint,
    source_event_type_desc_key text,
    confidence double precision NOT NULL,
    confidence_tier text NOT NULL,
    shot_event_id bigint NOT NULL,
    shot_xg double precision NOT NULL,
    transition_created_xg double precision NOT NULL,
    provenance jsonb DEFAULT '{}'::jsonb NOT NULL,
    created_at timestamp with time zone DEFAULT timezone('utc'::text, now()) NOT NULL,
    updated_at timestamp with time zone DEFAULT timezone('utc'::text, now()) NOT NULL,
    CONSTRAINT nhl_xg_transition_events_confidence_check CHECK (((confidence >= (0)::double precision) AND (confidence <= (1)::double precision))),
    CONSTRAINT nhl_xg_transition_events_tier_check CHECK ((confidence_tier = ANY (ARRAY['low'::text, 'medium'::text, 'high'::text]))),
    CONSTRAINT nhl_xg_transition_events_type_check CHECK ((transition_type = ANY (ARRAY['controlled_entry_proxy'::text, 'dump_in_entry_proxy'::text, 'controlled_exit_proxy'::text, 'failed_exit_against_proxy'::text, 'entry_assist_proxy'::text, 'transition_created_shot'::text])))
);


