--
-- Name: nst_avg_all; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.nst_avg_all AS
 SELECT nst_team_all.team_abbreviation,
    nst_team_all.team_name,
    sum(nst_team_all.gp) AS gp,
    sum(nst_team_all.toi) AS toi,
    sum(nst_team_all.w) AS w,
    sum(nst_team_all.l) AS l,
    sum(nst_team_all.otl) AS otl,
    sum(nst_team_all.points) AS points,
    sum(nst_team_all.cf) AS cf,
    sum(nst_team_all.ca) AS ca,
    avg(nst_team_all.cf_pct) AS cf_pct,
    sum(nst_team_all.ff) AS ff,
    sum(nst_team_all.fa) AS fa,
    avg(nst_team_all.ff_pct) AS ff_pct,
    sum(nst_team_all.sf) AS sf,
    sum(nst_team_all.sa) AS sa,
    avg(nst_team_all.sf_pct) AS sf_pct,
    sum(nst_team_all.gf) AS gf,
    sum(nst_team_all.ga) AS ga,
    avg(nst_team_all.gf_pct) AS gf_pct,
    sum(nst_team_all.xgf) AS xgf,
    sum(nst_team_all.xga) AS xga,
    avg(nst_team_all.xgf_pct) AS xgf_pct,
    sum(nst_team_all.scf) AS scf,
    sum(nst_team_all.sca) AS sca,
    avg(nst_team_all.scf_pct) AS scf_pct,
    sum(nst_team_all.hdcf) AS hdcf,
    sum(nst_team_all.hdca) AS hdca,
    avg(nst_team_all.hdcf_pct) AS hdcf_pct,
    sum(nst_team_all.hdsf) AS hdsf,
    sum(nst_team_all.hdsa) AS hdsa,
    avg(nst_team_all.hdsf_pct) AS hdsf_pct,
    sum(nst_team_all.hdgf) AS hdgf,
    sum(nst_team_all.hdga) AS hdga,
    avg(nst_team_all.hdgf_pct) AS hdgf_pct,
    avg(nst_team_all.sh_pct) AS sh_pct,
    avg(nst_team_all.sv_pct) AS sv_pct,
    avg(nst_team_all.pdo) AS pdo
   FROM public.nst_team_all
  GROUP BY nst_team_all.team_abbreviation, nst_team_all.team_name;


--
-- Name: nst_all_team_per_game; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.nst_all_team_per_game AS
 SELECT nst_avg_all.team_abbreviation,
    nst_avg_all.team_name,
    1 AS gp,
    ((nst_avg_all.toi)::numeric / (nst_avg_all.gp)::numeric) AS toi_per_game,
    ((nst_avg_all.w)::numeric / (nst_avg_all.gp)::numeric) AS w_per_game,
    ((nst_avg_all.l)::numeric / (nst_avg_all.gp)::numeric) AS l_per_game,
    ((nst_avg_all.otl)::numeric / (nst_avg_all.gp)::numeric) AS otl_per_game,
    ((nst_avg_all.points)::numeric / (nst_avg_all.gp)::numeric) AS points_per_game,
    ((nst_avg_all.cf)::numeric / (nst_avg_all.gp)::numeric) AS cf_per_game,
    ((nst_avg_all.ca)::numeric / (nst_avg_all.gp)::numeric) AS ca_per_game,
    nst_avg_all.cf_pct,
    ((nst_avg_all.ff)::numeric / (nst_avg_all.gp)::numeric) AS ff_per_game,
    ((nst_avg_all.fa)::numeric / (nst_avg_all.gp)::numeric) AS fa_per_game,
    nst_avg_all.ff_pct,
    ((nst_avg_all.sf)::numeric / (nst_avg_all.gp)::numeric) AS sf_per_game,
    ((nst_avg_all.sa)::numeric / (nst_avg_all.gp)::numeric) AS sa_per_game,
    nst_avg_all.sf_pct,
    ((nst_avg_all.gf)::numeric / (nst_avg_all.gp)::numeric) AS gf_per_game,
    ((nst_avg_all.ga)::numeric / (nst_avg_all.gp)::numeric) AS ga_per_game,
    nst_avg_all.gf_pct,
    ((nst_avg_all.xgf)::numeric / (nst_avg_all.gp)::numeric) AS xgf_per_game,
    ((nst_avg_all.xga)::numeric / (nst_avg_all.gp)::numeric) AS xga_per_game,
    nst_avg_all.xgf_pct,
    ((nst_avg_all.scf)::numeric / (nst_avg_all.gp)::numeric) AS scf_per_game,
    ((nst_avg_all.sca)::numeric / (nst_avg_all.gp)::numeric) AS sca_per_game,
    nst_avg_all.scf_pct,
    ((nst_avg_all.hdcf)::numeric / (nst_avg_all.gp)::numeric) AS hdcf_per_game,
    ((nst_avg_all.hdca)::numeric / (nst_avg_all.gp)::numeric) AS hdca_per_game,
    nst_avg_all.hdcf_pct,
    ((nst_avg_all.hdsf)::numeric / (nst_avg_all.gp)::numeric) AS hdsf_per_game,
    ((nst_avg_all.hdsa)::numeric / (nst_avg_all.gp)::numeric) AS hdsa_per_game,
    nst_avg_all.hdsf_pct,
    ((nst_avg_all.hdgf)::numeric / (nst_avg_all.gp)::numeric) AS hdgf_per_game,
    ((nst_avg_all.hdga)::numeric / (nst_avg_all.gp)::numeric) AS hdga_per_game,
    nst_avg_all.hdgf_pct,
    nst_avg_all.sh_pct,
    nst_avg_all.sv_pct,
    nst_avg_all.pdo
   FROM public.nst_avg_all;


