--
-- Name: nst_team_pp; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.nst_team_pp (
    team_abbreviation text NOT NULL,
    team_name text NOT NULL,
    gp integer,
    toi integer,
    w integer,
    l integer,
    otl integer,
    points integer,
    cf integer,
    ca integer,
    cf_pct double precision,
    ff integer,
    fa integer,
    ff_pct double precision,
    sf integer,
    sa integer,
    sf_pct double precision,
    gf integer,
    ga integer,
    gf_pct double precision,
    xgf double precision,
    xga double precision,
    xgf_pct double precision,
    scf integer,
    sca integer,
    scf_pct double precision,
    hdcf integer,
    hdca integer,
    hdcf_pct double precision,
    hdsf integer,
    hdsa integer,
    hdsf_pct double precision,
    hdgf integer,
    hdga integer,
    hdgf_pct double precision,
    sh_pct double precision,
    sv_pct double precision,
    pdo numeric(6,3),
    date date NOT NULL,
    situation text DEFAULT 'all'::text NOT NULL,
    created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    updated_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP
);


