    (((t.hdgf_per_game - l.hdgf) / NULLIF(l.hdgf, (0)::numeric)) * (100)::numeric) AS hdgf_per_game_diff,
    (((t.hdga_per_game - l.hdga) / NULLIF(l.hdga, (0)::numeric)) * (100)::numeric) AS hdga_per_game_diff,
    (((t.cf_pct - l.cf_pct) / NULLIF(l.cf_pct, (0)::double precision)) * (100)::double precision) AS cf_pct_diff,
    (((t.ff_pct - l.ff_pct) / NULLIF(l.ff_pct, (0)::double precision)) * (100)::double precision) AS ff_pct_diff,
    (((t.sf_pct - l.sf_pct) / NULLIF(l.sf_pct, (0)::double precision)) * (100)::double precision) AS sf_pct_diff,
