   FROM public.nst_avg_pp;


--
-- Name: nst_att_def_scores; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.nst_att_def_scores AS
 WITH league_pp AS (
         SELECT nst_league_averages.gf AS league_pp_gf,
            nst_league_averages.ga AS league_pp_ga,
            nst_league_averages.toi AS league_pp_toi,
            nst_league_averages.xgf AS league_pp_xgf,
            nst_league_averages.sh_pct AS league_pp_sh_pct,
            nst_league_averages.sf AS league_pp_sf,
            nst_league_averages.scf AS league_pp_scf,
            nst_league_averages.cf AS league_pp_cf,
            nst_league_averages.ff AS league_pp_ff,
            nst_league_averages.hdcf AS league_pp_hdcf,
            nst_league_averages.hdsf AS league_pp_hdsf,
            nst_league_averages.hdgf AS league_pp_hdgf,
            nst_league_averages.xga AS league_pp_xga,
            nst_league_averages.sa AS league_pp_sa,
            nst_league_averages.sca AS league_pp_sca,
            nst_league_averages.fa AS league_pp_fa,
            nst_league_averages.ca AS league_pp_ca,
            nst_league_averages.hdca AS league_pp_hdca,
            nst_league_averages.hdsa AS league_pp_hdsa,
            nst_league_averages.hdga AS league_pp_hdga,
            nst_league_averages.sv_pct AS league_pp_sv_pct
           FROM public.nst_league_averages
          WHERE (nst_league_averages.strength = 'pp_per_game'::text)
        ), league_pk AS (
         SELECT nst_league_averages.gf AS league_pk_gf,
            nst_league_averages.ga AS league_pk_ga,
            nst_league_averages.toi AS league_pk_toi,
            nst_league_averages.xgf AS league_pk_xgf,
            nst_league_averages.sh_pct AS league_pk_sh_pct,
            nst_league_averages.sf AS league_pk_sf,
            nst_league_averages.scf AS league_pk_scf,
            nst_league_averages.cf AS league_pk_cf,
            nst_league_averages.ff AS league_pk_ff,
            nst_league_averages.hdcf AS league_pk_hdcf,
            nst_league_averages.hdsf AS league_pk_hdsf,
            nst_league_averages.hdgf AS league_pk_hdgf,
            nst_league_averages.xga AS league_pk_xga,
            nst_league_averages.sa AS league_pk_sa,
            nst_league_averages.sca AS league_pk_sca,
            nst_league_averages.fa AS league_pk_fa,
            nst_league_averages.ca AS league_pk_ca,
            nst_league_averages.hdca AS league_pk_hdca,
            nst_league_averages.hdsa AS league_pk_hdsa,
            nst_league_averages.hdga AS league_pk_hdga,
            nst_league_averages.sv_pct AS league_pk_sv_pct
           FROM public.nst_league_averages
          WHERE (nst_league_averages.strength = 'pk_per_game'::text)
        ), league_all AS (
         SELECT nst_league_averages.gf AS league_all_gf,
            nst_league_averages.ga AS league_all_ga,
            nst_league_averages.toi AS league_all_toi,
            nst_league_averages.xgf AS league_all_xgf,
            nst_league_averages.sh_pct AS league_all_sh_pct,
            nst_league_averages.sf AS league_all_sf,
            nst_league_averages.scf AS league_all_scf,
            nst_league_averages.cf AS league_all_cf,
            nst_league_averages.ff AS league_all_ff,
            nst_league_averages.hdcf AS league_all_hdcf,
            nst_league_averages.hdsf AS league_all_hdsf,
            nst_league_averages.hdgf AS league_all_hdgf,
            nst_league_averages.xga AS league_all_xga,
            nst_league_averages.sa AS league_all_sa,
            nst_league_averages.sca AS league_all_sca,
            nst_league_averages.fa AS league_all_fa,
            nst_league_averages.ca AS league_all_ca,
            nst_league_averages.hdca AS league_all_hdca,
            nst_league_averages.hdsa AS league_all_hdsa,
            nst_league_averages.hdga AS league_all_hdga,
            nst_league_averages.sv_pct AS league_all_sv_pct
           FROM public.nst_league_averages
          WHERE (nst_league_averages.strength = 'all_per_game'::text)
        ), league_5v5 AS (
         SELECT nst_league_averages.gf AS league_5v5_gf,
            nst_league_averages.ga AS league_5v5_ga,
            nst_league_averages.toi AS league_5v5_toi,
            nst_league_averages.xgf AS league_5v5_xgf,
            nst_league_averages.sh_pct AS league_5v5_sh_pct,
            nst_league_averages.sf AS league_5v5_sf,
            nst_league_averages.scf AS league_5v5_scf,
            nst_league_averages.cf AS league_5v5_cf,
            nst_league_averages.ff AS league_5v5_ff,
            nst_league_averages.hdcf AS league_5v5_hdcf,
            nst_league_averages.hdsf AS league_5v5_hdsf,
            nst_league_averages.hdgf AS league_5v5_hdgf,
            nst_league_averages.xga AS league_5v5_xga,
            nst_league_averages.sa AS league_5v5_sa,
            nst_league_averages.sca AS league_5v5_sca,
            nst_league_averages.fa AS league_5v5_fa,
            nst_league_averages.ca AS league_5v5_ca,
            nst_league_averages.hdca AS league_5v5_hdca,
            nst_league_averages.hdsa AS league_5v5_hdsa,
            nst_league_averages.hdga AS league_5v5_hdga,
            nst_league_averages.sv_pct AS league_5v5_sv_pct
           FROM public.nst_league_averages
          WHERE (nst_league_averages.strength = '5v5_per_game'::text)
        )
 SELECT pp.team_abbreviation,
    pp.team_name,
    round((pp.gf_per_game / NULLIF(league_pp.league_pp_gf, (0)::numeric)), 3) AS att_score_pp,
    round((pk.gf_per_game / NULLIF(league_pk.league_pk_gf, (0)::numeric)), 3) AS att_score_pk,
    round((allg.gf_per_game / NULLIF(league_all.league_all_gf, (0)::numeric)), 3) AS att_score_all,
    round((fivf.gf_per_game / NULLIF(league_5v5.league_5v5_gf, (0)::numeric)), 3) AS att_score_5v5,
    round((pp.ga_per_game / NULLIF(league_pp.league_pp_ga, (0)::numeric)), 3) AS def_score_pp,
    round((pk.ga_per_game / NULLIF(league_pk.league_pk_ga, (0)::numeric)), 3) AS def_score_pk,
    round((allg.ga_per_game / NULLIF(league_all.league_all_ga, (0)::numeric)), 3) AS def_score_all,
    round((fivf.ga_per_game / NULLIF(league_5v5.league_5v5_ga, (0)::numeric)), 3) AS def_score_5v5,
    round((((pp.toi_per_game - league_pp.league_pp_toi) / NULLIF(league_pp.league_pp_toi, (0)::numeric)) * (100)::numeric), 2) AS pp_toi_diff,
    round((((pk.toi_per_game - league_pk.league_pk_toi) / NULLIF(league_pk.league_pk_toi, (0)::numeric)) * (100)::numeric), 2) AS pk_toi_diff,
    round((((allg.toi_per_game - league_all.league_all_toi) / NULLIF(league_all.league_all_toi, (0)::numeric)) * (100)::numeric), 2) AS all_toi_diff,
    round((((fivf.toi_per_game - league_5v5.league_5v5_toi) / NULLIF(league_5v5.league_5v5_toi, (0)::numeric)) * (100)::numeric), 2) AS "5v5_toi_diff",
    round((((((((((((1.0 * ((pp.xgf_per_game / (NULLIF(league_pp.league_pp_xgf, (0)::double precision))::numeric) - (1)::numeric)) + (1.0 * (((pp.sh_pct)::numeric / (NULLIF(league_pp.league_pp_sh_pct, (0)::double precision))::numeric) - (1)::numeric))) + (0.75 * ((pp.sf_per_game / NULLIF(league_pp.league_pp_sf, (0)::numeric)) - (1)::numeric))) + (0.75 * ((pp.scf_per_game / NULLIF(league_pp.league_pp_scf, (0)::numeric)) - (1)::numeric))) + (0.5 * ((pp.cf_per_game / NULLIF(league_pp.league_pp_cf, (0)::numeric)) - (1)::numeric))) + (0.5 * ((pp.ff_per_game / NULLIF(league_pp.league_pp_ff, (0)::numeric)) - (1)::numeric))) + (0.25 * ((pp.hdcf_per_game / NULLIF(league_pp.league_pp_hdcf, (0)::numeric)) - (1)::numeric))) + (0.25 * ((pp.hdsf_per_game / NULLIF(league_pp.league_pp_hdsf, (0)::numeric)) - (1)::numeric))) + (0.25 * ((pp.hdgf_per_game / NULLIF(league_pp.league_pp_hdgf, (0)::numeric)) - (1)::numeric))) / (5)::numeric) * (100)::numeric), 3) AS att_advantage_pp,
    round((((((((((((1.0 * ((pk.xgf_per_game / (NULLIF(league_pk.league_pk_xgf, (0)::double precision))::numeric) - (1)::numeric)) + (1.0 * (((pk.sh_pct)::numeric / (NULLIF(league_pk.league_pk_sh_pct, (0)::double precision))::numeric) - (1)::numeric))) + (0.75 * ((pk.sf_per_game / NULLIF(league_pk.league_pk_sf, (0)::numeric)) - (1)::numeric))) + (0.75 * ((pk.scf_per_game / NULLIF(league_pk.league_pk_scf, (0)::numeric)) - (1)::numeric))) + (0.5 * ((pk.cf_per_game / NULLIF(league_pk.league_pk_cf, (0)::numeric)) - (1)::numeric))) + (0.5 * ((pk.ff_per_game / NULLIF(league_pk.league_pk_ff, (0)::numeric)) - (1)::numeric))) + (0.25 * ((pk.hdcf_per_game / NULLIF(league_pk.league_pk_hdcf, (0)::numeric)) - (1)::numeric))) + (0.25 * ((pk.hdsf_per_game / NULLIF(league_pk.league_pk_hdsf, (0)::numeric)) - (1)::numeric))) + (0.25 * ((pk.hdgf_per_game / NULLIF(league_pk.league_pk_hdgf, (0)::numeric)) - (1)::numeric))) / (5)::numeric) * (100)::numeric), 3) AS att_advantage_pk,
    round((((((((((((1.0 * ((allg.xgf_per_game / (NULLIF(league_all.league_all_xgf, (0)::double precision))::numeric) - (1)::numeric)) + (1.0 * (((allg.sh_pct)::numeric / (NULLIF(league_all.league_all_sh_pct, (0)::double precision))::numeric) - (1)::numeric))) + (0.75 * ((allg.sf_per_game / NULLIF(league_all.league_all_sf, (0)::numeric)) - (1)::numeric))) + (0.75 * ((allg.scf_per_game / NULLIF(league_all.league_all_scf, (0)::numeric)) - (1)::numeric))) + (0.5 * ((allg.cf_per_game / NULLIF(league_all.league_all_cf, (0)::numeric)) - (1)::numeric))) + (0.5 * ((allg.ff_per_game / NULLIF(league_all.league_all_ff, (0)::numeric)) - (1)::numeric))) + (0.25 * ((allg.hdcf_per_game / NULLIF(league_all.league_all_hdcf, (0)::numeric)) - (1)::numeric))) + (0.25 * ((allg.hdsf_per_game / NULLIF(league_all.league_all_hdsf, (0)::numeric)) - (1)::numeric))) + (0.25 * ((allg.hdgf_per_game / NULLIF(league_all.league_all_hdgf, (0)::numeric)) - (1)::numeric))) / (5)::numeric) * (100)::numeric), 3) AS att_advantage_all,
    round((((((((((((1.0 * ((fivf.xgf_per_game / (NULLIF(league_5v5.league_5v5_xgf, (0)::double precision))::numeric) - (1)::numeric)) + (1.0 * (((fivf.sh_pct)::numeric / (NULLIF(league_5v5.league_5v5_sh_pct, (0)::double precision))::numeric) - (1)::numeric))) + (0.75 * ((fivf.sf_per_game / NULLIF(league_5v5.league_5v5_sf, (0)::numeric)) - (1)::numeric))) + (0.75 * ((fivf.scf_per_game / NULLIF(league_5v5.league_5v5_scf, (0)::numeric)) - (1)::numeric))) + (0.5 * ((fivf.cf_per_game / NULLIF(league_5v5.league_5v5_cf, (0)::numeric)) - (1)::numeric))) + (0.5 * ((fivf.ff_per_game / NULLIF(league_5v5.league_5v5_ff, (0)::numeric)) - (1)::numeric))) + (0.25 * ((fivf.hdcf_per_game / NULLIF(league_5v5.league_5v5_hdcf, (0)::numeric)) - (1)::numeric))) + (0.25 * ((fivf.hdsf_per_game / NULLIF(league_5v5.league_5v5_hdsf, (0)::numeric)) - (1)::numeric))) + (0.25 * ((fivf.hdgf_per_game / NULLIF(league_5v5.league_5v5_hdgf, (0)::numeric)) - (1)::numeric))) / (5)::numeric) * (100)::numeric), 3) AS att_advantage_5v5,
    round((((((((((((1.0 * (((league_pp.league_pp_xga)::numeric / NULLIF(pp.xga_per_game, (0)::numeric)) - (1)::numeric)) + (0.75 * ((league_pp.league_pp_sa / NULLIF(pp.sa_per_game, (0)::numeric)) - (1)::numeric))) + (0.75 * ((league_pp.league_pp_sca / NULLIF(pp.sca_per_game, (0)::numeric)) - (1)::numeric))) + (0.5 * ((league_pp.league_pp_fa / NULLIF(pp.fa_per_game, (0)::numeric)) - (1)::numeric))) + (0.5 * ((league_pp.league_pp_ca / NULLIF(pp.ca_per_game, (0)::numeric)) - (1)::numeric))) + (0.25 * ((league_pp.league_pp_hdca / NULLIF(pp.hdca_per_game, (0)::numeric)) - (1)::numeric))) + (0.25 * ((league_pp.league_pp_hdsa / NULLIF(pp.hdsa_per_game, (0)::numeric)) - (1)::numeric))) + (0.25 * ((league_pp.league_pp_hdga / NULLIF(pp.hdga_per_game, (0)::numeric)) - (1)::numeric))) + (1.0 * (((pp.sv_pct)::numeric / NULLIF((league_pp.league_pp_sv_pct)::numeric, (0)::numeric)) - (1)::numeric))) / (5)::numeric) * (100)::numeric), 2) AS def_advantage_pp,
    round((((((((((((1.0 * (((league_pk.league_pk_xga)::numeric / NULLIF(pk.xga_per_game, (0)::numeric)) - (1)::numeric)) + (0.75 * ((league_pk.league_pk_sa / NULLIF(pk.sa_per_game, (0)::numeric)) - (1)::numeric))) + (0.75 * ((league_pk.league_pk_sca / NULLIF(pk.sca_per_game, (0)::numeric)) - (1)::numeric))) + (0.5 * ((league_pk.league_pk_fa / NULLIF(pk.fa_per_game, (0)::numeric)) - (1)::numeric))) + (0.5 * ((league_pk.league_pk_ca / NULLIF(pk.ca_per_game, (0)::numeric)) - (1)::numeric))) + (0.25 * ((league_pk.league_pk_hdca / NULLIF(pk.hdca_per_game, (0)::numeric)) - (1)::numeric))) + (0.25 * ((league_pk.league_pk_hdsa / NULLIF(pk.hdsa_per_game, (0)::numeric)) - (1)::numeric))) + (0.25 * ((league_pk.league_pk_hdga / NULLIF(pk.hdga_per_game, (0)::numeric)) - (1)::numeric))) + (1.0 * (((pk.sv_pct)::numeric / NULLIF((league_pk.league_pk_sv_pct)::numeric, (0)::numeric)) - (1)::numeric))) / (5)::numeric) * (100)::numeric), 2) AS def_advantage_pk,
    round((((((((((((1.0 * (((league_all.league_all_xga)::numeric / NULLIF(allg.xga_per_game, (0)::numeric)) - (1)::numeric)) + (0.75 * ((league_all.league_all_sa / NULLIF(allg.sa_per_game, (0)::numeric)) - (1)::numeric))) + (0.75 * ((league_all.league_all_sca / NULLIF(allg.sca_per_game, (0)::numeric)) - (1)::numeric))) + (0.5 * ((league_all.league_all_fa / NULLIF(allg.fa_per_game, (0)::numeric)) - (1)::numeric))) + (0.5 * ((league_all.league_all_ca / NULLIF(allg.ca_per_game, (0)::numeric)) - (1)::numeric))) + (0.25 * ((league_all.league_all_hdca / NULLIF(allg.hdca_per_game, (0)::numeric)) - (1)::numeric))) + (0.25 * ((league_all.league_all_hdsa / NULLIF(allg.hdsa_per_game, (0)::numeric)) - (1)::numeric))) + (0.25 * ((league_all.league_all_hdga / NULLIF(allg.hdga_per_game, (0)::numeric)) - (1)::numeric))) + (1.0 * (((allg.sv_pct)::numeric / NULLIF((league_all.league_all_sv_pct)::numeric, (0)::numeric)) - (1)::numeric))) / (5)::numeric) * (100)::numeric), 2) AS def_advantage_all,
    round((((((((((((1.0 * (((league_5v5.league_5v5_xga)::numeric / NULLIF(fivf.xga_per_game, (0)::numeric)) - (1)::numeric)) + (0.75 * ((league_5v5.league_5v5_sa / NULLIF(fivf.sa_per_game, (0)::numeric)) - (1)::numeric))) + (0.75 * ((league_5v5.league_5v5_sca / NULLIF(fivf.sca_per_game, (0)::numeric)) - (1)::numeric))) + (0.5 * ((league_5v5.league_5v5_fa / NULLIF(fivf.fa_per_game, (0)::numeric)) - (1)::numeric))) + (0.5 * ((league_5v5.league_5v5_ca / NULLIF(fivf.ca_per_game, (0)::numeric)) - (1)::numeric))) + (0.25 * ((league_5v5.league_5v5_hdca / NULLIF(fivf.hdca_per_game, (0)::numeric)) - (1)::numeric))) + (0.25 * ((league_5v5.league_5v5_hdsa / NULLIF(fivf.hdsa_per_game, (0)::numeric)) - (1)::numeric))) + (0.25 * ((league_5v5.league_5v5_hdga / NULLIF(fivf.hdga_per_game, (0)::numeric)) - (1)::numeric))) + (1.0 * (((fivf.sv_pct)::numeric / NULLIF((league_5v5.league_5v5_sv_pct)::numeric, (0)::numeric)) - (1)::numeric))) / (5)::numeric) * (100)::numeric), 2) AS def_advantage_5v5
   FROM (((((((public.nst_pp_team_per_game pp
     JOIN public.nst_pk_team_per_game pk ON ((pp.team_abbreviation = pk.team_abbreviation)))
     JOIN public.nst_all_team_per_game allg ON ((pp.team_abbreviation = allg.team_abbreviation)))
     JOIN public.nst_5v5_team_per_game fivf ON ((pp.team_abbreviation = fivf.team_abbreviation)))
     CROSS JOIN league_pp)
     CROSS JOIN league_pk)
     CROSS JOIN league_all)
     CROSS JOIN league_5v5);


--
-- Name: nst_gamelog_5v5_counts; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.nst_gamelog_5v5_counts (
    id bigint NOT NULL,
    player_id bigint NOT NULL,
    season integer NOT NULL,
    date_scraped date NOT NULL,
    gp integer,
    toi integer,
    goals integer,
    total_assists integer,
    first_assists integer,
    second_assists integer,
    total_points integer,
    ipp double precision,
    shots integer,
    sh_percentage double precision,
    ixg double precision,
    icf integer,
    iff integer,
