--
-- Name: nst_seasonlong_es_counts; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.nst_seasonlong_es_counts AS
 SELECT nst_gamelog_es_counts.player_id,
    nst_gamelog_es_counts.season,
    sum(COALESCE(nst_gamelog_es_counts.gp, 0)) AS gp,
    sum(COALESCE(nst_gamelog_es_counts.toi, 0)) AS toi_seconds,
    sum(COALESCE(nst_gamelog_es_counts.goals, 0)) AS goals,
    sum(COALESCE(nst_gamelog_es_counts.total_assists, 0)) AS total_assists,
    sum(COALESCE(nst_gamelog_es_counts.first_assists, 0)) AS first_assists,
    sum(COALESCE(nst_gamelog_es_counts.second_assists, 0)) AS second_assists,
    sum(COALESCE(nst_gamelog_es_counts.total_points, 0)) AS total_points,
    sum(COALESCE(nst_gamelog_es_counts.shots, 0)) AS shots,
    (COALESCE((((sum(nst_gamelog_es_counts.goals))::numeric * 100.0) / (NULLIF(sum(nst_gamelog_es_counts.shots), 0))::numeric), 0.0))::double precision AS sh_percentage,
    sum(COALESCE(nst_gamelog_es_counts.ixg, (0.0)::double precision)) AS ixg,
    sum(COALESCE(nst_gamelog_es_counts.icf, 0)) AS icf,
    sum(COALESCE(nst_gamelog_es_counts.iff, 0)) AS iff,
    sum(COALESCE(nst_gamelog_es_counts.iscfs, 0)) AS iscfs,
    sum(COALESCE(nst_gamelog_es_counts.hdcf, 0)) AS hdcf,
