    (COALESCE((((oi.ca)::numeric * 3600.0) / (NULLIF(oi.toi_seconds_oi, 0))::numeric), 0.0))::double precision AS ca_per_60,
    (COALESCE((((oi.ff)::numeric * 3600.0) / (NULLIF(oi.toi_seconds_oi, 0))::numeric), 0.0))::double precision AS ff_per_60,
    (COALESCE((((oi.fa)::numeric * 3600.0) / (NULLIF(oi.toi_seconds_oi, 0))::numeric), 0.0))::double precision AS fa_per_60,
    (COALESCE((((oi.sf)::numeric * 3600.0) / (NULLIF(oi.toi_seconds_oi, 0))::numeric), 0.0))::double precision AS sf_per_60,
    (COALESCE((((oi.sa)::numeric * 3600.0) / (NULLIF(oi.toi_seconds_oi, 0))::numeric), 0.0))::double precision AS sa_per_60,
    (COALESCE((((oi.gf)::numeric * 3600.0) / (NULLIF(oi.toi_seconds_oi, 0))::numeric), 0.0))::double precision AS gf_per_60,
    (COALESCE((((oi.ga)::numeric * 3600.0) / (NULLIF(oi.toi_seconds_oi, 0))::numeric), 0.0))::double precision AS ga_per_60,
    COALESCE(((oi.xgf * (3600.0)::double precision) / (NULLIF(oi.toi_seconds_oi, 0))::double precision), (0.0)::double precision) AS xgf_per_60,
    COALESCE(((oi.xga * (3600.0)::double precision) / (NULLIF(oi.toi_seconds_oi, 0))::double precision), (0.0)::double precision) AS xga_per_60,
    (COALESCE((((oi.scf)::numeric * 3600.0) / (NULLIF(oi.toi_seconds_oi, 0))::numeric), 0.0))::double precision AS scf_per_60,
    (COALESCE((((oi.sca)::numeric * 3600.0) / (NULLIF(oi.toi_seconds_oi, 0))::numeric), 0.0))::double precision AS sca_per_60,
    (COALESCE((((oi.hdcf)::numeric * 3600.0) / (NULLIF(oi.toi_seconds_oi, 0))::numeric), 0.0))::double precision AS hdcf_per_60,
    (COALESCE((((oi.hdca)::numeric * 3600.0) / (NULLIF(oi.toi_seconds_oi, 0))::numeric), 0.0))::double precision AS hdca_per_60,
    (COALESCE((((oi.hdgf)::numeric * 3600.0) / (NULLIF(oi.toi_seconds_oi, 0))::numeric), 0.0))::double precision AS hdgf_per_60,
    (COALESCE((((oi.hdga)::numeric * 3600.0) / (NULLIF(oi.toi_seconds_oi, 0))::numeric), 0.0))::double precision AS hdga_per_60,
    (COALESCE((((oi.mdcf)::numeric * 3600.0) / (NULLIF(oi.toi_seconds_oi, 0))::numeric), 0.0))::double precision AS mdcf_per_60,
    (COALESCE((((oi.mdca)::numeric * 3600.0) / (NULLIF(oi.toi_seconds_oi, 0))::numeric), 0.0))::double precision AS mdca_per_60,
    (COALESCE((((oi.mdgf)::numeric * 3600.0) / (NULLIF(oi.toi_seconds_oi, 0))::numeric), 0.0))::double precision AS mdgf_per_60,
    (COALESCE((((oi.mdga)::numeric * 3600.0) / (NULLIF(oi.toi_seconds_oi, 0))::numeric), 0.0))::double precision AS mdga_per_60,
    (COALESCE((((oi.ldcf)::numeric * 3600.0) / (NULLIF(oi.toi_seconds_oi, 0))::numeric), 0.0))::double precision AS ldcf_per_60,
    (COALESCE((((oi.ldca)::numeric * 3600.0) / (NULLIF(oi.toi_seconds_oi, 0))::numeric), 0.0))::double precision AS ldca_per_60,
    (COALESCE((((oi.ldgf)::numeric * 3600.0) / (NULLIF(oi.toi_seconds_oi, 0))::numeric), 0.0))::double precision AS ldgf_per_60,
    (COALESCE((((oi.ldga)::numeric * 3600.0) / (NULLIF(oi.toi_seconds_oi, 0))::numeric), 0.0))::double precision AS ldga_per_60,
    (COALESCE((((oi.cf)::numeric * 100.0) / (NULLIF((oi.cf + oi.ca), 0))::numeric), 50.0))::double precision AS cf_pct,
    (COALESCE((((oi.ff)::numeric * 100.0) / (NULLIF((oi.ff + oi.fa), 0))::numeric), 50.0))::double precision AS ff_pct,
    (COALESCE((((oi.sf)::numeric * 100.0) / (NULLIF((oi.sf + oi.sa), 0))::numeric), 50.0))::double precision AS sf_pct,
    (COALESCE((((oi.gf)::numeric * 100.0) / (NULLIF((oi.gf + oi.ga), 0))::numeric), 50.0))::double precision AS gf_pct,
    COALESCE(((oi.xgf * (100.0)::double precision) / NULLIF((oi.xgf + oi.xga), (0)::double precision)), (50.0)::double precision) AS xgf_pct,
    (COALESCE((((oi.scf)::numeric * 100.0) / (NULLIF((oi.scf + oi.sca), 0))::numeric), 50.0))::double precision AS scf_pct,
    (COALESCE((((oi.hdcf)::numeric * 100.0) / (NULLIF((oi.hdcf + oi.hdca), 0))::numeric), 50.0))::double precision AS hdcf_pct,
    (COALESCE((((oi.hdgf)::numeric * 100.0) / (NULLIF((oi.hdgf + oi.hdga), 0))::numeric), 50.0))::double precision AS hdgf_pct,
    (COALESCE((((oi.mdcf)::numeric * 100.0) / (NULLIF((oi.mdcf + oi.mdca), 0))::numeric), 50.0))::double precision AS mdcf_pct,
    (COALESCE((((oi.mdgf)::numeric * 100.0) / (NULLIF((oi.mdgf + oi.mdga), 0))::numeric), 50.0))::double precision AS mdgf_pct,
    (COALESCE((((oi.ldcf)::numeric * 100.0) / (NULLIF((oi.ldcf + oi.ldca), 0))::numeric), 50.0))::double precision AS ldcf_pct,
    (COALESCE((((oi.ldgf)::numeric * 100.0) / (NULLIF((oi.ldgf + oi.ldga), 0))::numeric), 50.0))::double precision AS ldgf_pct,
    (COALESCE((((oi.gf)::numeric * 100.0) / (NULLIF(oi.sf, 0))::numeric), 0.0))::double precision AS on_ice_sh_pct,
    (COALESCE(((((oi.sa - oi.ga))::numeric * 100.0) / (NULLIF(oi.sa, 0))::numeric), 100.0))::double precision AS on_ice_sv_pct,
    ((COALESCE((((oi.gf)::numeric * 100.0) / (NULLIF(oi.sf, 0))::numeric), 0.0) + COALESCE(((((oi.sa - oi.ga))::numeric * 100.0) / (NULLIF(oi.sa, 0))::numeric), 100.0)))::double precision AS pdo,
    (COALESCE((((oi.off_zone_starts)::numeric * 100.0) / (NULLIF(((oi.off_zone_starts + oi.neu_zone_starts) + oi.def_zone_starts), 0))::numeric), 0.0))::double precision AS off_zone_start_pct,
    (COALESCE((((oi.off_zone_faceoffs)::numeric * 100.0) / (NULLIF(((oi.off_zone_faceoffs + oi.neu_zone_faceoffs) + oi.def_zone_faceoffs), 0))::numeric), 0.0))::double precision AS off_zone_faceoff_pct
   FROM public.nst_seasonlong_es_counts_oi oi;


--
