--
-- Name: nst_percentile_es_defense_filtered; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.nst_percentile_es_defense_filtered AS
 SELECT a.player_id,
    a.season,
    a.gp,
    a.toi_seconds,
    a.ca_per_60,
    a.fa_per_60,
    a.sa_per_60,
    a.ga_per_60,
    a.xga_per_60,
    a.sca_per_60,
    a.hdca_per_60,
    a.hdga_per_60,
    a.mdga_per_60,
    a.ldga_per_60,
    a.shots_blocked_per_60,
    a.takeaways_per_60,
    a.hits_per_60,
    a.pim_per_60,
    a.total_penalties_per_60,
    a.minor_penalties_per_60,
    a.major_penalties_per_60,
    a.misconduct_penalties_per_60,
    a.giveaways_per_60,
    a.on_ice_sv_pct,
    (( SELECT (((count(*))::numeric + (0.5 * (count(*) FILTER (WHERE (b.xga_per_60 = a.xga_per_60)))::numeric)))::double precision AS float8
           FROM public.nst_percentile_es_defense b
          WHERE ((b.season = a.season) AND ((b.gp)::numeric >= ceil(((a.gp)::numeric * 0.25))) AND (b.xga_per_60 IS NOT NULL) AND (a.xga_per_60 IS NOT NULL) AND (b.xga_per_60 <= a.xga_per_60))) / (NULLIF(( SELECT count(*) AS count
           FROM public.nst_percentile_es_defense b
          WHERE ((b.season = a.season) AND ((b.gp)::numeric >= ceil(((a.gp)::numeric * 0.25))) AND (b.xga_per_60 IS NOT NULL))), 0))::double precision) AS xga_per_60_percentile,
    (( SELECT (((count(*))::numeric + (0.5 * (count(*) FILTER (WHERE (b.sca_per_60 = a.sca_per_60)))::numeric)))::double precision AS float8
           FROM public.nst_percentile_es_defense b
          WHERE ((b.season = a.season) AND ((b.gp)::numeric >= ceil(((a.gp)::numeric * 0.25))) AND (b.sca_per_60 IS NOT NULL) AND (a.sca_per_60 IS NOT NULL) AND (b.sca_per_60 <= a.sca_per_60))) / (NULLIF(( SELECT count(*) AS count
           FROM public.nst_percentile_es_defense b
          WHERE ((b.season = a.season) AND ((b.gp)::numeric >= ceil(((a.gp)::numeric * 0.25))) AND (b.sca_per_60 IS NOT NULL))), 0))::double precision) AS sca_per_60_percentile,
    (( SELECT (((count(*))::numeric + (0.5 * (count(*) FILTER (WHERE (b.hdca_per_60 = a.hdca_per_60)))::numeric)))::double precision AS float8
           FROM public.nst_percentile_es_defense b
          WHERE ((b.season = a.season) AND ((b.gp)::numeric >= ceil(((a.gp)::numeric * 0.25))) AND (b.hdca_per_60 IS NOT NULL) AND (a.hdca_per_60 IS NOT NULL) AND (b.hdca_per_60 <= a.hdca_per_60))) / (NULLIF(( SELECT count(*) AS count
           FROM public.nst_percentile_es_defense b
          WHERE ((b.season = a.season) AND ((b.gp)::numeric >= ceil(((a.gp)::numeric * 0.25))) AND (b.hdca_per_60 IS NOT NULL))), 0))::double precision) AS hdca_per_60_percentile,
    (( SELECT (((count(*))::numeric + (0.5 * (count(*) FILTER (WHERE (b.shots_blocked_per_60 = a.shots_blocked_per_60)))::numeric)))::double precision AS float8
           FROM public.nst_percentile_es_defense b
          WHERE ((b.season = a.season) AND ((b.gp)::numeric >= ceil(((a.gp)::numeric * 0.25))) AND (b.shots_blocked_per_60 IS NOT NULL) AND (a.shots_blocked_per_60 IS NOT NULL) AND (b.shots_blocked_per_60 <= a.shots_blocked_per_60))) / (NULLIF(( SELECT count(*) AS count
           FROM public.nst_percentile_es_defense b
          WHERE ((b.season = a.season) AND ((b.gp)::numeric >= ceil(((a.gp)::numeric * 0.25))) AND (b.shots_blocked_per_60 IS NOT NULL))), 0))::double precision) AS shots_blocked_per_60_percentile,
    (( SELECT (((count(*))::numeric + (0.5 * (count(*) FILTER (WHERE (b.takeaways_per_60 = a.takeaways_per_60)))::numeric)))::double precision AS float8
           FROM public.nst_percentile_es_defense b
          WHERE ((b.season = a.season) AND ((b.gp)::numeric >= ceil(((a.gp)::numeric * 0.25))) AND (b.takeaways_per_60 IS NOT NULL) AND (a.takeaways_per_60 IS NOT NULL) AND (b.takeaways_per_60 <= a.takeaways_per_60))) / (NULLIF(( SELECT count(*) AS count
           FROM public.nst_percentile_es_defense b
          WHERE ((b.season = a.season) AND ((b.gp)::numeric >= ceil(((a.gp)::numeric * 0.25))) AND (b.takeaways_per_60 IS NOT NULL))), 0))::double precision) AS takeaways_per_60_percentile,
    (( SELECT (((count(*))::numeric + (0.5 * (count(*) FILTER (WHERE (b.minor_penalties_per_60 = a.minor_penalties_per_60)))::numeric)))::double precision AS float8
           FROM public.nst_percentile_es_defense b
          WHERE ((b.season = a.season) AND ((b.gp)::numeric >= ceil(((a.gp)::numeric * 0.25))) AND (b.minor_penalties_per_60 IS NOT NULL) AND (a.minor_penalties_per_60 IS NOT NULL) AND (b.minor_penalties_per_60 <= a.minor_penalties_per_60))) / (NULLIF(( SELECT count(*) AS count
           FROM public.nst_percentile_es_defense b
          WHERE ((b.season = a.season) AND ((b.gp)::numeric >= ceil(((a.gp)::numeric * 0.25))) AND (b.minor_penalties_per_60 IS NOT NULL))), 0))::double precision) AS minor_penalties_per_60_percentile,
    (( SELECT (((count(*))::numeric + (0.5 * (count(*) FILTER (WHERE (b.giveaways_per_60 = a.giveaways_per_60)))::numeric)))::double precision AS float8
           FROM public.nst_percentile_es_defense b
          WHERE ((b.season = a.season) AND ((b.gp)::numeric >= ceil(((a.gp)::numeric * 0.25))) AND (b.giveaways_per_60 IS NOT NULL) AND (a.giveaways_per_60 IS NOT NULL) AND (b.giveaways_per_60 <= a.giveaways_per_60))) / (NULLIF(( SELECT count(*) AS count
           FROM public.nst_percentile_es_defense b
          WHERE ((b.season = a.season) AND ((b.gp)::numeric >= ceil(((a.gp)::numeric * 0.25))) AND (b.giveaways_per_60 IS NOT NULL))), 0))::double precision) AS giveaways_per_60_percentile,
    NULL::text AS ga_per_60_percentile,
    NULL::text AS sa_per_60_percentile
   FROM public.nst_percentile_es_defense a;


--
-- Name: nst_percentile_es_offense; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.nst_percentile_es_offense AS
 SELECT r.player_id,
    r.season,
    r.gp,
    r.toi_seconds,
    r.goals_per_60,
    r.total_assists_per_60,
    r.first_assists_per_60,
    r.second_assists_per_60,
    r.total_points_per_60,
    r.shots_per_60,
    r.ixg_per_60,
    r.icf_per_60,
    r.iff_per_60,
    r.iscfs_per_60,
    r.ihdcf_per_60 AS i_hdcf_per_60,
    r.rush_attempts_per_60,
    r.rebounds_created_per_60,
    oi.cf_per_60,
    oi.ff_per_60,
    oi.sf_per_60,
    oi.gf_per_60,
    oi.xgf_per_60,
    oi.scf_per_60,
    oi.hdcf_per_60 AS oi_hdcf_per_60,
    oi.hdgf_per_60,
    oi.mdgf_per_60,
    oi.ldgf_per_60,
    oi.cf_pct,
    oi.ff_pct,
    oi.sf_pct,
    oi.gf_pct,
    oi.xgf_pct,
    oi.scf_pct,
    oi.hdcf_pct,
    oi.hdgf_pct,
    oi.mdgf_pct,
    oi.ldgf_pct,
    r.ipp,
    r.sh_percentage,
    oi.on_ice_sh_pct,
    r.penalties_drawn_per_60
   FROM (public.nst_seasonlong_es_rates r
     LEFT JOIN public.nst_seasonlong_es_rates_oi oi ON (((r.player_id = oi.player_id) AND (r.season = oi.season))));


