           FROM public.nst_percentile_es_offense b
          WHERE ((b.season = a.season) AND ((b.gp)::numeric >= ceil(((a.gp)::numeric * 0.25))) AND (b.iscfs_per_60 IS NOT NULL))), 0))::double precision) AS iscfs_per_60_percentile,
    (( SELECT (((count(*))::numeric + (0.5 * (count(*) FILTER (WHERE (b.penalties_drawn_per_60 = a.penalties_drawn_per_60)))::numeric)))::double precision AS float8
           FROM public.nst_percentile_es_offense b
          WHERE ((b.season = a.season) AND ((b.gp)::numeric >= ceil(((a.gp)::numeric * 0.25))) AND (b.penalties_drawn_per_60 IS NOT NULL) AND (a.penalties_drawn_per_60 IS NOT NULL) AND (b.penalties_drawn_per_60 <= a.penalties_drawn_per_60))) / (NULLIF(( SELECT count(*) AS count
           FROM public.nst_percentile_es_offense b
          WHERE ((b.season = a.season) AND ((b.gp)::numeric >= ceil(((a.gp)::numeric * 0.25))) AND (b.penalties_drawn_per_60 IS NOT NULL))), 0))::double precision) AS penalties_drawn_per_60_percentile,
    (( SELECT (((count(*))::numeric + (0.5 * (count(*) FILTER (WHERE (b.xgf_pct = a.xgf_pct)))::numeric)))::double precision AS float8
           FROM public.nst_percentile_es_offense b
          WHERE ((b.season = a.season) AND ((b.gp)::numeric >= ceil(((a.gp)::numeric * 0.25))) AND (b.xgf_pct IS NOT NULL) AND (a.xgf_pct IS NOT NULL) AND (b.xgf_pct <= a.xgf_pct))) / (NULLIF(( SELECT count(*) AS count
           FROM public.nst_percentile_es_offense b
          WHERE ((b.season = a.season) AND ((b.gp)::numeric >= ceil(((a.gp)::numeric * 0.25))) AND (b.xgf_pct IS NOT NULL))), 0))::double precision) AS xgf_pct_percentile,
    (( SELECT (((count(*))::numeric + (0.5 * (count(*) FILTER (WHERE (b.cf_pct = a.cf_pct)))::numeric)))::double precision AS float8
           FROM public.nst_percentile_es_offense b
          WHERE ((b.season = a.season) AND ((b.gp)::numeric >= ceil(((a.gp)::numeric * 0.25))) AND (b.cf_pct IS NOT NULL) AND (a.cf_pct IS NOT NULL) AND (b.cf_pct <= a.cf_pct))) / (NULLIF(( SELECT count(*) AS count
           FROM public.nst_percentile_es_offense b
          WHERE ((b.season = a.season) AND ((b.gp)::numeric >= ceil(((a.gp)::numeric * 0.25))) AND (b.cf_pct IS NOT NULL))), 0))::double precision) AS cf_pct_percentile,
    (( SELECT (((count(*))::numeric + (0.5 * (count(*) FILTER (WHERE (b.shots_per_60 = a.shots_per_60)))::numeric)))::double precision AS float8
           FROM public.nst_percentile_es_offense b
          WHERE ((b.season = a.season) AND ((b.gp)::numeric >= ceil(((a.gp)::numeric * 0.25))) AND (b.shots_per_60 IS NOT NULL) AND (a.shots_per_60 IS NOT NULL) AND (b.shots_per_60 <= a.shots_per_60))) / (NULLIF(( SELECT count(*) AS count
           FROM public.nst_percentile_es_offense b
          WHERE ((b.season = a.season) AND ((b.gp)::numeric >= ceil(((a.gp)::numeric * 0.25))) AND (b.shots_per_60 IS NOT NULL))), 0))::double precision) AS shots_per_60_percentile,
    (( SELECT (((count(*))::numeric + (0.5 * (count(*) FILTER (WHERE (b.gf_per_60 = a.gf_per_60)))::numeric)))::double precision AS float8
           FROM public.nst_percentile_es_offense b
          WHERE ((b.season = a.season) AND ((b.gp)::numeric >= ceil(((a.gp)::numeric * 0.25))) AND (b.gf_per_60 IS NOT NULL) AND (a.gf_per_60 IS NOT NULL) AND (b.gf_per_60 <= a.gf_per_60))) / (NULLIF(( SELECT count(*) AS count
           FROM public.nst_percentile_es_offense b
          WHERE ((b.season = a.season) AND ((b.gp)::numeric >= ceil(((a.gp)::numeric * 0.25))) AND (b.gf_per_60 IS NOT NULL))), 0))::double precision) AS gf_per_60_percentile,
    (( SELECT (((count(*))::numeric + (0.5 * (count(*) FILTER (WHERE (b.scf_per_60 = a.scf_per_60)))::numeric)))::double precision AS float8
           FROM public.nst_percentile_es_offense b
          WHERE ((b.season = a.season) AND ((b.gp)::numeric >= ceil(((a.gp)::numeric * 0.25))) AND (b.scf_per_60 IS NOT NULL) AND (a.scf_per_60 IS NOT NULL) AND (b.scf_per_60 <= a.scf_per_60))) / (NULLIF(( SELECT count(*) AS count
           FROM public.nst_percentile_es_offense b
          WHERE ((b.season = a.season) AND ((b.gp)::numeric >= ceil(((a.gp)::numeric * 0.25))) AND (b.scf_per_60 IS NOT NULL))), 0))::double precision) AS scf_per_60_percentile,
    (( SELECT (((count(*))::numeric + (0.5 * (count(*) FILTER (WHERE (b.hdgf_per_60 = a.hdgf_per_60)))::numeric)))::double precision AS float8
           FROM public.nst_percentile_es_offense b
          WHERE ((b.season = a.season) AND ((b.gp)::numeric >= ceil(((a.gp)::numeric * 0.25))) AND (b.hdgf_per_60 IS NOT NULL) AND (a.hdgf_per_60 IS NOT NULL) AND (b.hdgf_per_60 <= a.hdgf_per_60))) / (NULLIF(( SELECT count(*) AS count
           FROM public.nst_percentile_es_offense b
          WHERE ((b.season = a.season) AND ((b.gp)::numeric >= ceil(((a.gp)::numeric * 0.25))) AND (b.hdgf_per_60 IS NOT NULL))), 0))::double precision) AS hdgf_per_60_percentile
   FROM public.nst_percentile_es_offense a;


--
-- Name: nst_seasonlong_pk_counts; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.nst_seasonlong_pk_counts AS
 SELECT nst_gamelog_pk_counts.player_id,
    nst_gamelog_pk_counts.season,
    sum(COALESCE(nst_gamelog_pk_counts.gp, 0)) AS gp,
    sum(COALESCE(nst_gamelog_pk_counts.toi, 0)) AS toi_seconds,
    sum(COALESCE(nst_gamelog_pk_counts.goals, 0)) AS goals,
    sum(COALESCE(nst_gamelog_pk_counts.total_assists, 0)) AS total_assists,
    sum(COALESCE(nst_gamelog_pk_counts.first_assists, 0)) AS first_assists,
    sum(COALESCE(nst_gamelog_pk_counts.second_assists, 0)) AS second_assists,
    sum(COALESCE(nst_gamelog_pk_counts.total_points, 0)) AS total_points,
    sum(COALESCE(nst_gamelog_pk_counts.shots, 0)) AS shots,
    (COALESCE((((sum(nst_gamelog_pk_counts.goals))::numeric * 100.0) / (NULLIF(sum(nst_gamelog_pk_counts.shots), 0))::numeric), 0.0))::double precision AS sh_percentage,
    sum(COALESCE(nst_gamelog_pk_counts.ixg, (0.0)::double precision)) AS ixg,
    sum(COALESCE(nst_gamelog_pk_counts.icf, 0)) AS icf,
    sum(COALESCE(nst_gamelog_pk_counts.iff, 0)) AS iff,
    sum(COALESCE(nst_gamelog_pk_counts.iscfs, 0)) AS iscfs,
    sum(COALESCE(nst_gamelog_pk_counts.hdcf, 0)) AS hdcf,
    sum(COALESCE(nst_gamelog_pk_counts.rush_attempts, 0)) AS rush_attempts,
    sum(COALESCE(nst_gamelog_pk_counts.rebounds_created, 0)) AS rebounds_created,
    sum(COALESCE(nst_gamelog_pk_counts.pim, 0)) AS pim,
    sum(COALESCE(nst_gamelog_pk_counts.total_penalties, 0)) AS total_penalties,
    sum(COALESCE(nst_gamelog_pk_counts.minor_penalties, 0)) AS minor_penalties,
    sum(COALESCE(nst_gamelog_pk_counts.major_penalties, 0)) AS major_penalties,
    sum(COALESCE(nst_gamelog_pk_counts.misconduct_penalties, 0)) AS misconduct_penalties,
    sum(COALESCE(nst_gamelog_pk_counts.penalties_drawn, 0)) AS penalties_drawn,
    sum(COALESCE(nst_gamelog_pk_counts.giveaways, 0)) AS giveaways,
    sum(COALESCE(nst_gamelog_pk_counts.takeaways, 0)) AS takeaways,
    sum(COALESCE(nst_gamelog_pk_counts.hits, 0)) AS hits,
    sum(COALESCE(nst_gamelog_pk_counts.hits_taken, 0)) AS hits_taken,
    sum(COALESCE(nst_gamelog_pk_counts.shots_blocked, 0)) AS shots_blocked,
    sum(COALESCE(nst_gamelog_pk_counts.faceoffs_won, 0)) AS faceoffs_won,
    sum(COALESCE(nst_gamelog_pk_counts.faceoffs_lost, 0)) AS faceoffs_lost,
    (COALESCE((((sum(nst_gamelog_pk_counts.faceoffs_won))::numeric * 100.0) / (NULLIF((sum(nst_gamelog_pk_counts.faceoffs_won) + sum(nst_gamelog_pk_counts.faceoffs_lost)), 0))::numeric), 0.0))::double precision AS faceoffs_percentage
   FROM public.nst_gamelog_pk_counts
  GROUP BY nst_gamelog_pk_counts.player_id, nst_gamelog_pk_counts.season;


