    sum(COALESCE(nst_gamelog_pk_counts_oi.sf, 0)) AS sf,
    sum(COALESCE(nst_gamelog_pk_counts_oi.sa, 0)) AS sa,
    (sum(COALESCE(nst_gamelog_pk_counts_oi.gf, (0)::double precision)))::bigint AS gf,
