    sum(COALESCE(nst_gamelog_pk_counts_oi.mdgf, 0)) AS mdgf,
    sum(COALESCE(nst_gamelog_pk_counts_oi.mdga, 0)) AS mdga,
    sum(COALESCE(nst_gamelog_pk_counts_oi.ldcf, 0)) AS ldcf,
