    sum(COALESCE(nst_gamelog_pk_counts_oi.ldga, 0)) AS ldga,
    sum(COALESCE(nst_gamelog_pk_counts_oi.off_zone_starts, 0)) AS off_zone_starts,
    sum(COALESCE(nst_gamelog_pk_counts_oi.neu_zone_starts, 0)) AS neu_zone_starts,
    sum(COALESCE(nst_gamelog_pk_counts_oi.def_zone_starts, 0)) AS def_zone_starts,
    sum(COALESCE(nst_gamelog_pk_counts_oi.off_zone_faceoffs, 0)) AS off_zone_faceoffs,
    sum(COALESCE(nst_gamelog_pk_counts_oi.neu_zone_faceoffs, 0)) AS neu_zone_faceoffs,
