    (( SELECT (((count(*))::numeric + (0.5 * (count(*) FILTER (WHERE (b.shots_per_60 = a.shots_per_60)))::numeric)))::double precision AS float8
           FROM public.nst_percentile_pk_offense b
          WHERE ((b.season = a.season) AND ((b.gp)::numeric >= ceil(((a.gp)::numeric * 0.25))) AND (b.shots_per_60 IS NOT NULL) AND (a.shots_per_60 IS NOT NULL) AND (b.shots_per_60 <= a.shots_per_60))) / (NULLIF(( SELECT count(*) AS count
           FROM public.nst_percentile_pk_offense b
          WHERE ((b.season = a.season) AND ((b.gp)::numeric >= ceil(((a.gp)::numeric * 0.25))) AND (b.shots_per_60 IS NOT NULL))), 0))::double precision) AS shots_per_60_percentile,
    (( SELECT (((count(*))::numeric + (0.5 * (count(*) FILTER (WHERE (b.total_points_per_60 = a.total_points_per_60)))::numeric)))::double precision AS float8
           FROM public.nst_percentile_pk_offense b
          WHERE ((b.season = a.season) AND ((b.gp)::numeric >= ceil(((a.gp)::numeric * 0.25))) AND (b.total_points_per_60 IS NOT NULL) AND (a.total_points_per_60 IS NOT NULL) AND (b.total_points_per_60 <= a.total_points_per_60))) / (NULLIF(( SELECT count(*) AS count
           FROM public.nst_percentile_pk_offense b
          WHERE ((b.season = a.season) AND ((b.gp)::numeric >= ceil(((a.gp)::numeric * 0.25))) AND (b.total_points_per_60 IS NOT NULL))), 0))::double precision) AS total_points_per_60_percentile,
    (( SELECT (((count(*))::numeric + (0.5 * (count(*) FILTER (WHERE (b.ixg_per_60 = a.ixg_per_60)))::numeric)))::double precision AS float8
           FROM public.nst_percentile_pk_offense b
          WHERE ((b.season = a.season) AND ((b.gp)::numeric >= ceil(((a.gp)::numeric * 0.25))) AND (b.ixg_per_60 IS NOT NULL) AND (a.ixg_per_60 IS NOT NULL) AND (b.ixg_per_60 <= a.ixg_per_60))) / (NULLIF(( SELECT count(*) AS count
           FROM public.nst_percentile_pk_offense b
          WHERE ((b.season = a.season) AND ((b.gp)::numeric >= ceil(((a.gp)::numeric * 0.25))) AND (b.ixg_per_60 IS NOT NULL))), 0))::double precision) AS ixg_per_60_percentile
   FROM public.nst_percentile_pk_offense a;


