    (COALESCE((((sum(nst_gamelog_pp_counts.faceoffs_won))::numeric * 100.0) / (NULLIF((sum(nst_gamelog_pp_counts.faceoffs_won) + sum(nst_gamelog_pp_counts.faceoffs_lost)), 0))::numeric), 0.0))::double precision AS faceoffs_percentage
