--
-- Name: nst_percentile_pp_offense; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.nst_percentile_pp_offense AS
 SELECT r.player_id,
    r.season,
    r.gp,
    r.toi_seconds,
    r.goals_per_60,
    r.total_assists_per_60,
    r.first_assists_per_60,
    r.second_assists_per_60,
    r.total_points_per_60,
    r.shots_per_60,
    r.ixg_per_60,
    r.icf_per_60,
    r.iff_per_60,
    r.iscfs_per_60,
    r.ihdcf_per_60 AS i_hdcf_per_60,
    r.rush_attempts_per_60,
    r.rebounds_created_per_60,
    oi.cf_per_60,
    oi.ff_per_60,
    oi.sf_per_60,
    oi.gf_per_60,
    oi.xgf_per_60,
    oi.scf_per_60,
    oi.hdcf_per_60 AS oi_hdcf_per_60,
    oi.hdgf_per_60,
    oi.mdgf_per_60,
    oi.ldgf_per_60,
    oi.cf_pct,
    oi.ff_pct,
    oi.sf_pct,
    oi.gf_pct,
    oi.xgf_pct,
    oi.scf_pct,
    oi.hdcf_pct,
    oi.hdgf_pct,
    oi.mdgf_pct,
    oi.ldgf_pct,
    r.ipp,
    r.sh_percentage,
    oi.on_ice_sh_pct,
    r.penalties_drawn_per_60
   FROM (public.nst_seasonlong_pp_rates r
     LEFT JOIN public.nst_seasonlong_pp_rates_oi oi ON (((r.player_id = oi.player_id) AND (r.season = oi.season))));


