--
-- Name: nst_pk_team_differentials; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.nst_pk_team_differentials AS
 SELECT t.team_abbreviation,
    t.team_name,
    t.gp,
    t.w_per_game,
    t.l_per_game,
    t.otl_per_game,
    t.points_per_game,
    (((t.toi_per_game - l.toi) / NULLIF(l.toi, (0)::numeric)) * (100)::numeric) AS toi_per_game_diff,
    (((t.cf_per_game - l.cf) / NULLIF(l.cf, (0)::numeric)) * (100)::numeric) AS cf_per_game_diff,
    (((t.ca_per_game - l.ca) / NULLIF(l.ca, (0)::numeric)) * (100)::numeric) AS ca_per_game_diff,
    (((t.ff_per_game - l.ff) / NULLIF(l.ff, (0)::numeric)) * (100)::numeric) AS ff_per_game_diff,
    (((t.fa_per_game - l.fa) / NULLIF(l.fa, (0)::numeric)) * (100)::numeric) AS fa_per_game_diff,
    (((t.sf_per_game - l.sf) / NULLIF(l.sf, (0)::numeric)) * (100)::numeric) AS sf_per_game_diff,
    (((t.sa_per_game - l.sa) / NULLIF(l.sa, (0)::numeric)) * (100)::numeric) AS sa_per_game_diff,
    (((t.gf_per_game - l.gf) / NULLIF(l.gf, (0)::numeric)) * (100)::numeric) AS gf_per_game_diff,
    (((t.ga_per_game - l.ga) / NULLIF(l.ga, (0)::numeric)) * (100)::numeric) AS ga_per_game_diff,
    ((((t.xgf_per_game)::double precision - l.xgf) / NULLIF(l.xgf, (0)::double precision)) * (100)::double precision) AS xgf_per_game_diff,
    ((((t.xga_per_game)::double precision - l.xga) / NULLIF(l.xga, (0)::double precision)) * (100)::double precision) AS xga_per_game_diff,
    (((t.scf_per_game - l.scf) / NULLIF(l.scf, (0)::numeric)) * (100)::numeric) AS scf_per_game_diff,
    (((t.sca_per_game - l.sca) / NULLIF(l.sca, (0)::numeric)) * (100)::numeric) AS sca_per_game_diff,
    (((t.hdcf_per_game - l.hdcf) / NULLIF(l.hdcf, (0)::numeric)) * (100)::numeric) AS hdcf_per_game_diff,
    (((t.hdca_per_game - l.hdca) / NULLIF(l.hdca, (0)::numeric)) * (100)::numeric) AS hdca_per_game_diff,
    (((t.hdsf_per_game - l.hdsf) / NULLIF(l.hdsf, (0)::numeric)) * (100)::numeric) AS hdsf_per_game_diff,
    (((t.hdsa_per_game - l.hdsa) / NULLIF(l.hdsa, (0)::numeric)) * (100)::numeric) AS hdsa_per_game_diff,
    (((t.hdgf_per_game - l.hdgf) / NULLIF(l.hdgf, (0)::numeric)) * (100)::numeric) AS hdgf_per_game_diff,
    (((t.hdga_per_game - l.hdga) / NULLIF(l.hdga, (0)::numeric)) * (100)::numeric) AS hdga_per_game_diff,
    (((t.cf_pct - l.cf_pct) / NULLIF(l.cf_pct, (0)::double precision)) * (100)::double precision) AS cf_pct_diff,
    (((t.ff_pct - l.ff_pct) / NULLIF(l.ff_pct, (0)::double precision)) * (100)::double precision) AS ff_pct_diff,
    (((t.sf_pct - l.sf_pct) / NULLIF(l.sf_pct, (0)::double precision)) * (100)::double precision) AS sf_pct_diff,
    (((t.gf_pct - l.gf_pct) / NULLIF(l.gf_pct, (0)::double precision)) * (100)::double precision) AS gf_pct_diff,
    (((t.xgf_pct - l.xgf_pct) / NULLIF(l.xgf_pct, (0)::double precision)) * (100)::double precision) AS xgf_pct_diff,
    (((t.scf_pct - l.scf_pct) / NULLIF(l.scf_pct, (0)::double precision)) * (100)::double precision) AS scf_pct_diff,
    (((t.hdcf_pct - l.hdcf_pct) / NULLIF(l.hdcf_pct, (0)::double precision)) * (100)::double precision) AS hdcf_pct_diff,
    (((t.hdsf_pct - l.hdsf_pct) / NULLIF(l.hdsf_pct, (0)::double precision)) * (100)::double precision) AS hdsf_pct_diff,
    (((t.hdgf_pct - l.hdgf_pct) / NULLIF(l.hdgf_pct, (0)::double precision)) * (100)::double precision) AS hdgf_pct_diff,
    (((t.sh_pct - l.sh_pct) / NULLIF(l.sh_pct, (0)::double precision)) * (100)::double precision) AS sh_pct_diff,
    (((t.sv_pct - l.sv_pct) / NULLIF(l.sv_pct, (0)::double precision)) * (100)::double precision) AS sv_pct_diff,
    (((t.pdo - l.pdo) / NULLIF(l.pdo, (0)::numeric)) * (100)::numeric) AS pdo_diff
   FROM (public.nst_all_team_per_game t
     CROSS JOIN ( SELECT nst_league_averages.strength,
            nst_league_averages.gp,
            nst_league_averages.toi,
            nst_league_averages.w,
            nst_league_averages.l,
            nst_league_averages.otl,
            nst_league_averages.points,
            nst_league_averages.cf,
            nst_league_averages.ca,
            nst_league_averages.cf_pct,
            nst_league_averages.ff,
            nst_league_averages.fa,
            nst_league_averages.ff_pct,
            nst_league_averages.sf,
            nst_league_averages.sa,
            nst_league_averages.sf_pct,
            nst_league_averages.gf,
            nst_league_averages.ga,
            nst_league_averages.gf_pct,
            nst_league_averages.xgf,
            nst_league_averages.xga,
            nst_league_averages.xgf_pct,
            nst_league_averages.scf,
            nst_league_averages.sca,
            nst_league_averages.scf_pct,
            nst_league_averages.hdcf,
            nst_league_averages.hdca,
            nst_league_averages.hdcf_pct,
            nst_league_averages.hdsf,
            nst_league_averages.hdsa,
            nst_league_averages.hdsf_pct,
            nst_league_averages.hdgf,
            nst_league_averages.hdga,
            nst_league_averages.hdgf_pct,
            nst_league_averages.sh_pct,
            nst_league_averages.sv_pct,
            nst_league_averages.pdo
           FROM public.nst_league_averages
          WHERE (nst_league_averages.strength = 'pk_per_game'::text)) l);


