--
-- Name: nst_seasonlong_as_counts; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.nst_seasonlong_as_counts AS
 SELECT nst_gamelog_as_counts.player_id,
    nst_gamelog_as_counts.season,
    sum(COALESCE((nst_gamelog_as_counts.gp)::integer, 0)) AS gp,
    sum(COALESCE(nst_gamelog_as_counts.toi, 0)) AS toi_seconds,
    sum(COALESCE((nst_gamelog_as_counts.goals)::integer, 0)) AS goals,
    sum(COALESCE((nst_gamelog_as_counts.total_assists)::integer, 0)) AS total_assists,
    sum(COALESCE((nst_gamelog_as_counts.first_assists)::integer, 0)) AS first_assists,
    sum(COALESCE((nst_gamelog_as_counts.second_assists)::integer, 0)) AS second_assists,
    sum(COALESCE((nst_gamelog_as_counts.total_points)::integer, 0)) AS total_points,
    sum(COALESCE((nst_gamelog_as_counts.shots)::integer, 0)) AS shots,
    (COALESCE((((sum(COALESCE((nst_gamelog_as_counts.goals)::integer, 0)))::numeric * 100.0) / (NULLIF(sum(COALESCE((nst_gamelog_as_counts.shots)::integer, 0)), 0))::numeric), 0.0))::double precision AS sh_percentage,
    sum(COALESCE(nst_gamelog_as_counts.ixg, (0.0)::double precision)) AS ixg,
    sum(COALESCE((nst_gamelog_as_counts.icf)::integer, 0)) AS icf,
    sum(COALESCE((nst_gamelog_as_counts.iff)::integer, 0)) AS iff,
    sum(COALESCE((nst_gamelog_as_counts.iscfs)::integer, 0)) AS iscfs,
    sum(COALESCE((nst_gamelog_as_counts.hdcf)::integer, 0)) AS hdcf,
    sum(COALESCE((nst_gamelog_as_counts.rush_attempts)::integer, 0)) AS rush_attempts,
    sum(COALESCE((nst_gamelog_as_counts.rebounds_created)::integer, 0)) AS rebounds_created,
    sum(COALESCE((nst_gamelog_as_counts.pim)::integer, 0)) AS pim,
    sum(COALESCE((nst_gamelog_as_counts.total_penalties)::integer, 0)) AS total_penalties,
    sum(COALESCE((nst_gamelog_as_counts.minor_penalties)::integer, 0)) AS minor_penalties,
    sum(COALESCE((nst_gamelog_as_counts.major_penalties)::integer, 0)) AS major_penalties,
    sum(COALESCE((nst_gamelog_as_counts.misconduct_penalties)::integer, 0)) AS misconduct_penalties,
    sum(COALESCE((nst_gamelog_as_counts.penalties_drawn)::integer, 0)) AS penalties_drawn,
    sum(COALESCE((nst_gamelog_as_counts.giveaways)::integer, 0)) AS giveaways,
    sum(COALESCE((nst_gamelog_as_counts.takeaways)::integer, 0)) AS takeaways,
    sum(COALESCE((nst_gamelog_as_counts.hits)::integer, 0)) AS hits,
    sum(COALESCE((nst_gamelog_as_counts.hits_taken)::integer, 0)) AS hits_taken,
    sum(COALESCE((nst_gamelog_as_counts.shots_blocked)::integer, 0)) AS shots_blocked,
    sum(COALESCE((nst_gamelog_as_counts.faceoffs_won)::integer, 0)) AS faceoffs_won,
    sum(COALESCE((nst_gamelog_as_counts.faceoffs_lost)::integer, 0)) AS faceoffs_lost,
    (COALESCE((((sum(COALESCE((nst_gamelog_as_counts.faceoffs_won)::integer, 0)))::numeric * 100.0) / (NULLIF((sum(COALESCE((nst_gamelog_as_counts.faceoffs_won)::integer, 0)) + sum(COALESCE((nst_gamelog_as_counts.faceoffs_lost)::integer, 0))), 0))::numeric), 0.0))::double precision AS faceoffs_percentage
   FROM public.nst_gamelog_as_counts
  GROUP BY nst_gamelog_as_counts.player_id, nst_gamelog_as_counts.season;


--
-- Name: nst_seasonlong_as_counts_oi; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.nst_seasonlong_as_counts_oi AS
 SELECT g.player_id,
    g.season,
    sum(COALESCE(g.gp, 0)) AS gp,
    sum(COALESCE(g.toi, 0)) AS toi_seconds_oi,
    sum(COALESCE(g.cf, 0)) AS cf,
    sum(COALESCE(g.ca, 0)) AS ca,
    sum(COALESCE(g.ff, 0)) AS ff,
    sum(COALESCE(g.fa, 0)) AS fa,
    sum(COALESCE(g.sf, 0)) AS sf,
    sum(COALESCE(g.sa, 0)) AS sa,
    (sum(COALESCE((g.gf)::double precision, (0)::double precision)))::bigint AS gf,
    (sum(COALESCE((g.ga)::double precision, (0)::double precision)))::bigint AS ga,
    sum(COALESCE(g.xgf, (0.0)::double precision)) AS xgf,
    sum(COALESCE(g.xga, (0.0)::double precision)) AS xga,
    (sum(COALESCE((g.scf)::double precision, (0)::double precision)))::bigint AS scf,
    (sum(COALESCE((g.sca)::double precision, (0)::double precision)))::bigint AS sca,
    sum(COALESCE(g.hdcf, 0)) AS hdcf,
    (sum(COALESCE((g.hdca)::double precision, (0)::double precision)))::bigint AS hdca,
    sum(COALESCE(g.hdgf, 0)) AS hdgf,
    sum(COALESCE(g.hdga, (0)::double precision)) AS hdga,
    sum(COALESCE(g.mdcf, 0)) AS mdcf,
    sum(COALESCE(g.mdca, 0)) AS mdca,
    sum(COALESCE(g.mdgf, 0)) AS mdgf,
    sum(COALESCE(g.mdga, 0)) AS mdga,
    sum(COALESCE(g.ldcf, 0)) AS ldcf,
    sum(COALESCE(g.ldca, 0)) AS ldca,
    sum(COALESCE(g.ldgf, 0)) AS ldgf,
    sum(COALESCE(g.ldga, 0)) AS ldga,
    sum(COALESCE(g.off_zone_starts, 0)) AS off_zone_starts,
    sum(COALESCE(g.neu_zone_starts, 0)) AS neu_zone_starts,
    sum(COALESCE(g.def_zone_starts, 0)) AS def_zone_starts,
    sum(COALESCE(g.off_zone_faceoffs, 0)) AS off_zone_faceoffs,
    sum(COALESCE(g.neu_zone_faceoffs, 0)) AS neu_zone_faceoffs,
    sum(COALESCE(g.def_zone_faceoffs, 0)) AS def_zone_faceoffs
   FROM public.nst_gamelog_as_counts_oi g
  GROUP BY g.player_id, g.season;


--
-- Name: nst_seasonlong_as_rates; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.nst_seasonlong_as_rates AS
 SELECT c.player_id,
    c.season,
    c.gp,
    c.toi_seconds,
    (COALESCE((((c.goals)::numeric * 3600.0) / (NULLIF(c.toi_seconds, 0))::numeric), 0.0))::double precision AS goals_per_60,
    (COALESCE((((c.total_assists)::numeric * 3600.0) / (NULLIF(c.toi_seconds, 0))::numeric), 0.0))::double precision AS total_assists_per_60,
    (COALESCE((((c.first_assists)::numeric * 3600.0) / (NULLIF(c.toi_seconds, 0))::numeric), 0.0))::double precision AS first_assists_per_60,
    (COALESCE((((c.second_assists)::numeric * 3600.0) / (NULLIF(c.toi_seconds, 0))::numeric), 0.0))::double precision AS second_assists_per_60,
    (COALESCE((((c.total_points)::numeric * 3600.0) / (NULLIF(c.toi_seconds, 0))::numeric), 0.0))::double precision AS total_points_per_60,
    (COALESCE((((c.shots)::numeric * 3600.0) / (NULLIF(c.toi_seconds, 0))::numeric), 0.0))::double precision AS shots_per_60,
    COALESCE(((c.ixg * (3600.0)::double precision) / (NULLIF(c.toi_seconds, 0))::double precision), (0.0)::double precision) AS ixg_per_60,
    (COALESCE((((c.icf)::numeric * 3600.0) / (NULLIF(c.toi_seconds, 0))::numeric), 0.0))::double precision AS icf_per_60,
    (COALESCE((((c.iff)::numeric * 3600.0) / (NULLIF(c.toi_seconds, 0))::numeric), 0.0))::double precision AS iff_per_60,
    (COALESCE((((c.iscfs)::numeric * 3600.0) / (NULLIF(c.toi_seconds, 0))::numeric), 0.0))::double precision AS iscfs_per_60,
    (COALESCE((((c.hdcf)::numeric * 3600.0) / (NULLIF(c.toi_seconds, 0))::numeric), 0.0))::double precision AS ihdcf_per_60,
    (COALESCE((((c.rush_attempts)::numeric * 3600.0) / (NULLIF(c.toi_seconds, 0))::numeric), 0.0))::double precision AS rush_attempts_per_60,
    (COALESCE((((c.rebounds_created)::numeric * 3600.0) / (NULLIF(c.toi_seconds, 0))::numeric), 0.0))::double precision AS rebounds_created_per_60,
    (COALESCE((((c.pim)::numeric * 3600.0) / (NULLIF(c.toi_seconds, 0))::numeric), 0.0))::double precision AS pim_per_60,
    (COALESCE((((c.total_penalties)::numeric * 3600.0) / (NULLIF(c.toi_seconds, 0))::numeric), 0.0))::double precision AS total_penalties_per_60,
    (COALESCE((((c.minor_penalties)::numeric * 3600.0) / (NULLIF(c.toi_seconds, 0))::numeric), 0.0))::double precision AS minor_penalties_per_60,
    (COALESCE((((c.major_penalties)::numeric * 3600.0) / (NULLIF(c.toi_seconds, 0))::numeric), 0.0))::double precision AS major_penalties_per_60,
    (COALESCE((((c.misconduct_penalties)::numeric * 3600.0) / (NULLIF(c.toi_seconds, 0))::numeric), 0.0))::double precision AS misconduct_penalties_per_60,
    (COALESCE((((c.penalties_drawn)::numeric * 3600.0) / (NULLIF(c.toi_seconds, 0))::numeric), 0.0))::double precision AS penalties_drawn_per_60,
    (COALESCE((((c.giveaways)::numeric * 3600.0) / (NULLIF(c.toi_seconds, 0))::numeric), 0.0))::double precision AS giveaways_per_60,
    (COALESCE((((c.takeaways)::numeric * 3600.0) / (NULLIF(c.toi_seconds, 0))::numeric), 0.0))::double precision AS takeaways_per_60,
