    (COALESCE((((c.shots)::numeric * 3600.0) / (NULLIF(c.toi_seconds, 0))::numeric), 0.0))::double precision AS shots_per_60,
    COALESCE(((c.ixg * (3600.0)::double precision) / (NULLIF(c.toi_seconds, 0))::double precision), (0.0)::double precision) AS ixg_per_60,
    (COALESCE((((c.icf)::numeric * 3600.0) / (NULLIF(c.toi_seconds, 0))::numeric), 0.0))::double precision AS icf_per_60,
    (COALESCE((((c.iff)::numeric * 3600.0) / (NULLIF(c.toi_seconds, 0))::numeric), 0.0))::double precision AS iff_per_60,
    (COALESCE((((c.iscfs)::numeric * 3600.0) / (NULLIF(c.toi_seconds, 0))::numeric), 0.0))::double precision AS iscfs_per_60,
    (COALESCE((((c.hdcf)::numeric * 3600.0) / (NULLIF(c.toi_seconds, 0))::numeric), 0.0))::double precision AS ihdcf_per_60,
    (COALESCE((((c.rush_attempts)::numeric * 3600.0) / (NULLIF(c.toi_seconds, 0))::numeric), 0.0))::double precision AS rush_attempts_per_60,
    (COALESCE((((c.rebounds_created)::numeric * 3600.0) / (NULLIF(c.toi_seconds, 0))::numeric), 0.0))::double precision AS rebounds_created_per_60,
    (COALESCE((((c.pim)::numeric * 3600.0) / (NULLIF(c.toi_seconds, 0))::numeric), 0.0))::double precision AS pim_per_60,
    (COALESCE((((c.total_penalties)::numeric * 3600.0) / (NULLIF(c.toi_seconds, 0))::numeric), 0.0))::double precision AS total_penalties_per_60,
    (COALESCE((((c.penalties_drawn)::numeric * 3600.0) / (NULLIF(c.toi_seconds, 0))::numeric), 0.0))::double precision AS penalties_drawn_per_60,
    (COALESCE((((c.giveaways)::numeric * 3600.0) / (NULLIF(c.toi_seconds, 0))::numeric), 0.0))::double precision AS giveaways_per_60,
    (COALESCE((((c.takeaways)::numeric * 3600.0) / (NULLIF(c.toi_seconds, 0))::numeric), 0.0))::double precision AS takeaways_per_60,
    (COALESCE((((c.hits)::numeric * 3600.0) / (NULLIF(c.toi_seconds, 0))::numeric), 0.0))::double precision AS hits_per_60,
    (COALESCE((((c.hits_taken)::numeric * 3600.0) / (NULLIF(c.toi_seconds, 0))::numeric), 0.0))::double precision AS hits_taken_per_60,
    (COALESCE((((c.shots_blocked)::numeric * 3600.0) / (NULLIF(c.toi_seconds, 0))::numeric), 0.0))::double precision AS shots_blocked_per_60,
    (COALESCE((((c.faceoffs_won)::numeric * 3600.0) / (NULLIF(c.toi_seconds, 0))::numeric), 0.0))::double precision AS faceoffs_won_per_60,
    (COALESCE((((c.faceoffs_lost)::numeric * 3600.0) / (NULLIF(c.toi_seconds, 0))::numeric), 0.0))::double precision AS faceoffs_lost_per_60
   FROM (public.nst_seasonlong_pp_counts c
     LEFT JOIN public.nst_seasonlong_pp_counts_oi oi ON (((c.player_id = oi.player_id) AND (c.season = oi.season))));


