--
-- Name: nst_team_scores_all_strengths; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.nst_team_scores_all_strengths AS
 SELECT t_all.team_abbreviation,
    t_all.team_name,
    t_all.gp,
    t_all.w_per_game,
    t_all.l_per_game,
    t_all.otl_per_game,
    t_all.points_per_game,
    ((((((((((((COALESCE(t_all.cf_per_game_diff, (0)::numeric) / (100)::numeric) * 0.5) + ((COALESCE(t_all.ff_per_game_diff, (0)::numeric) / (100)::numeric) * 0.5)) + ((COALESCE(t_all.sf_per_game_diff, (0)::numeric) / (100)::numeric) * 1.25)) + ((COALESCE(t_all.gf_per_game_diff, (0)::numeric) / (100)::numeric) * (2)::numeric)))::double precision + ((COALESCE(t_all.xgf_per_game_diff, (0)::double precision) / (100)::double precision) * (1)::double precision)) + (((COALESCE(t_all.scf_per_game_diff, (0)::numeric) / (100)::numeric) * 0.5))::double precision) + (((COALESCE(t_all.hdcf_per_game_diff, (0)::numeric) / (100)::numeric) * 0.3))::double precision) + (((COALESCE(t_all.hdsf_per_game_diff, (0)::numeric) / (100)::numeric) * 0.5))::double precision) + (((COALESCE(t_all.hdgf_per_game_diff, (0)::numeric) / (100)::numeric) * 0.25))::double precision) + ((COALESCE(t_all.sh_pct_diff, (0)::double precision) / (100)::double precision) * (1)::double precision)) AS att_score_all,
    ((((((((((((COALESCE((- t_all.ca_per_game_diff), (0)::numeric) / (100)::numeric) * 0.5) + ((COALESCE((- t_all.fa_per_game_diff), (0)::numeric) / (100)::numeric) * 0.5)) + ((COALESCE((- t_all.sa_per_game_diff), (0)::numeric) / (100)::numeric) * 1.25)) + ((COALESCE((- t_all.ga_per_game_diff), (0)::numeric) / (100)::numeric) * (2)::numeric)))::double precision + ((COALESCE((- t_all.xga_per_game_diff), (0)::double precision) / (100)::double precision) * (0.75)::double precision)) + (((COALESCE((- t_all.sca_per_game_diff), (0)::numeric) / (100)::numeric) * 0.5))::double precision) + (((COALESCE((- t_all.hdca_per_game_diff), (0)::numeric) / (100)::numeric) * 0.3))::double precision) + (((COALESCE((- t_all.hdsa_per_game_diff), (0)::numeric) / (100)::numeric) * 0.5))::double precision) + (((COALESCE((- t_all.hdga_per_game_diff), (0)::numeric) / (100)::numeric) * 0.25))::double precision) + ((COALESCE(t_all.sv_pct_diff, (0)::double precision) / (100)::double precision) * (1)::double precision)) AS def_score_all,
    ((((((((((((COALESCE(t_5v5.cf_per_game_diff, (0)::numeric) / (100)::numeric) * 0.5) + ((COALESCE(t_5v5.ff_per_game_diff, (0)::numeric) / (100)::numeric) * 0.5)) + ((COALESCE(t_5v5.sf_per_game_diff, (0)::numeric) / (100)::numeric) * 1.25)) + ((COALESCE(t_5v5.gf_per_game_diff, (0)::numeric) / (100)::numeric) * (2)::numeric)))::double precision + ((COALESCE(t_5v5.xgf_per_game_diff, (0)::double precision) / (100)::double precision) * (0.75)::double precision)) + (((COALESCE(t_5v5.scf_per_game_diff, (0)::numeric) / (100)::numeric) * 0.5))::double precision) + (((COALESCE(t_5v5.hdcf_per_game_diff, (0)::numeric) / (100)::numeric) * 0.3))::double precision) + (((COALESCE(t_5v5.hdsf_per_game_diff, (0)::numeric) / (100)::numeric) * 0.3))::double precision) + (((COALESCE(t_5v5.hdgf_per_game_diff, (0)::numeric) / (100)::numeric) * 0.25))::double precision) + ((COALESCE(t_5v5.sh_pct_diff, (0)::double precision) / (100)::double precision) * (1)::double precision)) AS att_score_5v5,
    ((((((((((((COALESCE((- t_5v5.ca_per_game_diff), (0)::numeric) / (100)::numeric) * 0.5) + ((COALESCE((- t_5v5.fa_per_game_diff), (0)::numeric) / (100)::numeric) * 0.5)) + ((COALESCE((- t_5v5.sa_per_game_diff), (0)::numeric) / (100)::numeric) * 1.25)) + ((COALESCE((- t_5v5.ga_per_game_diff), (0)::numeric) / (100)::numeric) * (2)::numeric)))::double precision + ((COALESCE((- t_5v5.xga_per_game_diff), (0)::double precision) / (100)::double precision) * (0.75)::double precision)) + (((COALESCE((- t_5v5.sca_per_game_diff), (0)::numeric) / (100)::numeric) * 0.5))::double precision) + (((COALESCE((- t_5v5.hdca_per_game_diff), (0)::numeric) / (100)::numeric) * 0.3))::double precision) + (((COALESCE((- t_5v5.hdsa_per_game_diff), (0)::numeric) / (100)::numeric) * 0.3))::double precision) + (((COALESCE((- t_5v5.hdga_per_game_diff), (0)::numeric) / (100)::numeric) * 0.25))::double precision) + ((COALESCE(t_5v5.sv_pct_diff, (0)::double precision) / (100)::double precision) * (1)::double precision)) AS def_score_5v5,
    ((((((((((((COALESCE(t_pp.cf_per_game_diff, (0)::numeric) / (100)::numeric) * 0.5) + ((COALESCE(t_pp.ff_per_game_diff, (0)::numeric) / (100)::numeric) * 0.5)) + ((COALESCE(t_pp.sf_per_game_diff, (0)::numeric) / (100)::numeric) * 1.25)) + ((COALESCE(t_pp.gf_per_game_diff, (0)::numeric) / (100)::numeric) * (2)::numeric)))::double precision + ((COALESCE(t_pp.xgf_per_game_diff, (0)::double precision) / (100)::double precision) * (0.75)::double precision)) + (((COALESCE(t_pp.scf_per_game_diff, (0)::numeric) / (100)::numeric) * 0.5))::double precision) + (((COALESCE(t_pp.hdcf_per_game_diff, (0)::numeric) / (100)::numeric) * 0.3))::double precision) + (((COALESCE(t_pp.hdsf_per_game_diff, (0)::numeric) / (100)::numeric) * 0.3))::double precision) + (((COALESCE(t_pp.hdgf_per_game_diff, (0)::numeric) / (100)::numeric) * 0.25))::double precision) + ((COALESCE(t_pp.sh_pct_diff, (0)::double precision) / (100)::double precision) * (1)::double precision)) AS att_score_pp,
    ((((((((((((COALESCE((- t_pp.ca_per_game_diff), (0)::numeric) / (100)::numeric) * 0.5) + ((COALESCE((- t_pp.fa_per_game_diff), (0)::numeric) / (100)::numeric) * 0.5)) + ((COALESCE((- t_pp.sa_per_game_diff), (0)::numeric) / (100)::numeric) * 1.25)) + ((COALESCE((- t_pp.ga_per_game_diff), (0)::numeric) / (100)::numeric) * (2)::numeric)))::double precision + ((COALESCE((- t_pp.xga_per_game_diff), (0)::double precision) / (100)::double precision) * (0.75)::double precision)) + (((COALESCE((- t_pp.sca_per_game_diff), (0)::numeric) / (100)::numeric) * 0.5))::double precision) + (((COALESCE((- t_pp.hdca_per_game_diff), (0)::numeric) / (100)::numeric) * 0.3))::double precision) + (((COALESCE((- t_pp.hdsa_per_game_diff), (0)::numeric) / (100)::numeric) * 0.3))::double precision) + (((COALESCE((- t_pp.hdga_per_game_diff), (0)::numeric) / (100)::numeric) * 0.25))::double precision) + ((COALESCE(t_pp.sv_pct_diff, (0)::double precision) / (100)::double precision) * (1)::double precision)) AS def_score_pp,
    ((((((((((((COALESCE(t_pk.cf_per_game_diff, (0)::numeric) / (100)::numeric) * 0.5) + ((COALESCE(t_pk.ff_per_game_diff, (0)::numeric) / (100)::numeric) * 0.5)) + ((COALESCE(t_pk.sf_per_game_diff, (0)::numeric) / (100)::numeric) * 1.25)) + ((COALESCE(t_pk.gf_per_game_diff, (0)::numeric) / (100)::numeric) * (2)::numeric)))::double precision + ((COALESCE(t_pk.xgf_per_game_diff, (0)::double precision) / (100)::double precision) * (0.75)::double precision)) + (((COALESCE(t_pk.scf_per_game_diff, (0)::numeric) / (100)::numeric) * 0.5))::double precision) + (((COALESCE(t_pk.hdcf_per_game_diff, (0)::numeric) / (100)::numeric) * 0.3))::double precision) + (((COALESCE(t_pk.hdsf_per_game_diff, (0)::numeric) / (100)::numeric) * 0.3))::double precision) + (((COALESCE(t_pk.hdgf_per_game_diff, (0)::numeric) / (100)::numeric) * 0.25))::double precision) + ((COALESCE(t_pk.sh_pct_diff, (0)::double precision) / (100)::double precision) * (1)::double precision)) AS att_score_pk,
    ((((((((((((COALESCE((- t_pk.ca_per_game_diff), (0)::numeric) / (100)::numeric) * 0.5) + ((COALESCE((- t_pk.fa_per_game_diff), (0)::numeric) / (100)::numeric) * 0.5)) + ((COALESCE((- t_pk.sa_per_game_diff), (0)::numeric) / (100)::numeric) * 1.25)) + ((COALESCE((- t_pk.ga_per_game_diff), (0)::numeric) / (100)::numeric) * (2)::numeric)))::double precision + ((COALESCE((- t_pk.xga_per_game_diff), (0)::double precision) / (100)::double precision) * (0.75)::double precision)) + (((COALESCE((- t_pk.sca_per_game_diff), (0)::numeric) / (100)::numeric) * 0.5))::double precision) + (((COALESCE((- t_pk.hdca_per_game_diff), (0)::numeric) / (100)::numeric) * 0.3))::double precision) + (((COALESCE((- t_pk.hdsa_per_game_diff), (0)::numeric) / (100)::numeric) * 0.3))::double precision) + (((COALESCE((- t_pk.hdga_per_game_diff), (0)::numeric) / (100)::numeric) * 0.25))::double precision) + ((COALESCE(t_pk.sv_pct_diff, (0)::double precision) / (100)::double precision) * (1)::double precision)) AS def_score_pk
   FROM (((public.nst_all_team_differentials t_all
     JOIN public.nst_5v5_team_differentials t_5v5 USING (team_abbreviation))
     JOIN public.nst_pp_team_differentials t_pp USING (team_abbreviation))
     JOIN public.nst_pk_team_differentials t_pk USING (team_abbreviation));


