--
-- Name: player_gamelogs_unified; Type: MATERIALIZED VIEW; Schema: public; Owner: -
--

CREATE MATERIALIZED VIEW public.player_gamelogs_unified AS
 WITH nst_keys AS (
         SELECT nst_gamelog_as_counts.player_id,
            nst_gamelog_as_counts.date_scraped AS date_key,
            nst_gamelog_as_counts.season
           FROM public.nst_gamelog_as_counts
        UNION
