    nro.mdgf_pct AS nst_oi_mdgf_pct_rates,
    nro.ldcf_per_60 AS nst_oi_ldcf_per_60,
    nro.ldca_per_60 AS nst_oi_ldca_per_60,
    nro.ldcf_pct AS nst_oi_ldcf_pct_rates,
    nro.ldgf_per_60 AS nst_oi_ldgf_per_60,
    nro.ldga_per_60 AS nst_oi_ldga_per_60,
    nro.ldgf_pct AS nst_oi_ldgf_pct_rates,
    nro.on_ice_sh_pct AS nst_oi_sh_pct_rates,
    nro.on_ice_sv_pct AS nst_oi_sv_pct_rates,
    nro.pdo AS nst_oi_pdo_rates,
    nro.off_zone_starts_per_60 AS nst_oi_off_zone_starts_per_60,
    nro.neu_zone_starts_per_60 AS nst_oi_neu_zone_starts_per_60,
    nro.def_zone_starts_per_60 AS nst_oi_def_zone_starts_per_60,
    nro.off_zone_start_pct AS nst_oi_off_zone_start_pct_rates,
    (nc.player_id IS NOT NULL) AS has_nst_counts,
    (nco.player_id IS NOT NULL) AS has_nst_counts_oi,
    (nr.player_id IS NOT NULL) AS has_nst_rates,
    (nro.player_id IS NOT NULL) AS has_nst_rates_oi,
    COALESCE(w.shots, 0) AS shots_safe,
    COALESCE(w.shooting_percentage, (0)::double precision) AS shooting_pct_safe,
    COALESCE(nco.cf_pct, (0.5)::double precision) AS possession_pct_safe,
    CURRENT_TIMESTAMP AS materialized_at
   FROM ((((((wgo w
     JOIN nst_keys k ON (((k.player_id = w.player_id) AND (k.date_key = w.date) AND (k.season = w.season_id))))
     LEFT JOIN public.players p ON ((w.player_id = p.id)))
     LEFT JOIN public.nst_gamelog_as_counts nc ON (((w.player_id = nc.player_id) AND (w.date = nc.date_scraped) AND (w.season_id = nc.season))))
     LEFT JOIN public.nst_gamelog_as_counts_oi nco ON (((w.player_id = nco.player_id) AND (w.date = nco.date_scraped) AND (w.season_id = nco.season))))
     LEFT JOIN public.nst_gamelog_as_rates nr ON (((w.player_id = nr.player_id) AND (w.date = nr.date_scraped) AND (w.season_id = nr.season))))
     LEFT JOIN public.nst_gamelog_as_rates_oi nro ON (((w.player_id = nro.player_id) AND (w.date = nro.date_scraped) AND (w.season_id = nro.season))))
  WITH NO DATA;


--
-- Name: player_lineup_deployment_tallies; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.player_lineup_deployment_tallies (
    player_id bigint NOT NULL,
    season_id integer NOT NULL,
    game_type integer NOT NULL,
    deployment_group text NOT NULL,
    deployment_code text NOT NULL,
    deployment_label text NOT NULL,
    line_number integer,
    slot_number integer,
    slot_label text,
    unit_number integer,
    games integer NOT NULL,
    total_games integer NOT NULL,
    share numeric(7,4) NOT NULL,
    team_ids integer[] DEFAULT '{}'::integer[] NOT NULL,
    first_game_date date,
    last_game_date date,
    source_table text NOT NULL,
    source_version text DEFAULT 'lcpg_v1'::text NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT player_lineup_deployment_tallies_game_type_check CHECK ((game_type = ANY (ARRAY[2, 3]))),
    CONSTRAINT player_lineup_deployment_tallies_games_check CHECK (((games >= 0) AND (total_games > 0) AND (games <= total_games))),
    CONSTRAINT player_lineup_deployment_tallies_group_check CHECK ((deployment_group = ANY (ARRAY['forward'::text, 'defense'::text, 'power_play'::text]))),
    CONSTRAINT player_lineup_deployment_tallies_share_check CHECK (((share >= (0)::numeric) AND (share <= (1)::numeric))),
    CONSTRAINT player_lineup_deployment_tallies_source_table_check CHECK ((source_table = ANY (ARRAY['shift_charts'::text, 'lineCombinations'::text, 'powerPlayCombinations'::text])))
);


--
-- Name: TABLE player_lineup_deployment_tallies; Type: COMMENT; Schema: public; Owner: -
