--
-- Name: player_totals_unified; Type: MATERIALIZED VIEW; Schema: public; Owner: -
--

CREATE MATERIALIZED VIEW public.player_totals_unified AS
 WITH base AS (
         SELECT psu.player_id,
            psu.season_id,
            psu.team_id,
            psu.player_name,
            psu.position_code,
            psu.shoots_catches,
            psu.date,
            psu.games_played,
            psu.points,
            psu.goals,
            psu.assists,
            psu.shots,
            psu.plus_minus,
            psu.gw_goals,
            psu.pp_points,
            psu.sh_points,
            psu.penalty_minutes,
            psu.hits,
            psu.blocked_shots,
            psu.takeaways,
            psu.giveaways,
            psu.d_zone_faceoffs,
            psu.ev_faceoffs,
            psu.n_zone_faceoffs,
            psu.o_zone_faceoffs,
            psu.total_faceoffs,
            psu.total_fol,
            psu.total_fow,
            ((psu.d_zone_faceoffs)::double precision * psu.d_zone_fo_percentage) AS d_zone_fow_numer,
            ((psu.ev_faceoffs)::double precision * psu.ev_faceoff_percentage) AS ev_fow_numer,
            ((psu.n_zone_faceoffs)::double precision * psu.n_zone_fo_percentage) AS n_zone_fow_numer,
            ((psu.o_zone_faceoffs)::double precision * psu.o_zone_fo_percentage) AS o_zone_fow_numer,
            psu.es_goals_against,
            psu.es_goals_for,
            psu.toi_per_game,
            psu.es_toi_per_game,
            psu.ev_time_on_ice,
            psu.pp_toi,
            psu.sh_time_on_ice,
            psu.toi_per_game_5v5,
