           FROM public.player_stats_unified psu
          WHERE ((psu.games_played = 1) AND (psu.date >= '2023-01-01'::date) AND (psu.player_id IS NOT NULL) AND (psu.date IS NOT NULL))
        )
 SELECT base.player_id,
    base.season_id,
    max(base.player_name) AS player_name,
    array_agg(DISTINCT base.team_id) AS team_ids,
    max(base.position_code) AS position_code,
    max(base.shoots_catches) AS shoots_catches,
    sum(base.games_played) AS games_played,
    sum(base.points) AS points,
    sum(base.goals) AS goals,
    sum(base.assists) AS assists,
    sum(base.shots) AS shots,
    sum(base.plus_minus) AS plus_minus,
    sum(base.gw_goals) AS gw_goals,
    sum(base.pp_points) AS pp_points,
    sum(base.sh_points) AS sh_points,
    sum(base.penalty_minutes) AS penalty_minutes,
    sum(base.hits) AS hits,
    sum(base.blocked_shots) AS blocked_shots,
    sum(base.takeaways) AS takeaways,
    sum(base.giveaways) AS giveaways,
    sum(base.total_faceoffs) AS total_faceoffs,
    sum(base.total_fol) AS total_fol,
    sum(base.total_fow) AS total_fow,
    ((sum(base.total_fow))::numeric / (NULLIF(sum(base.total_faceoffs), 0))::numeric) AS fow_percentage,
    sum(base.d_zone_faceoffs) AS d_zone_faceoffs,
    ((sum(base.d_zone_fow_numer))::numeric / (NULLIF(sum(base.d_zone_faceoffs), 0))::numeric) AS d_zone_fo_percentage,
    sum(base.ev_faceoffs) AS ev_faceoffs,
    ((sum(base.ev_fow_numer))::numeric / (NULLIF(sum(base.ev_faceoffs), 0))::numeric) AS ev_faceoff_percentage,
    sum(base.n_zone_faceoffs) AS n_zone_faceoffs,
    ((sum(base.n_zone_fow_numer))::numeric / (NULLIF(sum(base.n_zone_faceoffs), 0))::numeric) AS n_zone_fo_percentage,
    sum(base.o_zone_faceoffs) AS o_zone_faceoffs,
    ((sum(base.o_zone_fow_numer))::numeric / (NULLIF(sum(base.o_zone_faceoffs), 0))::numeric) AS o_zone_fo_percentage,
    sum(base.es_goals_for) AS es_goals_for,
    sum(base.es_goals_against) AS es_goals_against,
    ((sum(base.es_goals_for))::numeric / (NULLIF((sum(base.es_goals_for) + sum(base.es_goals_against)), 0))::numeric) AS es_goals_for_percentage,
    sum(base.toi_per_game) AS toi_all_situations,
    ((sum(base.toi_per_game))::numeric / (NULLIF(sum(base.games_played), 0))::numeric) AS avg_toi_per_game,
    sum(base.es_toi_per_game) AS es_toi_total,
    ((sum(base.es_toi_per_game))::numeric / (NULLIF(sum(base.games_played), 0))::numeric) AS es_toi_per_game,
    sum(base.ev_time_on_ice) AS ev_time_on_ice,
    sum(base.pp_toi) AS pp_toi,
    sum(base.sh_time_on_ice) AS sh_time_on_ice,
    sum(base.toi_per_game_5v5) AS toi_5v5_total,
    ((sum(base.toi_per_game_5v5))::numeric / (NULLIF(sum(base.games_played), 0))::numeric) AS toi_per_game_5v5,
    ((sum(base.goals))::numeric / (NULLIF(sum(base.shots), 0))::numeric) AS shooting_percentage,
    sum(base.pp_goals) AS pp_goals,
    sum(base.pp_assists) AS pp_assists,
    sum(base.pp_goals_for) AS pp_goals_for,
    sum(base.pp_goals_against) AS pp_goals_against,
    sum(base.pp_points) AS pp_points_total,
    sum(base.pp_primary_assists) AS pp_primary_assists,
    sum(base.pp_secondary_assists) AS pp_secondary_assists,
    sum(base.pp_individual_sat_for) AS pp_individual_sat_for,
    sum(base.pp_shots) AS pp_shots,
    ((sum(base.pp_goals))::numeric / (NULLIF(sum(base.pp_shots), 0))::numeric) AS pp_shooting_percentage,
    ((3600.0 * (sum(base.pp_goals_for))::numeric) / (NULLIF(sum(base.pp_toi), 0))::numeric) AS pp_goals_for_per_60,
    ((3600.0 * (sum(base.pp_goals))::numeric) / (NULLIF(sum(base.pp_toi), 0))::numeric) AS pp_goals_per_60,
    ((3600.0 * (sum(base.pp_points))::numeric) / (NULLIF(sum(base.pp_toi), 0))::numeric) AS pp_points_per_60,
    ((3600.0 * (sum(base.pp_primary_assists))::numeric) / (NULLIF(sum(base.pp_toi), 0))::numeric) AS pp_primary_assists_per_60,
    ((3600.0 * (sum(base.pp_secondary_assists))::numeric) / (NULLIF(sum(base.pp_toi), 0))::numeric) AS pp_secondary_assists_per_60,
    ((3600.0 * (sum(base.pp_individual_sat_for))::numeric) / (NULLIF(sum(base.pp_toi), 0))::numeric) AS pp_individual_sat_per_60,
    ((3600.0 * (sum(base.pp_shots))::numeric) / (NULLIF(sum(base.pp_toi), 0))::numeric) AS pp_shots_per_60,
    ((((sum(base.pp_toi))::numeric)::double precision / NULLIF(sum(base.team_pp_toi_est), (0)::double precision)))::numeric AS pp_toi_pct_of_team,
    sum(base.sh_goals) AS sh_goals,
    sum(base.sh_assists) AS sh_assists,
    sum(base.sh_primary_assists) AS sh_primary_assists,
    sum(base.sh_secondary_assists) AS sh_secondary_assists,
    sum(base.sh_shots) AS sh_shots,
    ((sum(base.sh_goals))::numeric / (NULLIF(sum(base.sh_shots), 0))::numeric) AS sh_shooting_percentage,
    ((3600.0 * (sum(base.sh_goals))::numeric) / (NULLIF(sum(base.sh_time_on_ice), 0))::numeric) AS sh_goals_per_60,
    ((3600.0 * (sum(base.sh_primary_assists))::numeric) / (NULLIF(sum(base.sh_time_on_ice), 0))::numeric) AS sh_primary_assists_per_60,
    ((3600.0 * (sum(base.sh_secondary_assists))::numeric) / (NULLIF(sum(base.sh_time_on_ice), 0))::numeric) AS sh_secondary_assists_per_60,
    sum(base.assists_5v5) AS assists_5v5,
    sum(base.goals_5v5) AS goals_5v5,
    sum(base.points_5v5) AS points_5v5,
    sum(base.primary_assists_5v5) AS primary_assists_5v5,
    sum(base.secondary_assists_5v5) AS secondary_assists_5v5,
    (((3600.0 * (sum(base.goals_5v5))::numeric))::double precision / NULLIF(sum(base.toi_per_game_5v5), (0)::double precision)) AS goals_per_60_5v5,
    (((3600.0 * (sum(base.assists_5v5))::numeric))::double precision / NULLIF(sum(base.toi_per_game_5v5), (0)::double precision)) AS assists_per_60_5v5,
    (((3600.0 * (sum(base.points_5v5))::numeric))::double precision / NULLIF(sum(base.toi_per_game_5v5), (0)::double precision)) AS points_per_60_5v5,
    sum(base.total_primary_assists) AS total_primary_assists,
    sum(base.total_secondary_assists) AS total_secondary_assists,
    sum(base.shifts) AS shifts,
    ((sum(base.toi_per_game))::numeric / (NULLIF(sum(base.shifts), 0))::numeric) AS time_on_ice_per_shift,
    sum(base.missed_shots) AS missed_shots,
    sum(base.nst_toi) AS nst_toi,
    sum(base.nst_first_assists) AS nst_first_assists,
    sum(base.nst_second_assists) AS nst_second_assists,
    sum(base.nst_ixg) AS nst_ixg,
    sum(base.nst_icf) AS nst_icf,
    sum(base.nst_iff) AS nst_iff,
    sum(base.nst_iscfs) AS nst_iscfs,
    sum(base.nst_hdcf) AS nst_hdcf,
    sum(base.nst_rush_attempts) AS nst_rush_attempts,
    sum(base.nst_rebounds_created) AS nst_rebounds_created,
    sum(base.nst_penalties_drawn) AS nst_penalties_drawn,
    sum(base.nst_hits_taken) AS nst_hits_taken,
    sum(base.nst_faceoffs_won) AS nst_faceoffs_won,
    sum(base.nst_faceoffs_lost) AS nst_faceoffs_lost,
    ((3600.0 * (sum(base.goals))::numeric) / (NULLIF(sum(base.nst_toi), 0))::numeric) AS nst_goals_per_60,
    ((3600.0 * ((sum(base.nst_first_assists) + sum(base.nst_second_assists)))::numeric) / (NULLIF(sum(base.nst_toi), 0))::numeric) AS nst_assists_per_60,
    ((3600.0 * (sum(base.nst_first_assists))::numeric) / (NULLIF(sum(base.nst_toi), 0))::numeric) AS nst_first_assists_per_60,
    ((3600.0 * (sum(base.nst_second_assists))::numeric) / (NULLIF(sum(base.nst_toi), 0))::numeric) AS nst_second_assists_per_60,
    ((3600.0 * (((sum(base.goals) + sum(base.nst_first_assists)) + sum(base.nst_second_assists)))::numeric) / (NULLIF(sum(base.nst_toi), 0))::numeric) AS nst_points_per_60,
    ((3600.0 * (sum(base.shots))::numeric) / (NULLIF(sum(base.nst_toi), 0))::numeric) AS nst_shots_per_60,
    (((3600.0)::double precision * sum(base.nst_ixg)) / (NULLIF(sum(base.nst_toi), 0))::double precision) AS nst_ixg_per_60,
    ((3600.0 * (sum(base.nst_icf))::numeric) / (NULLIF(sum(base.nst_toi), 0))::numeric) AS nst_icf_per_60,
    ((3600.0 * (sum(base.nst_iff))::numeric) / (NULLIF(sum(base.nst_toi), 0))::numeric) AS nst_iff_per_60,
    ((3600.0 * (sum(base.nst_iscfs))::numeric) / (NULLIF(sum(base.nst_toi), 0))::numeric) AS nst_iscfs_per_60,
    ((3600.0 * (sum(base.nst_hdcf))::numeric) / (NULLIF(sum(base.nst_toi), 0))::numeric) AS nst_hdcf_per_60,
    ((3600.0 * (sum(base.nst_rush_attempts))::numeric) / (NULLIF(sum(base.nst_toi), 0))::numeric) AS nst_rush_attempts_per_60,
    ((3600.0 * (sum(base.nst_rebounds_created))::numeric) / (NULLIF(sum(base.nst_toi), 0))::numeric) AS nst_rebounds_created_per_60,
    ((3600.0 * (sum(base.penalty_minutes))::numeric) / (NULLIF(sum(base.nst_toi), 0))::numeric) AS nst_pim_per_60,
    ((3600.0 * (sum(base.nst_penalties_drawn))::numeric) / (NULLIF(sum(base.nst_toi), 0))::numeric) AS nst_penalties_drawn_per_60,
    ((3600.0 * (sum(base.giveaways))::numeric) / (NULLIF(sum(base.nst_toi), 0))::numeric) AS nst_giveaways_per_60,
    ((3600.0 * (sum(base.takeaways))::numeric) / (NULLIF(sum(base.nst_toi), 0))::numeric) AS nst_takeaways_per_60,
    ((3600.0 * (sum(base.hits))::numeric) / (NULLIF(sum(base.nst_toi), 0))::numeric) AS nst_hits_per_60,
    ((3600.0 * (sum(base.blocked_shots))::numeric) / (NULLIF(sum(base.nst_toi), 0))::numeric) AS nst_shots_blocked_per_60,
    ((3600.0 * (sum(base.nst_faceoffs_won))::numeric) / (NULLIF(sum(base.nst_toi), 0))::numeric) AS nst_faceoffs_won_per_60,
    ((3600.0 * (sum(base.nst_faceoffs_lost))::numeric) / (NULLIF(sum(base.nst_toi), 0))::numeric) AS nst_faceoffs_lost_per_60,
    ((3600.0 * (sum(base.nst_hits_taken))::numeric) / (NULLIF(sum(base.nst_toi), 0))::numeric) AS nst_hits_taken_per_60,
    sum(base.nst_oi_cf) AS nst_oi_cf,
    sum(base.nst_oi_ca) AS nst_oi_ca,
    sum(base.nst_oi_ff) AS nst_oi_ff,
    sum(base.nst_oi_fa) AS nst_oi_fa,
    sum(base.nst_oi_sf) AS nst_oi_sf,
    sum(base.nst_oi_sa) AS nst_oi_sa,
    sum(base.nst_oi_gf) AS nst_oi_gf,
    sum(base.nst_oi_ga) AS nst_oi_ga,
    sum(base.nst_oi_xgf) AS nst_oi_xgf,
    sum(base.nst_oi_xga) AS nst_oi_xga,
    sum(base.nst_oi_scf) AS nst_oi_scf,
    sum(base.nst_oi_sca) AS nst_oi_sca,
    sum(base.nst_oi_hdcf) AS nst_oi_hdcf,
    sum(base.nst_oi_hdca) AS nst_oi_hdca,
    sum(base.nst_oi_hdgf) AS nst_oi_hdgf,
    sum(base.nst_oi_hdga) AS nst_oi_hdga,
    sum(base.nst_oi_mdcf) AS nst_oi_mdcf,
    sum(base.nst_oi_mdca) AS nst_oi_mdca,
    sum(base.nst_oi_mdgf) AS nst_oi_mdgf,
    sum(base.nst_oi_mdga) AS nst_oi_mdga,
    sum(base.nst_oi_ldcf) AS nst_oi_ldcf,
    sum(base.nst_oi_ldca) AS nst_oi_ldca,
    sum(base.nst_oi_ldgf) AS nst_oi_ldgf,
    sum(base.nst_oi_ldga) AS nst_oi_ldga,
    sum(base.nst_oi_off_zone_starts) AS nst_oi_off_zone_starts,
    sum(base.nst_oi_neu_zone_starts) AS nst_oi_neu_zone_starts,
    sum(base.nst_oi_def_zone_starts) AS nst_oi_def_zone_starts,
    ((sum(base.nst_oi_cf))::numeric / (NULLIF((sum(base.nst_oi_cf) + sum(base.nst_oi_ca)), 0))::numeric) AS nst_oi_cf_pct,
    ((sum(base.nst_oi_ff))::numeric / (NULLIF((sum(base.nst_oi_ff) + sum(base.nst_oi_fa)), 0))::numeric) AS nst_oi_ff_pct,
    ((sum(base.nst_oi_sf))::numeric / (NULLIF((sum(base.nst_oi_sf) + sum(base.nst_oi_sa)), 0))::numeric) AS nst_oi_sf_pct,
    ((sum(base.nst_oi_gf))::numeric / (NULLIF((sum(base.nst_oi_gf) + sum(base.nst_oi_ga)), 0))::numeric) AS nst_oi_gf_pct,
    (sum(base.nst_oi_xgf) / NULLIF((sum(base.nst_oi_xgf) + sum(base.nst_oi_xga)), (0)::double precision)) AS nst_oi_xgf_pct,
    ((sum(base.nst_oi_scf))::numeric / (NULLIF((sum(base.nst_oi_scf) + sum(base.nst_oi_sca)), 0))::numeric) AS nst_oi_scf_pct,
    ((sum(base.nst_oi_hdcf))::numeric / (NULLIF((sum(base.nst_oi_hdcf) + sum(base.nst_oi_hdca)), 0))::numeric) AS nst_oi_hdcf_pct,
    ((sum(base.nst_oi_hdgf))::double precision / NULLIF(((sum(base.nst_oi_hdgf))::double precision + sum(base.nst_oi_hdga)), (0)::double precision)) AS nst_oi_hdgf_pct,
    ((sum(base.nst_oi_mdcf))::numeric / (NULLIF((sum(base.nst_oi_mdcf) + sum(base.nst_oi_mdca)), 0))::numeric) AS nst_oi_mdcf_pct,
    ((sum(base.nst_oi_mdgf))::numeric / (NULLIF((sum(base.nst_oi_mdgf) + sum(base.nst_oi_mdga)), 0))::numeric) AS nst_oi_mdgf_pct,
    ((sum(base.nst_oi_ldcf))::numeric / (NULLIF((sum(base.nst_oi_ldcf) + sum(base.nst_oi_ldca)), 0))::numeric) AS nst_oi_ldcf_pct,
    ((sum(base.nst_oi_ldgf))::numeric / (NULLIF((sum(base.nst_oi_ldgf) + sum(base.nst_oi_ldga)), 0))::numeric) AS nst_oi_ldgf_pct,
    ((sum(base.nst_oi_gf))::numeric / (NULLIF(sum(base.nst_oi_sf), 0))::numeric) AS nst_oi_shooting_pct,
    (((sum(base.nst_oi_sa) - sum(base.nst_oi_ga)))::numeric / (NULLIF(sum(base.nst_oi_sa), 0))::numeric) AS nst_oi_save_pct,
    (((sum(base.nst_oi_gf))::numeric / (NULLIF(sum(base.nst_oi_sf), 0))::numeric) + (((sum(base.nst_oi_sa) - sum(base.nst_oi_ga)))::numeric / (NULLIF(sum(base.nst_oi_sa), 0))::numeric)) AS nst_oi_pdo,
    ((sum(base.nst_oi_off_zone_starts))::numeric / (NULLIF((sum(base.nst_oi_off_zone_starts) + sum(base.nst_oi_def_zone_starts)), 0))::numeric) AS nst_oi_off_zone_start_pct,
    ((3600.0 * (sum(base.nst_oi_cf))::numeric) / (NULLIF(sum(base.ev_time_on_ice), 0))::numeric) AS nst_oi_cf_per_60,
    ((3600.0 * (sum(base.nst_oi_ca))::numeric) / (NULLIF(sum(base.ev_time_on_ice), 0))::numeric) AS nst_oi_ca_per_60,
    ((3600.0 * (sum(base.nst_oi_ff))::numeric) / (NULLIF(sum(base.ev_time_on_ice), 0))::numeric) AS nst_oi_ff_per_60,
    ((3600.0 * (sum(base.nst_oi_fa))::numeric) / (NULLIF(sum(base.ev_time_on_ice), 0))::numeric) AS nst_oi_fa_per_60,
    ((3600.0 * (sum(base.nst_oi_sf))::numeric) / (NULLIF(sum(base.ev_time_on_ice), 0))::numeric) AS nst_oi_sf_per_60,
    ((3600.0 * (sum(base.nst_oi_sa))::numeric) / (NULLIF(sum(base.ev_time_on_ice), 0))::numeric) AS nst_oi_sa_per_60,
    ((3600.0 * (sum(base.nst_oi_gf))::numeric) / (NULLIF(sum(base.ev_time_on_ice), 0))::numeric) AS nst_oi_gf_per_60,
    ((3600.0 * (sum(base.nst_oi_ga))::numeric) / (NULLIF(sum(base.ev_time_on_ice), 0))::numeric) AS nst_oi_ga_per_60,
    (((3600.0)::double precision * sum(base.nst_oi_xgf)) / (NULLIF(sum(base.ev_time_on_ice), 0))::double precision) AS nst_oi_xgf_per_60,
    (((3600.0)::double precision * sum(base.nst_oi_xga)) / (NULLIF(sum(base.ev_time_on_ice), 0))::double precision) AS nst_oi_xga_per_60,
    ((3600.0 * (sum(base.nst_oi_scf))::numeric) / (NULLIF(sum(base.ev_time_on_ice), 0))::numeric) AS nst_oi_scf_per_60,
    ((3600.0 * (sum(base.nst_oi_sca))::numeric) / (NULLIF(sum(base.ev_time_on_ice), 0))::numeric) AS nst_oi_sca_per_60,
    ((3600.0 * (sum(base.nst_oi_hdcf))::numeric) / (NULLIF(sum(base.ev_time_on_ice), 0))::numeric) AS nst_oi_hdcf_per_60,
    ((3600.0 * (sum(base.nst_oi_hdca))::numeric) / (NULLIF(sum(base.ev_time_on_ice), 0))::numeric) AS nst_oi_hdca_per_60,
    ((3600.0 * (sum(base.nst_oi_hdgf))::numeric) / (NULLIF(sum(base.ev_time_on_ice), 0))::numeric) AS nst_oi_hdgf_per_60,
    ((((3600.0)::double precision * sum(base.nst_oi_hdga)))::numeric / (NULLIF(sum(base.ev_time_on_ice), 0))::numeric) AS nst_oi_hdga_per_60,
    ((3600.0 * (sum(base.nst_oi_mdcf))::numeric) / (NULLIF(sum(base.ev_time_on_ice), 0))::numeric) AS nst_oi_mdcf_per_60,
    ((3600.0 * (sum(base.nst_oi_mdca))::numeric) / (NULLIF(sum(base.ev_time_on_ice), 0))::numeric) AS nst_oi_mdca_per_60,
    ((3600.0 * (sum(base.nst_oi_mdgf))::numeric) / (NULLIF(sum(base.ev_time_on_ice), 0))::numeric) AS nst_oi_mdgf_per_60,
    ((3600.0 * (sum(base.nst_oi_mdga))::numeric) / (NULLIF(sum(base.ev_time_on_ice), 0))::numeric) AS nst_oi_mdga_per_60,
    ((3600.0 * (sum(base.nst_oi_ldcf))::numeric) / (NULLIF(sum(base.ev_time_on_ice), 0))::numeric) AS nst_oi_ldcf_per_60,
    ((3600.0 * (sum(base.nst_oi_ldca))::numeric) / (NULLIF(sum(base.ev_time_on_ice), 0))::numeric) AS nst_oi_ldca_per_60,
    ((3600.0 * (sum(base.nst_oi_ldgf))::numeric) / (NULLIF(sum(base.ev_time_on_ice), 0))::numeric) AS nst_oi_ldgf_per_60,
    ((3600.0 * (sum(base.nst_oi_ldga))::numeric) / (NULLIF(sum(base.ev_time_on_ice), 0))::numeric) AS nst_oi_ldga_per_60,
    ((3600.0 * (sum(base.nst_oi_off_zone_starts))::numeric) / (NULLIF(sum(base.ev_time_on_ice), 0))::numeric) AS nst_oi_off_zone_starts_per_60,
    ((3600.0 * (sum(base.nst_oi_neu_zone_starts))::numeric) / (NULLIF(sum(base.ev_time_on_ice), 0))::numeric) AS nst_oi_neu_zone_starts_per_60,
    ((3600.0 * (sum(base.nst_oi_def_zone_starts))::numeric) / (NULLIF(sum(base.ev_time_on_ice), 0))::numeric) AS nst_oi_def_zone_starts_per_60,
    ((sum(base.goals))::numeric / (NULLIF(sum(base.points), 0))::numeric) AS goals_pct,
    ((((sum(base.toi_per_game_5v5))::numeric)::double precision / NULLIF(sum(base.toi_per_game), (0)::double precision)))::numeric AS zone_start_pct,
    ((((sum(base.toi_per_game_5v5))::numeric)::double precision / NULLIF(sum(base.toi_per_game), (0)::double precision)))::numeric AS zone_start_pct_5v5,
    ((sum(base.shots))::numeric / (NULLIF(sum(base.nst_icf), 0))::numeric) AS individual_shots_for_per_60_proxy_ratio,
    bool_or(base.has_nst_counts) AS has_nst_counts,
    bool_or(base.has_nst_counts_oi) AS has_nst_counts_oi,
    bool_or(base.has_nst_rates) AS has_nst_rates,
    bool_or(base.has_nst_rates_oi) AS has_nst_rates_oi,
    sum(base.shots_safe) AS shots_safe_total,
    ((sum(base.goals))::numeric / (NULLIF(sum(base.shots_safe), 0))::numeric) AS shooting_pct_safe_agg,
    ((sum(base.nst_oi_cf))::numeric / (NULLIF((sum(base.nst_oi_cf) + sum(base.nst_oi_ca)), 0))::numeric) AS possession_pct_safe_agg,
    CURRENT_TIMESTAMP AS materialized_at
   FROM base
  GROUP BY base.player_id, base.season_id
  WITH NO DATA;


