--
-- Name: power_rankings; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.power_rankings AS
 SELECT t.id AS team_id,
    t.name AS team_name,
    t.abbreviation,
    (((((((((((COALESCE(avg(rg.ltg_point_pct), (0)::numeric) * (10)::numeric) + (COALESCE(avg(rg.ltg_goals_for), (0)::numeric) * (6)::numeric)) - (COALESCE(avg(rg.ltg_goals_against), (0)::numeric) * (4)::numeric)) + (COALESCE(avg(rg.ltg_shots_for_per_game), (0)::numeric) * (2)::numeric)) - (COALESCE(avg(rg.ltg_shots_against_per_game), (0)::numeric) * (2)::numeric)) + (COALESCE(avg(rg.ltg_power_play_pct), (0)::numeric) * (10)::numeric)) - (COALESCE(avg(rg.ltg_penalty_kill_pct), (0)::numeric) * (2)::numeric)) + (COALESCE(avg(rg.ltg_pp_opportunities), (0)::numeric) * (4)::numeric)) + (COALESCE(avg(rg.ltg_hits), (0)::numeric) * (1)::numeric)) + (COALESCE(avg(rg.ltg_blocked_shots), (0)::numeric) * (1)::numeric)) + (COALESCE(avg(rg.ltg_pim), (0)::numeric) * (1)::numeric)) AS power_score
   FROM (public.rolling_games rg
     JOIN public.teams t ON ((rg.team_id = t.id)))
  GROUP BY t.id, t.name, t.abbreviation
  ORDER BY (((((((((((COALESCE(avg(rg.ltg_point_pct), (0)::numeric) * (10)::numeric) + (COALESCE(avg(rg.ltg_goals_for), (0)::numeric) * (6)::numeric)) - (COALESCE(avg(rg.ltg_goals_against), (0)::numeric) * (4)::numeric)) + (COALESCE(avg(rg.ltg_shots_for_per_game), (0)::numeric) * (2)::numeric)) - (COALESCE(avg(rg.ltg_shots_against_per_game), (0)::numeric) * (2)::numeric)) + (COALESCE(avg(rg.ltg_power_play_pct), (0)::numeric) * (10)::numeric)) - (COALESCE(avg(rg.ltg_penalty_kill_pct), (0)::numeric) * (2)::numeric)) + (COALESCE(avg(rg.ltg_pp_opportunities), (0)::numeric) * (4)::numeric)) + (COALESCE(avg(rg.ltg_hits), (0)::numeric) * (1)::numeric)) + (COALESCE(avg(rg.ltg_blocked_shots), (0)::numeric) * (1)::numeric)) + (COALESCE(avg(rg.ltg_pim), (0)::numeric) * (1)::numeric)) DESC;


