--
-- Name: rolling_player_metric_support_payloads; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.rolling_player_metric_support_payloads (
    player_id bigint NOT NULL,
    game_date date NOT NULL,
    strength_state text NOT NULL,
    season bigint NOT NULL,
    team_id bigint,
    game_id bigint,
    payload_schema_version integer DEFAULT 1 NOT NULL,
    support_payload jsonb DEFAULT '{}'::jsonb NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT rolling_player_metric_support_payloads_payload_object_ck CHECK ((jsonb_typeof(support_payload) = 'object'::text))
);


--
-- Name: TABLE rolling_player_metric_support_payloads; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE public.rolling_player_metric_support_payloads IS 'JSONB support payloads for rolling_player_game_metrics rows. Stores recompute-only, historical compatibility, and validation support components so ranking rows can remain narrow.';


--
-- Name: COLUMN rolling_player_metric_support_payloads.support_payload; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.rolling_player_metric_support_payloads.support_payload IS 'Versioned object keyed by payload category, such as recomputeSupport, historicalCompatibility, deprecatedCompatibility, and diagnostics.';


--
-- Name: roster_events_event_id_seq; Type: SEQUENCE; Schema: public; Owner: -
--

ALTER TABLE public.forge_roster_events ALTER COLUMN event_id ADD GENERATED BY DEFAULT AS IDENTITY (
    SEQUENCE NAME public.roster_events_event_id_seq
    START WITH 1
    INCREMENT BY 1
    NO MINVALUE
    NO MAXVALUE
    CACHE 1
);


--
-- Name: rosters; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.rosters (
    "playerId" bigint NOT NULL,
    "seasonId" bigint NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    "teamId" smallint NOT NULL,
    "sweaterNumber" smallint NOT NULL,
    is_current boolean DEFAULT true NOT NULL,
    ended_at timestamp with time zone
);


--
-- Name: TABLE rosters; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE public.rosters IS 'Team rosters';


--
-- Name: seasons; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.seasons (
    id bigint NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    "startDate" date NOT NULL,
    "endDate" date NOT NULL,
    "regularSeasonEndDate" date NOT NULL,
    "numberOfGames" smallint NOT NULL
);


--
-- Name: seasons_id_seq; Type: SEQUENCE; Schema: public; Owner: -
--

ALTER TABLE public.seasons ALTER COLUMN id ADD GENERATED BY DEFAULT AS IDENTITY (
    SEQUENCE NAME public.seasons_id_seq
    START WITH 1
    INCREMENT BY 1
    NO MINVALUE
    NO MAXVALUE
    CACHE 1
);


--
-- Name: shift_charts; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.shift_charts (
    id integer NOT NULL,
    game_id integer NOT NULL,
    game_type character varying(10),
    game_date date,
    player_id integer,
    player_first_name character varying(50),
    player_last_name character varying(50),
    team_id integer,
    team_abbreviation character varying(10),
    shift_numbers integer[],
    periods integer[],
    start_times character varying[],
    end_times character varying[],
    durations character varying[],
    game_toi character varying(10),
