    CONSTRAINT skater_composite_ratings_position_group_check CHECK (((position_group IS NULL) OR (position_group = ANY (ARRAY['forward'::text, 'defense'::text])))),
    CONSTRAINT skater_composite_ratings_score_ranges_check CHECK ((((offense_rating_overall IS NULL) OR ((offense_rating_overall >= (0)::double precision) AND (offense_rating_overall <= (100)::double precision))) AND ((offense_rating_deployment IS NULL) OR ((offense_rating_deployment >= (0)::double precision) AND (offense_rating_deployment <= (100)::double precision))) AND ((defense_rating_overall IS NULL) OR ((defense_rating_overall >= (0)::double precision) AND (defense_rating_overall <= (100)::double precision))) AND ((defense_rating_deployment IS NULL) OR ((defense_rating_deployment >= (0)::double precision) AND (defense_rating_deployment <= (100)::double precision))) AND ((mcm_score IS NULL) OR ((mcm_score >= (0)::double precision) AND (mcm_score <= (100)::double precision))) AND ((shoot_first_score IS NULL) OR ((shoot_first_score >= (0)::double precision) AND (shoot_first_score <= (100)::double precision))) AND ((pass_first_score IS NULL) OR ((pass_first_score >= (0)::double precision) AND (pass_first_score <= (100)::double precision))) AND ((play_driver_score IS NULL) OR ((play_driver_score >= (0)::double precision) AND (play_driver_score <= (100)::double precision))) AND ((results_luck_index IS NULL) OR (results_luck_index >= (0)::double precision)))),
    CONSTRAINT skater_composite_ratings_strength_state_check CHECK ((strength_state = ANY (ARRAY['all'::text, '5v5'::text, 'ev'::text, 'pp'::text, 'pk'::text]))),
    CONSTRAINT skater_composite_ratings_window_semantics_check CHECK ((window_semantics = ANY (ARRAY['player_last_n_games_played'::text, 'team_last_n_games'::text, 'season_to_date'::text, 'custom'::text]))),
    CONSTRAINT skater_composite_ratings_window_size_check CHECK ((window_size >= 0)),
    CONSTRAINT skater_composite_ratings_window_type_check CHECK ((window_type = ANY (ARRAY['season'::text, 'last_5'::text, 'last_10'::text, 'last_20'::text, 'last_40'::text, 'last_82'::text, 'past_240_games'::text, 'custom'::text])))
);


