--
-- Name: statsUpdateStatus; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public."statsUpdateStatus" (
    "gameId" bigint NOT NULL,
    updated boolean DEFAULT false NOT NULL,
    outcome text DEFAULT 'pending'::text NOT NULL,
    reason text,
    contract_version smallint DEFAULT 1 NOT NULL,
    expected_team_rows integer,
    observed_team_rows integer,
    expected_skater_rows integer,
    observed_skater_rows integer,
    expected_goalie_rows integer,
    observed_goalie_rows integer,
    completed_at timestamp with time zone,
    CONSTRAINT stats_update_status_manifest_state_check CHECK (((((outcome = 'pending'::text) AND (updated = false) AND (contract_version = 1) AND (reason IS NULL) AND (expected_team_rows IS NULL) AND (observed_team_rows IS NULL) AND (expected_skater_rows IS NULL) AND (observed_skater_rows IS NULL) AND (expected_goalie_rows IS NULL) AND (observed_goalie_rows IS NULL) AND (completed_at IS NULL)) OR ((outcome = 'legacy_unverified'::text) AND (updated = true) AND (contract_version = 0) AND (reason IS NULL) AND (expected_team_rows IS NULL) AND (observed_team_rows IS NULL) AND (expected_skater_rows IS NULL) AND (observed_skater_rows IS NULL) AND (expected_goalie_rows IS NULL) AND (observed_goalie_rows IS NULL) AND (completed_at IS NULL)) OR ((outcome = 'complete'::text) AND (updated = true) AND (contract_version = 1) AND (reason IS NULL) AND (completed_at IS NOT NULL) AND (expected_team_rows = 2) AND (observed_team_rows = expected_team_rows) AND ((expected_skater_rows >= 1) AND (expected_skater_rows <= 100)) AND (observed_skater_rows = expected_skater_rows) AND ((expected_goalie_rows >= 1) AND (expected_goalie_rows <= 100)) AND (observed_goalie_rows = expected_goalie_rows) AND ((expected_skater_rows + expected_goalie_rows) <= 100)) OR ((outcome = 'quarantined'::text) AND (updated = true) AND (contract_version = 1) AND (reason = ANY (ARRAY['game_not_finished'::text, 'schedule_not_realized'::text])) AND (completed_at IS NOT NULL) AND (expected_team_rows = 0) AND (observed_team_rows = 0) AND (expected_skater_rows = 0) AND (observed_skater_rows = 0) AND (expected_goalie_rows = 0) AND (observed_goalie_rows = 0))) IS TRUE))
);


