    player_id integer NOT NULL,
    season_id integer,
    snapshot_date date NOT NULL,
    metric_key text NOT NULL,
    window_code text NOT NULL,
    baseline numeric,
    ewma numeric,
    value numeric NOT NULL,
    ci_lower numeric NOT NULL,
    ci_upper numeric NOT NULL,
    n_eff numeric,
    prior_weight numeric,
    z_score numeric,
    percentile numeric,
    exposure numeric,
    distribution jsonb,
    computed_at timestamp with time zone DEFAULT now() NOT NULL
);


--
-- Name: sustainability_trends_v; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.sustainability_trends_v AS
 SELECT s.player_id,
    s.season_id,
    s.snapshot_date,
    s.position_group,
    s.window_code,
    s.s_raw,
    s.s_100,
    (- ((((((((s.components -> 'weights'::text) -> 'luck'::text) ->> 'shp'::text))::double precision * ((s.components ->> 'z_shp'::text))::double precision) + (((((s.components -> 'weights'::text) -> 'luck'::text) ->> 'oishp'::text))::double precision * ((s.components ->> 'z_oishp'::text))::double precision)) + (((((s.components -> 'weights'::text) -> 'luck'::text) ->> 'ipp'::text))::double precision * ((s.components ->> 'z_ipp'::text))::double precision)) + (((((s.components -> 'weights'::text) -> 'luck'::text) ->> 'ppshp'::text))::double precision * ((s.components ->> 'z_ppshp'::text))::double precision))) AS luck_pressure,
    (((abs(((s.components ->> 'z_shp'::text))::double precision) + abs(((s.components ->> 'z_oishp'::text))::double precision)) + abs(((s.components ->> 'z_ipp'::text))::double precision)) + abs(((s.components ->> 'z_ppshp'::text))::double precision)) AS abs_luck,
    pb.player_name,
    pb.position_code
   FROM (public.sustainability_scores s
     LEFT JOIN public.player_baselines pb ON (((pb.player_id = s.player_id) AND (pb.snapshot_date = s.snapshot_date))));


