--
-- Name: team_unit_toi; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.team_unit_toi (
    id bigint NOT NULL,
    season_id integer NOT NULL,
    snapshot_date date NOT NULL,
    game_id integer NOT NULL,
    game_date date,
    team_id integer NOT NULL,
    team_abbrev text,
    unit_type text NOT NULL,
    unit_number integer NOT NULL,
    player_ids integer[] DEFAULT '{}'::integer[] NOT NULL,
    player_count integer DEFAULT 0 NOT NULL,
    unit_toi_seconds double precision NOT NULL,
    team_unit_pool_toi_seconds double precision NOT NULL,
    unit_share double precision GENERATED ALWAYS AS (
CASE
    WHEN (team_unit_pool_toi_seconds > (0)::double precision) THEN (unit_toi_seconds / team_unit_pool_toi_seconds)
    ELSE NULL::double precision
END) STORED,
    toi_basis text DEFAULT 'pooled_player_seconds'::text NOT NULL,
    source_table text NOT NULL,
    source_version text DEFAULT 'team_unit_toi_v1'::text NOT NULL,
    coverage_status text DEFAULT 'complete'::text NOT NULL,
    coverage_warnings jsonb DEFAULT '[]'::jsonb NOT NULL,
    metadata jsonb DEFAULT '{}'::jsonb NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT team_unit_toi_basis_check CHECK ((toi_basis = 'pooled_player_seconds'::text)),
    CONSTRAINT team_unit_toi_coverage_status_check CHECK ((coverage_status = ANY (ARRAY['complete'::text, 'partial'::text, 'source_gap'::text]))),
    CONSTRAINT team_unit_toi_seconds_check CHECK (((unit_toi_seconds >= (0)::double precision) AND (team_unit_pool_toi_seconds >= (0)::double precision))),
    CONSTRAINT team_unit_toi_source_table_check CHECK ((source_table = ANY (ARRAY['nhl_api_shift_rows'::text, 'powerPlayCombinations'::text]))),
    CONSTRAINT team_unit_toi_unit_number_check CHECK ((unit_number > 0)),
    CONSTRAINT team_unit_toi_unit_type_check CHECK ((unit_type = ANY (ARRAY['forward_line'::text, 'defense_pair'::text, 'power_play'::text])))
);


