--
-- Name: view_active_player_ids_max_season; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.view_active_player_ids_max_season AS
 WITH max_season AS (
         SELECT max(nst_seasonal_individual_counts.season) AS season
           FROM public.nst_seasonal_individual_counts
        ), active_ids AS (
         SELECT n.player_id
           FROM (public.nst_seasonal_individual_counts n
             JOIN max_season ms ON ((n.season = ms.season)))
        UNION
         SELECT n.player_id
           FROM (public.nst_seasonal_on_ice_counts n
             JOIN max_season ms ON ((n.season = ms.season)))
        )
 SELECT DISTINCT a.player_id,
    COALESCE(p."fullName", (y.player_name)::text, NULLIF(TRIM(BOTH FROM ((COALESCE(p."firstName", ''::text) || ' '::text) || COALESCE(p."lastName", ''::text))), ''::text)) AS player_name
   FROM ((active_ids a
     LEFT JOIN public.players p ON ((p.id = a.player_id)))
     LEFT JOIN public.yahoo_names y ON (((y.player_id)::bigint = a.player_id)))
  WHERE ((a.player_id IS NOT NULL) AND (COALESCE(p."fullName", (y.player_name)::text, NULLIF(TRIM(BOTH FROM ((COALESCE(p."firstName", ''::text) || ' '::text) || COALESCE(p."lastName", ''::text))), ''::text)) IS NOT NULL));


