 SELECT max(games."seasonId") AS season_id
   FROM public.games;


--
-- Name: vw_active_teams; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.vw_active_teams AS
 SELECT ts."teamId" AS team_id,
    t.abbreviation AS app_abbrev,
    cs.season_id
   FROM ((public.team_season ts
     JOIN public.teams t ON ((t.id = ts."teamId")))
     JOIN public.vw_current_season cs ON ((cs.season_id = ts."seasonId")));


--
-- Name: vw_pp_unit_share_recent; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.vw_pp_unit_share_recent AS
 WITH ppc AS (
         SELECT p."gameId" AS game_id,
            p."playerId" AS player_id,
            p.unit AS pp_unit,
            p."PPTOI" AS pp_toi_seconds,
            p."percentageOfPP" AS pct_raw
           FROM public."powerPlayCombinations" p
        ), lc_map AS (
         SELECT DISTINCT lc."gameId" AS game_id,
            lc."teamId" AS team_id,
            unnest(lc.forwards) AS player_id
           FROM public."lineCombinations" lc
        UNION
         SELECT DISTINCT lc."gameId",
            lc."teamId",
            unnest(lc.defensemen) AS unnest
           FROM public."lineCombinations" lc
        UNION
         SELECT DISTINCT lc."gameId",
            lc."teamId",
            unnest(lc.goalies) AS unnest
           FROM public."lineCombinations" lc
        ), ppc_team AS (
         SELECT p.game_id,
            COALESCE(lc.team_id,
                CASE
                    WHEN (pl.team_id = g."homeTeamId") THEN g."homeTeamId"
                    WHEN (pl.team_id = g."awayTeamId") THEN g."awayTeamId"
                    ELSE NULL::smallint
                END) AS team_id,
            p.player_id,
            p.pp_unit,
            p.pp_toi_seconds,
            p.pct_raw
           FROM (((ppc p
             LEFT JOIN lc_map lc ON (((lc.game_id = p.game_id) AND (lc.player_id = p.player_id))))
             LEFT JOIN public.games g ON ((g.id = p.game_id)))
             LEFT JOIN public.players pl ON ((pl.id = p.player_id)))
        ), ppc_team_resolved AS (
         SELECT ppc_team.game_id,
            ppc_team.team_id,
            ppc_team.player_id,
            ppc_team.pp_unit,
            ppc_team.pp_toi_seconds,
            ppc_team.pct_raw
           FROM ppc_team
          WHERE (ppc_team.team_id IS NOT NULL)
        ), per_game_team AS (
         SELECT ppc_team_resolved.game_id,
            ppc_team_resolved.team_id,
            (sum(ppc_team_resolved.pp_toi_seconds))::double precision AS team_pp_toi
           FROM ppc_team_resolved
          GROUP BY ppc_team_resolved.game_id, ppc_team_resolved.team_id
        ), ppc_norm AS (
         SELECT r.game_id,
            r.team_id,
            r.player_id,
            r.pp_unit,
            r.pp_toi_seconds,
            r.pct_raw,
                CASE
                    WHEN (r.pct_raw IS NULL) THEN NULL::double precision
                    WHEN (r.pct_raw > (1)::numeric) THEN ((r.pct_raw)::double precision / (100.0)::double precision)
                    ELSE (r.pct_raw)::double precision
                END AS pct_share
           FROM ppc_team_resolved r
        ), recent AS (
         SELECT n.player_id,
            t.abbreviation AS team_abbrev,
            avg(
                CASE
                    WHEN (n.pp_unit = 1) THEN 1.0
                    ELSE 0.0
                END) AS p_pp1,
            avg(((n.pp_toi_seconds)::double precision / NULLIF(p.team_pp_toi, (0)::double precision))) AS pp_share_recent,
            (((3600.0)::double precision * (sum(n.pp_toi_seconds))::double precision) / NULLIF(sum(p.team_pp_toi), (0)::double precision)) AS pp_toi60_recent,
            avg(n.pct_share) AS pct_share_avg
           FROM (((ppc_norm n
             JOIN per_game_team p USING (game_id, team_id))
             JOIN public.games g ON ((g.id = n.game_id)))
             JOIN public.teams t ON ((t.id = n.team_id)))
          WHERE (g.date >= (CURRENT_DATE - '30 days'::interval))
          GROUP BY n.player_id, t.abbreviation
        )
 SELECT recent.player_id,
    recent.team_abbrev,
    recent.p_pp1,
    recent.pp_share_recent,
    recent.pp_toi60_recent,
    recent.pct_share_avg
   FROM recent;


--
-- Name: vw_season_game_dates; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.vw_season_game_dates AS
 WITH cs AS (
         SELECT vw_current_season.season_id
           FROM public.vw_current_season
        )
 SELECT DISTINCT g.date
   FROM (public.games g
     JOIN cs ON ((cs.season_id = g."seasonId")));


--
-- Name: vw_slate_day; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.vw_slate_day AS
 WITH game_base AS (
         SELECT g.id AS game_id,
            g.date AS game_date,
            g."seasonId" AS season_id,
            g."homeTeamId" AS home_team_id,
            g."awayTeamId" AS away_team_id,
            home.abbreviation AS home_abbrev,
            away.abbreviation AS away_abbrev
           FROM ((public.games g
             JOIN public.teams home ON ((home.id = g."homeTeamId")))
             JOIN public.teams away ON ((away.id = g."awayTeamId")))
        )
 SELECT gb.game_id,
    gb.game_date,
    gb.season_id,
    gb.home_team_id AS team_id,
    gb.away_team_id AS opp_id,
    gb.home_abbrev AS team_abbrev,
    gb.away_abbrev AS opp_abbrev,
    'home'::text AS home_away
   FROM game_base gb
UNION ALL
 SELECT gb.game_id,
    gb.game_date,
    gb.season_id,
    gb.away_team_id AS team_id,
    gb.home_team_id AS opp_id,
    gb.away_abbrev AS team_abbrev,
    gb.home_abbrev AS opp_abbrev,
    'away'::text AS home_away
   FROM game_base gb;


