--
-- Name: vw_team_strength_state_daily; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.vw_team_strength_state_daily AS
 SELECT t5.team_abbreviation AS team_abbrev,
    t5.date,
    '5v5'::text AS state,
    ((t5.xgf * (3600.0)::double precision) / NULLIF((t5.toi)::double precision, (0)::double precision)) AS xgf60,
    ((t5.xga * (3600.0)::double precision) / NULLIF((t5.toi)::double precision, (0)::double precision)) AS xga60,
    (((t5.cf)::double precision * (3600.0)::double precision) / NULLIF((t5.toi)::double precision, (0)::double precision)) AS cf60,
    (((t5.ca)::double precision * (3600.0)::double precision) / NULLIF((t5.toi)::double precision, (0)::double precision)) AS ca60,
    (((t5.scf)::double precision * (3600.0)::double precision) / NULLIF((t5.toi)::double precision, (0)::double precision)) AS scf60,
    (((t5.sca)::double precision * (3600.0)::double precision) / NULLIF((t5.toi)::double precision, (0)::double precision)) AS sca60,
    (((t5.hdcf)::double precision * (3600.0)::double precision) / NULLIF((t5.toi)::double precision, (0)::double precision)) AS hdcf60,
    (((t5.hdca)::double precision * (3600.0)::double precision) / NULLIF((t5.toi)::double precision, (0)::double precision)) AS hdca60,
    (((t5.sf)::double precision * (3600.0)::double precision) / NULLIF((t5.toi)::double precision, (0)::double precision)) AS sf60,
    (((t5.sa)::double precision * (3600.0)::double precision) / NULLIF((t5.toi)::double precision, (0)::double precision)) AS sa60
   FROM public.nst_team_5v5 t5
UNION ALL
 SELECT pp.team_abbreviation AS team_abbrev,
    pp.date,
    'PP'::text AS state,
    ((pp.xgf * (3600.0)::double precision) / NULLIF((pp.toi)::double precision, (0)::double precision)) AS xgf60,
    ((pp.xga * (3600.0)::double precision) / NULLIF((pp.toi)::double precision, (0)::double precision)) AS xga60,
    (((pp.cf)::double precision * (3600.0)::double precision) / NULLIF((pp.toi)::double precision, (0)::double precision)) AS cf60,
    (((pp.ca)::double precision * (3600.0)::double precision) / NULLIF((pp.toi)::double precision, (0)::double precision)) AS ca60,
    (((pp.scf)::double precision * (3600.0)::double precision) / NULLIF((pp.toi)::double precision, (0)::double precision)) AS scf60,
    (((pp.sca)::double precision * (3600.0)::double precision) / NULLIF((pp.toi)::double precision, (0)::double precision)) AS sca60,
    (((pp.hdcf)::double precision * (3600.0)::double precision) / NULLIF((pp.toi)::double precision, (0)::double precision)) AS hdcf60,
    (((pp.hdca)::double precision * (3600.0)::double precision) / NULLIF((pp.toi)::double precision, (0)::double precision)) AS hdca60,
    (((pp.sf)::double precision * (3600.0)::double precision) / NULLIF((pp.toi)::double precision, (0)::double precision)) AS sf60,
    (((pp.sa)::double precision * (3600.0)::double precision) / NULLIF((pp.toi)::double precision, (0)::double precision)) AS sa60
   FROM public.nst_team_pp pp
UNION ALL
 SELECT pk.team_abbreviation AS team_abbrev,
    pk.date,
    'PK'::text AS state,
    ((pk.xgf * (3600.0)::double precision) / NULLIF((pk.toi)::double precision, (0)::double precision)) AS xgf60,
    ((pk.xga * (3600.0)::double precision) / NULLIF((pk.toi)::double precision, (0)::double precision)) AS xga60,
    (((pk.cf)::double precision * (3600.0)::double precision) / NULLIF((pk.toi)::double precision, (0)::double precision)) AS cf60,
    (((pk.ca)::double precision * (3600.0)::double precision) / NULLIF((pk.toi)::double precision, (0)::double precision)) AS ca60,
    (((pk.scf)::double precision * (3600.0)::double precision) / NULLIF((pk.toi)::double precision, (0)::double precision)) AS scf60,
    (((pk.sca)::double precision * (3600.0)::double precision) / NULLIF((pk.toi)::double precision, (0)::double precision)) AS sca60,
    (((pk.hdcf)::double precision * (3600.0)::double precision) / NULLIF((pk.toi)::double precision, (0)::double precision)) AS hdcf60,
    (((pk.hdca)::double precision * (3600.0)::double precision) / NULLIF((pk.toi)::double precision, (0)::double precision)) AS hdca60,
    (((pk.sf)::double precision * (3600.0)::double precision) / NULLIF((pk.toi)::double precision, (0)::double precision)) AS sf60,
    (((pk.sa)::double precision * (3600.0)::double precision) / NULLIF((pk.toi)::double precision, (0)::double precision)) AS sa60
   FROM public.nst_team_pk pk;


--
-- Name: vw_team_strength_state_daily_norm; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.vw_team_strength_state_daily_norm AS
 WITH ats AS (
         SELECT vw_active_teams.team_id,
            vw_active_teams.app_abbrev,
            vw_active_teams.season_id
           FROM public.vw_active_teams
        ), states(state) AS (
         VALUES ('5v5'::text), ('PP'::text), ('PK'::text)
        )
 SELECT d.date,
    a.team_id,
    COALESCE(x.nst_abbrev, (a.app_abbrev)::text) AS nst_abbrev,
    s.state,
    ((src.xgf / NULLIF((src.toi)::double precision, (0)::double precision)) * (3600)::double precision) AS xgf60,
    ((src.xga / NULLIF((src.toi)::double precision, (0)::double precision)) * (3600)::double precision) AS xga60,
    (((src.cf)::double precision / NULLIF((src.toi)::double precision, (0)::double precision)) * (3600)::double precision) AS cf60,
    (((src.ca)::double precision / NULLIF((src.toi)::double precision, (0)::double precision)) * (3600)::double precision) AS ca60,
    (((src.scf)::double precision / NULLIF((src.toi)::double precision, (0)::double precision)) * (3600)::double precision) AS scf60,
    (((src.sca)::double precision / NULLIF((src.toi)::double precision, (0)::double precision)) * (3600)::double precision) AS sca60,
    (((src.hdcf)::double precision / NULLIF((src.toi)::double precision, (0)::double precision)) * (3600)::double precision) AS hdcf60,
    (((src.hdca)::double precision / NULLIF((src.toi)::double precision, (0)::double precision)) * (3600)::double precision) AS hdca60,
    (((src.sf)::double precision / NULLIF((src.toi)::double precision, (0)::double precision)) * (3600)::double precision) AS sf60,
    (((src.sa)::double precision / NULLIF((src.toi)::double precision, (0)::double precision)) * (3600)::double precision) AS sa60
   FROM ((((public.vw_season_game_dates d
     CROSS JOIN public.vw_active_teams a)
     LEFT JOIN public.team_abbrev_xwalk x ON (((x.season_id = a.season_id) AND (x.team_id = a.team_id))))
     CROSS JOIN states s)
     LEFT JOIN LATERAL ( SELECT z.state,
            z.team_abbreviation,
            z.date,
            z.xgf,
            z.xga,
            z.cf,
            z.ca,
            z.scf,
            z.sca,
            z.hdcf,
            z.hdca,
            z.sf,
            z.sa,
            z.toi
           FROM ( SELECT t.state,
                    t.team_abbreviation,
                    t.date,
                    t.xgf,
                    t.xga,
                    t.cf,
                    t.ca,
                    t.scf,
                    t.sca,
                    t.hdcf,
                    t.hdca,
                    t.sf,
                    t.sa,
                    t.toi
                   FROM (( SELECT
                                CASE s.state
                                    WHEN '5v5'::text THEN 'nst_team_5v5'::text
                                    WHEN 'PP'::text THEN 'nst_team_pp'::text
                                    WHEN 'PK'::text THEN 'nst_team_pk'::text
                                    ELSE NULL::text
                                END AS tbl) pick
                     JOIN ( SELECT '5v5'::text AS state,
                            nst_team_5v5.team_abbreviation,
                            nst_team_5v5.date,
                            nst_team_5v5.xgf,
                            nst_team_5v5.xga,
                            nst_team_5v5.cf,
                            nst_team_5v5.ca,
                            nst_team_5v5.scf,
                            nst_team_5v5.sca,
                            nst_team_5v5.hdcf,
                            nst_team_5v5.hdca,
                            nst_team_5v5.sf,
                            nst_team_5v5.sa,
                            nst_team_5v5.toi
                           FROM public.nst_team_5v5
                        UNION ALL
                         SELECT 'PP'::text,
                            nst_team_pp.team_abbreviation,
                            nst_team_pp.date,
                            nst_team_pp.xgf,
                            nst_team_pp.xga,
                            nst_team_pp.cf,
                            nst_team_pp.ca,
                            nst_team_pp.scf,
                            nst_team_pp.sca,
                            nst_team_pp.hdcf,
                            nst_team_pp.hdca,
                            nst_team_pp.sf,
                            nst_team_pp.sa,
                            nst_team_pp.toi
                           FROM public.nst_team_pp
                        UNION ALL
                         SELECT 'PK'::text,
                            nst_team_pk.team_abbreviation,
                            nst_team_pk.date,
                            nst_team_pk.xgf,
                            nst_team_pk.xga,
                            nst_team_pk.cf,
                            nst_team_pk.ca,
                            nst_team_pk.scf,
                            nst_team_pk.sca,
                            nst_team_pk.hdcf,
                            nst_team_pk.hdca,
                            nst_team_pk.sf,
                            nst_team_pk.sa,
                            nst_team_pk.toi
                           FROM public.nst_team_pk) t ON ((t.state = s.state)))
                  WHERE ((t.team_abbreviation = COALESCE(x.nst_abbrev, (a.app_abbrev)::text)) AND (t.date <= d.date))
                  ORDER BY t.date DESC
                 LIMIT 1) z) src ON (true));


