--
-- Name: COLUMN wigo_career.std_pp_pct; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.wigo_career.std_pp_pct IS 'Player''s % of Team''s PP TOI used (from wgo_skater_stats_totals.pp_toi_pct_per_game)';


--
-- Name: COLUMN wigo_career.std_ozs_pct; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.wigo_career.std_ozs_pct IS 'Calculated using All Strengths zone starts (OffZS / (OffZS + DefZS)).';


--
-- Name: COLUMN wigo_career.std_ihdcf_per_60; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.wigo_career.std_ihdcf_per_60 IS 'Individual High Danger Chances For / 60 mins (All Strengths TOI)';


--
-- Name: COLUMN wigo_career.std_iscf_per_60; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.wigo_career.std_iscf_per_60 IS 'Individual Scoring Chances For / 60 mins (All Strengths TOI)';


--
-- Name: COLUMN wigo_career.ly_pp_pct; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.wigo_career.ly_pp_pct IS 'Player''s % of Team''s PP TOI used (from wgo_skater_stats_totals.pp_toi_pct_per_game)';


--
-- Name: COLUMN wigo_career.ly_ozs_pct; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.wigo_career.ly_ozs_pct IS 'Calculated using All Strengths zone starts (OffZS / (OffZS + DefZS)).';


--
-- Name: COLUMN wigo_career.ya3_pp_pct; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.wigo_career.ya3_pp_pct IS 'Average of seasonal pp_toi_pct_per_game over the 3YA period.';


--
-- Name: COLUMN wigo_career.ya3_ozs_pct; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.wigo_career.ya3_ozs_pct IS 'Recalculated from total All Strengths OffZS / (Total OffZS + Total DefZS) over period.';


--
-- Name: COLUMN wigo_career.ca_pp_pct; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.wigo_career.ca_pp_pct IS 'Average of seasonal pp_toi_pct_per_game over the career period (excluding current).';


--
-- Name: COLUMN wigo_career.ca_ozs_pct; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.wigo_career.ca_ozs_pct IS 'Recalculated from total All Strengths OffZS / (Total OffZS + Total DefZS) over career.';


