--
-- Name: xg_execution_leases; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.xg_execution_leases (
    lease_key text NOT NULL,
    owner_token uuid,
    state text DEFAULT 'idle'::text NOT NULL,
    acquired_at timestamp with time zone,
    heartbeat_at timestamp with time zone,
    lease_expires_at timestamp with time zone,
    completed_at timestamp with time zone,
    last_success_at timestamp with time zone,
    last_failure_at timestamp with time zone,
    last_error text,
    attempt_count bigint DEFAULT 0 NOT NULL,
    metadata jsonb DEFAULT '{}'::jsonb NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT xg_execution_leases_key_nonempty CHECK ((length(btrim(lease_key)) > 0)),
    CONSTRAINT xg_execution_leases_running_owner_check CHECK ((((state = 'running'::text) AND (owner_token IS NOT NULL) AND (lease_expires_at IS NOT NULL)) OR ((state <> 'running'::text) AND (owner_token IS NULL) AND (lease_expires_at IS NULL)))),
    CONSTRAINT xg_execution_leases_state_check CHECK ((state = ANY (ARRAY['idle'::text, 'running'::text, 'succeeded'::text, 'failed'::text])))
);


--
-- Name: TABLE xg_execution_leases; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE public.xg_execution_leases IS 'Cross-instance xG job leases with owner-safe stale recovery and durable success/failure telemetry.';


