--
-- Name: yahoo_nhl_player_map; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.yahoo_nhl_player_map (
    nhl_player_id text,
    nhl_player_name text,
    nhl_team_abbreviation text,
    name_norm text,
    player_type text,
    points numeric,
    goals numeric,
    assists numeric,
    shots numeric,
    pp_points numeric,
    blocked_shots numeric,
    hits numeric,
    total_fow numeric,
    penalty_minutes numeric,
    sh_points numeric,
    wins numeric,
    losses numeric,
    saves numeric,
    shots_against numeric,
    shutouts numeric,
    quality_start numeric,
    goals_against_avg numeric,
    save_pct numeric,
    yahoo_player_id character varying(255),
    yahoo_player_name character varying(255),
    yahoo_team character varying(10),
    percent_ownership double precision,
    eligible_positions jsonb,
    injury_note text,
    status character varying(10),
    status_full character varying(255),
    mapped_position text GENERATED ALWAYS AS (
CASE
    WHEN (player_type = 'goalie'::text) THEN 'G'::text
    ELSE 'Skater'::text
END) STORED
);


--
-- Name: yahoo_nhl_player_map_mat; Type: MATERIALIZED VIEW; Schema: public; Owner: -
--

CREATE MATERIALIZED VIEW public.yahoo_nhl_player_map_mat AS
 SELECT m.nhl_player_id,
    m.nhl_player_name,
    m.nhl_team_abbreviation,
    m.yahoo_player_id,
    m.yahoo_player_name,
    m.yahoo_team,
    m.percent_ownership,
    m.eligible_positions,
    m.injury_note,
    m.status,
    m.status_full,
    m.points,
    m.goals,
    m.assists,
    m.shots,
    m.pp_points,
    m.blocked_shots,
    m.hits,
    m.total_fow,
    m.penalty_minutes,
    m.sh_points,
    m.wins,
    m.losses,
    m.saves,
    m.shots_against,
    m.shutouts,
    m.quality_start,
    m.goals_against_avg,
    m.save_pct,
    m.player_type,
        CASE
            WHEN (m.player_type = 'goalie'::text) THEN 'G'::text
            ELSE 'Skater'::text
        END AS player_position,
        CASE
            WHEN (m.player_type = 'goalie'::text) THEN 'G'::text
            ELSE 'Skater'::text
        END AS mapped_position,
        CASE
            WHEN (m.player_type = 'goalie'::text) THEN 'G'::text
            ELSE 'Skater'::text
        END AS normalized_position,
    public.immutable_unaccent(lower(COALESCE(m.nhl_team_abbreviation, (m.yahoo_team)::text))) AS normalized_team,
    NULL::numeric AS percent_games
   FROM public.yahoo_nhl_player_map m
  WITH NO DATA;


