--
-- Name: games Enable ALL for Admins; Type: POLICY; Schema: public; Owner: -
--

CREATE POLICY "Enable ALL for Admins" ON public.games TO authenticated USING ((EXISTS ( SELECT 1
   FROM public.users
  WHERE ((users.user_id = auth.uid()) AND ((users.role)::text = 'admin'::text))))) WITH CHECK ((EXISTS ( SELECT 1
   FROM public.users
  WHERE ((users.user_id = auth.uid()) AND ((users.role)::text = 'admin'::text)))));


